import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import FormData from 'form-data';
import fetch from 'node-fetch';

// Get current directory name (ESM equivalent of __dirname)
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Test file upload to the server
async function testUpload() {
  try {
    console.log('Preparing to test file upload...');

    // Create a form data object
    const formData = new FormData();

    // Add a test audio file - use an OGG file with MP3 extension
    const audioFilePath = path.join(__dirname, 'test-audio.mp3');
    const audioFile = fs.createReadStream(audioFilePath);
    // Add proper filename and mimetype for multer to recognize it
    formData.append('audio', audioFile, {
      filename: 'test-audio.mp3',
      contentType: 'audio/mp3'
    });

    // Make a POST request to the upload endpoint
    console.log('Sending test file to /api/upload...');
    const response = await fetch('http://localhost:5000/api/upload', {
      method: 'POST',
      body: formData,
    });

    // Parse the response
    const result = await response.json();

    if (response.ok) {
      console.log('✓ Upload successful!');
      console.log('Response:', JSON.stringify(result, null, 2));

      // Verify the URL format is correct
      if (result.audioUrl) {
        console.log('\nVerifying URL format:');
        console.log('Audio URL:', result.audioUrl);
        const correctFormat = result.audioUrl.includes('.r2.cloudflarestorage.com/goldenpearl/');
        console.log('URL has correct format:', correctFormat ? '✓ Yes' : '❌ No');
      }

      // Verify the signed URL format
      if (result.signedAudioUrl) {
        console.log('\nVerifying signed URL format:');
        console.log('Signed URL:', result.signedAudioUrl);
        const correctFormat = result.signedAudioUrl.includes('.r2.cloudflarestorage.com/goldenpearl/');
        console.log('Signed URL has correct format:', correctFormat ? '✓ Yes' : '❌ No');
      }
    } else {
      console.error('❌ Upload failed:', result);
    }
  } catch (error) {
    console.error('❌ Error during test:', error);
  }
}

// Run the test
testUpload();

