import { getSignedFileUrl } from './r2';

// AI Music Analysis Service
// This service analyzes uploaded audio files and generates intelligent tags

interface AudioAnalysisResult {
  genre?: string;
  mood?: string;
  tempo?: number;
  energyLevel?: 'low' | 'medium' | 'high';
  timeOfDayFit?: 'morning' | 'afternoon' | 'evening' | 'night';
  vocalType?: 'instrumental' | 'vocal' | 'mixed';
  language?: string;
  culturalStyle?: string;
  aiTags: string[];
}

// Simulated AI analysis based on file characteristics and metadata
export async function analyzeAudioFile(filename: string, metadata: {
  title: string;
  artist: string;
  duration: number;
}): Promise<AudioAnalysisResult> {
  console.log(`Starting AI analysis for: ${filename}`);

  try {
    // In a real implementation, this would use actual AI/ML libraries
    // For now, we'll implement intelligent heuristics based on file properties

    const analysis = await performHeuristicAnalysis(filename, metadata);

    console.log(`AI analysis completed for ${filename}:`, analysis);
    return analysis;

  } catch (error) {
    console.error('Error in AI analysis:', error);
    // Return minimal analysis on error
    return {
      energyLevel: 'medium',
      timeOfDayFit: 'afternoon',
      vocalType: 'mixed',
      aiTags: ['general']
    };
  }
}

async function performHeuristicAnalysis(filename: string, metadata: {
  title: string;
  artist: string;
  duration: number;
}): Promise<AudioAnalysisResult> {

  const title = metadata.title.toLowerCase();
  const artist = metadata.artist.toLowerCase();
  const duration = metadata.duration;

  let analysis: AudioAnalysisResult = {
    aiTags: []
  };

  // Genre detection based on artist names and titles
  if (artist.includes('arabic') || artist.includes('khalil') || title.includes('desert') || title.includes('oud')) {
    analysis.genre = 'Arabic Fusion';
    analysis.culturalStyle = 'Middle Eastern';
    analysis.aiTags.push('arabic', 'middle-eastern');
  } else if (title.includes('jazz') || title.includes('lounge') || artist.includes('jazz')) {
    analysis.genre = 'Jazz Lounge';
    analysis.aiTags.push('jazz', 'sophisticated');
  } else if (title.includes('electronic') || title.includes('beat') || title.includes('synth')) {
    analysis.genre = 'Electronic';
    analysis.aiTags.push('electronic', 'modern');
  } else if (title.includes('chill') || title.includes('ambient') || title.includes('calm')) {
    analysis.genre = 'Chillout';
    analysis.aiTags.push('chill', 'relaxing');
  } else {
    analysis.genre = 'World Fusion';
    analysis.aiTags.push('world', 'fusion');
  }

  // Mood detection
  if (title.includes('sad') || title.includes('melancholy') || title.includes('blue')) {
    analysis.mood = 'Melancholic';
    analysis.energyLevel = 'low';
    analysis.aiTags.push('melancholic', 'emotional');
  } else if (title.includes('happy') || title.includes('upbeat') || title.includes('energy') || title.includes('dance')) {
    analysis.mood = 'Energetic';
    analysis.energyLevel = 'high';
    analysis.aiTags.push('energetic', 'uplifting');
  } else if (title.includes('chill') || title.includes('relax') || title.includes('calm') || title.includes('peace')) {
    analysis.mood = 'Relaxed';
    analysis.energyLevel = 'low';
    analysis.aiTags.push('peaceful', 'calming');
  } else {
    analysis.mood = 'Balanced';
    analysis.energyLevel = 'medium';
    analysis.aiTags.push('balanced');
  }

  // Tempo estimation based on duration and keywords
  if (title.includes('slow') || title.includes('ballad') || duration > 300) {
    analysis.tempo = 80; // Slow tempo
    analysis.aiTags.push('slow-tempo');
  } else if (title.includes('fast') || title.includes('dance') || title.includes('beat')) {
    analysis.tempo = 140; // Fast tempo
    analysis.aiTags.push('fast-tempo');
  } else {
    analysis.tempo = 110; // Medium tempo
    analysis.aiTags.push('medium-tempo');
  }

  // Time of day fit based on mood and energy
  if (analysis.energyLevel === 'low' && (title.includes('night') || title.includes('dream') || title.includes('moon'))) {
    analysis.timeOfDayFit = 'night';
    analysis.aiTags.push('night-time');
  } else if (analysis.energyLevel === 'high' && (title.includes('morning') || title.includes('wake') || title.includes('sunrise'))) {
    analysis.timeOfDayFit = 'morning';
    analysis.aiTags.push('morning-energy');
  } else if (title.includes('sunset') || title.includes('evening') || title.includes('golden')) {
    analysis.timeOfDayFit = 'evening';
    analysis.aiTags.push('evening-vibes');
  } else {
    analysis.timeOfDayFit = 'afternoon';
    analysis.aiTags.push('daytime');
  }

  // Vocal detection based on title and artist info
  if (title.includes('instrumental') || title.includes('piano') || title.includes('guitar') || title.includes('oud')) {
    analysis.vocalType = 'instrumental';
    analysis.aiTags.push('instrumental');
  } else if (artist.includes('vocals') || title.includes('singing') || title.includes('voice')) {
    analysis.vocalType = 'vocal';
    analysis.aiTags.push('vocal');
  } else {
    analysis.vocalType = 'mixed';
    analysis.aiTags.push('mixed-vocals');
  }

  // Language detection (simplified)
  if (artist.includes('arabic') || title.includes('habibi') || title.includes('ya')) {
    analysis.language = 'Arabic';
    analysis.aiTags.push('arabic-language');
  } else if (title.includes('english') || artist.includes('english')) {
    analysis.language = 'English';
    analysis.aiTags.push('english-language');
  } else {
    analysis.language = 'Instrumental';
    analysis.aiTags.push('no-vocals');
  }

  // Add contextual tags based on combinations
  if (analysis.genre === 'Arabic Fusion' && analysis.mood === 'Relaxed') {
    analysis.aiTags.push('arabic-chill', 'middle-east-lounge');
  }

  if (analysis.energyLevel === 'high' && analysis.timeOfDayFit === 'morning') {
    analysis.aiTags.push('morning-workout', 'wake-up-music');
  }

  if (analysis.vocalType === 'instrumental' && analysis.mood === 'Relaxed') {
    analysis.aiTags.push('background-music', 'ambient');
  }

  return analysis;
}

// Get AI recommendations for program blocks based on time and context
export function getAiRecommendations(
  dayOfWeek: number,
  hour: number,
  blockType: 'music' | 'content' | 'mixed'
): {
  recommendedTags: string[];
  recommendedMood: string;
  recommendedEnergyLevel: string;
  reasoning: string;
} {

  const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;

  let recommendedTags: string[] = [];
  let recommendedMood: string;
  let recommendedEnergyLevel: string;
  let reasoning: string;

  // Time-based recommendations
  if (hour >= 6 && hour <= 9) {
    // Morning
    recommendedMood = 'Energetic';
    recommendedEnergyLevel = 'medium';
    recommendedTags = ['morning-energy', 'wake-up-music', 'uplifting'];
    reasoning = 'Morning hours require energizing content to help listeners start their day';
  } else if (hour >= 10 && hour <= 12) {
    // Late morning
    recommendedMood = 'Balanced';
    recommendedEnergyLevel = 'medium';
    recommendedTags = ['daytime', 'work-friendly', 'balanced'];
    reasoning = 'Late morning calls for balanced energy suitable for work and daily activities';
  } else if (hour >= 13 && hour <= 17) {
    // Afternoon
    recommendedMood = 'Relaxed';
    recommendedEnergyLevel = 'low';
    recommendedTags = ['afternoon', 'calming', 'background-music'];
    reasoning = 'Afternoon hours benefit from relaxing content for a midday break';
  } else if (hour >= 18 && hour <= 21) {
    // Evening
    recommendedMood = 'Balanced';
    recommendedEnergyLevel = 'medium';
    recommendedTags = ['evening-vibes', 'social', 'dinner-music'];
    reasoning = 'Evening time is perfect for social and dining atmosphere music';
  } else {
    // Night
    recommendedMood = 'Relaxed';
    recommendedEnergyLevel = 'low';
    recommendedTags = ['night-time', 'ambient', 'peaceful'];
    reasoning = 'Night hours require calming content for relaxation and wind-down';
  }

  // Weekend adjustments
  if (isWeekend) {
    if (hour >= 10 && hour <= 14) {
      recommendedTags.push('weekend-vibes', 'leisure');
      reasoning += '. Weekend timing allows for more relaxed, leisure-oriented content';
    }
  }

  // Block type adjustments
  if (blockType === 'content') {
    recommendedTags.push('talk-show', 'informative');
    reasoning += '. Content block should feature engaging talk formats';
  } else if (blockType === 'music') {
    recommendedTags.push('continuous-play', 'seamless');
    reasoning += '. Music block should flow seamlessly without interruption';
  }

  return {
    recommendedTags,
    recommendedMood,
    recommendedEnergyLevel,
    reasoning
  };
}

