import { S3Client, PutObjectCommand, DeleteObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import crypto from 'crypto';
import path from 'path';
import * as dotenv from 'dotenv';

// Load environment variables directly in this file
dotenv.config();

// Hardcoded fallback values if needed
const R2_ACCOUNT_ID = process.env.R2_ACCOUNT_ID || '9483a930fdaec4bd11fa3caf88dad91d';
const R2_ACCESS_KEY_ID = process.env.R2_ACCESS_KEY_ID || '20df76032b15fc0b99949503a424fa6e';
const R2_SECRET_ACCESS_KEY = process.env.R2_SECRET_ACCESS_KEY || '5a511a7052accd17a966baa71dc6248db24e61dd021e697c36b33b43f7bd291d';
const R2_BUCKET_NAME = process.env.R2_BUCKET_NAME || 'goldenpearl';

// Log the available R2 environment variables
console.log('R2 Client Configuration:');
console.log(`Endpoint: https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com`);
console.log(`Bucket: ${R2_BUCKET_NAME}`);

// Configure the R2 client
export const r2Client = new S3Client({
  region: 'auto',
  endpoint: `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com`,
  credentials: {
    accessKeyId: R2_ACCESS_KEY_ID,
    secretAccessKey: R2_SECRET_ACCESS_KEY
  }
});

// Generate a unique filename to avoid collisions
export function generateUniqueFilename(originalFilename: string): string {
  const timestamp = new Date().getTime();
  const hash = crypto.createHash('md5').update(`${originalFilename}-${timestamp}`).digest('hex').slice(0, 8);
  const ext = path.extname(originalFilename);
  const base = path.basename(originalFilename, ext).replace(/[^a-zA-Z0-9]/g, '-').toLowerCase();

  return `${base}-${hash}${ext}`;
}

// Upload a file to R2
export async function uploadFileToR2(
  buffer: Buffer, 
  originalFilename: string,
  contentType: string = 'application/octet-stream'
): Promise<string> {
  const uniqueFilename = generateUniqueFilename(originalFilename);

  const command = new PutObjectCommand({
    Bucket: R2_BUCKET_NAME,
    Key: uniqueFilename,
    Body: buffer,
    ContentType: contentType
  });

  try {
    await r2Client.send(command);
    return uniqueFilename;
  } catch (error) {
    console.error('Error uploading file to R2:', error);
    throw new Error(`Failed to upload file to R2: ${error}`);
  }
}

// Delete a file from R2
export async function deleteFileFromR2(filename: string): Promise<void> {
  const command = new DeleteObjectCommand({
    Bucket: R2_BUCKET_NAME,
    Key: filename
  });

  try {
    await r2Client.send(command);
  } catch (error) {
    console.error('Error deleting file from R2:', error);
    throw new Error(`Failed to delete file from R2: ${error}`);
  }
}

// Get a signed URL for temporary access to a file
export async function getSignedFileUrl(filename: string, expirationSeconds = 3600): Promise<string> {
  const command = new GetObjectCommand({
    Bucket: R2_BUCKET_NAME,
    Key: filename
  });

  try {
    // Get signed URL from AWS SDK
    const signedUrl = await getSignedUrl(r2Client, command, { expiresIn: expirationSeconds });

    // Unfortunately, the AWS SDK generates URLs with the bucket in the subdomain,
    // which is not the format we want. Let's check and correct it if needed.
    if (signedUrl.includes(`${R2_BUCKET_NAME}.${R2_ACCOUNT_ID}.r2.cloudflarestorage.com`)) {
      console.log('Converting signed URL format from subdomain to path format...');

      // Create a URL object for easier parsing
      const urlObj = new URL(signedUrl);
      const hostname = urlObj.hostname;
      const pathname = urlObj.pathname;
      const search = urlObj.search;

      // Extract the filename from the path
      const filenameFromPath = pathname.split('/').pop() || filename;

      // Reconstruct with the correct format (bucket in path)
      const correctedUrl = `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${R2_BUCKET_NAME}/${filenameFromPath}${search}`;
      console.log('Successfully corrected signed URL format');
      return correctedUrl;
    }

    return signedUrl;
  } catch (error) {
    console.error('Error generating signed URL:', error);
    throw new Error(`Failed to generate signed URL: ${error}`);
  }
}

// Get a public URL for a file using the public bucket endpoint
export function getPublicFileUrl(filename: string): string {
  // Return URL with proper path format (bucket in path, not subdomain)
  return `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${R2_BUCKET_NAME}/${filename}`;
}

// Get direct accessible URL specifically for the Doha Metro Suite file
export function getDohaMetroSuiteUrl(): string {
  return `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${R2_BUCKET_NAME}/the-doha-metro-suite-afcad310.mp3`;
}

