export async function registerRoutes(app: Express): Promise<Server> {
  // API Routes
  const apiRouter = app.route('/api');

  // Authentication middleware
  const requireAuth = (req: Request, res: Response, next: any) => {
    // For demo purposes, we'll skip authentication in development
    if (req.headers.authorization === 'Bearer admin-token' || process.env.NODE_ENV === 'development') {
      return next();
    }
    return res.status(401).json({ message: 'Unauthorized' });
  };

  // Admin middleware
  const requireAdmin = async (req: Request, res: Response, next: any) => {
    // For demo purposes, we'll skip authentication in development
    if (process.env.NODE_ENV === 'development') {
      return next();
    }

    if (req.headers.authorization?.startsWith('Bearer ')) {
      const token = req.headers.authorization.split(' ')[1];
      if (token === 'admin-token') { // In a real app, this would validate a JWT
        return next();
      }
    }
    return res.status(403).json({ message: 'Forbidden: Admin access required' });
  };

  // Current playing track/show
  app.get('/api/now-playing', async (req: Request, res: Response) => {
    try {
      const currentScheduleItem = await storage.getCurrentScheduleItem();

      if (!currentScheduleItem) {
        // If no scheduled item, return a default track
        const tracks = await storage.listTracks(3);
        if (tracks.length > 0) {
          return res.json({
            type: 'track',
            data: tracks[0],
            nextTracks: tracks.slice(1)
          });
        }
        return res.status(404).json({ message: 'No content currently scheduled' });
      }

      if (currentScheduleItem.type === 'show') {
        const show = await storage.getShow(currentScheduleItem.itemId);
        if (!show) {
          return res.status(404).json({ message: 'Scheduled show not found' });
        }

        // Get some random tracks for the playlist
        const tracks = await storage.listTracks(3);

        return res.json({
          type: 'show',
          data: show,
          nextTracks: tracks
        });
      } else if (currentScheduleItem.type === 'track') {
        const track = await storage.getTrack(currentScheduleItem.itemId);
        if (!track) {
          return res.status(404).json({ message: 'Scheduled track not found' });
        }

        // Get some more tracks to queue up
        const tracks = await storage.listTracks(3);
        const nextTracks = tracks.filter(t => t.id !== track.id).slice(0, 2);

        return res.json({
          type: 'track',
          data: track,
          nextTracks
        });
      }

      return res.status(400).json({ message: 'Unknown schedule item type' });
    } catch (error) {
      res.status(500).json({ message: 'Error fetching current content', error: String(error) });
    }
  });

  // User routes
  app.post('/api/login', async (req: Request, res: Response) => {
    try {
      const { username, password } = req.body;

      if (!username || !password) {
        return res.status(400).json({ message: 'Username and password are required' });
      }

      const user = await storage.getUserByUsername(username);

      if (!user || user.password !== password) { // In production, use proper password hashing
        return res.status(401).json({ message: 'Invalid credentials' });
      }

      // In a real app, would generate and return a JWT
      const token = user.isAdmin ? 'admin-token' : 'user-token';

      return res.json({
        token,
        user: {
          id: user.id,
          username: user.username,
          email: user.email,
          fullName: user.fullName,
          isAdmin: user.isAdmin
        }
      });
    } catch (error) {
      res.status(500).json({ message: 'Login error', error: String(error) });
    }
