        return res.status(400).json({ message: 'Audio file is required' });
      }

      const audioFile = files.audio[0];
      const imageFile = files.image?.[0];

      // Extract audio duration from the file using music-metadata
      let audioDuration = 0;
      if (audioFile) {
        try {
          // Import the music-metadata library
          const mm = await import('music-metadata');

          // Parse the audio file metadata
          const metadata = await mm.parseBuffer(audioFile.buffer, {
            mimeType: audioFile.mimetype,
            size: audioFile.size
          });

          // Extract the duration in seconds and round to nearest integer
          if (metadata.format && metadata.format.duration) {
            audioDuration = Math.round(metadata.format.duration);
            console.log(`Extracted audio duration: ${audioDuration} seconds`);
          } else {
            console.log('Could not extract duration from audio file metadata');
          }
        } catch (metadataError) {
          console.error('Error extracting audio metadata:', metadataError);
          // Fall back to client-provided duration if available
          if (req.body.audioDuration) {
            audioDuration = parseInt(req.body.audioDuration, 10);
            console.log(`Using client-provided duration: ${audioDuration} seconds`);
          }
        }
      } else if (req.body.audioDuration) {
        // Fall back to client-provided duration
        audioDuration = parseInt(req.body.audioDuration, 10);
      }

      // Upload files to R2
      const audioFileName = await uploadFileToR2(
        audioFile.buffer, 
        audioFile.originalname,
        audioFile.mimetype
      );

      let imageFileName = null;
      if (imageFile) {
        imageFileName = await uploadFileToR2(
          imageFile.buffer,
          imageFile.originalname,
          imageFile.mimetype
        );
      }

      // Get public URLs for the uploaded files using the correct format (bucket in path)
      const audioUrl = getPublicFileUrl(audioFileName);
      const coverArt = imageFileName ? getPublicFileUrl(imageFileName) : null;

      // Check and correct URL format if needed (add explicit logging)
      console.log(`Generated audio URL: ${audioUrl}`);

      // Create a signed URL with an expiration for secure access
      const signedAudioUrl = await getSignedFileUrl(audioFileName);
      console.log(`Generated signed URL: ${signedAudioUrl}`);

      // Import AI tagging service
      const { analyzeAudioFile } = await import('./ai-tagging');

      // Perform AI analysis if we have audio file
      let aiAnalysis = null;
      if (audioFileName) {
        try {
          aiAnalysis = await analyzeAudioFile(audioFileName, {
            title: req.body.title || audioFileName,
            artist: req.body.artist || 'Unknown Artist',
            duration: audioDuration
          });
          console.log('AI analysis completed:', aiAnalysis);
        } catch (error) {
          console.error('AI analysis failed:', error);
        }
      }

      // Store metadata in the response
      const responseData = {
        audioUrl, // Public URL
        signedAudioUrl, // Secure signed URL with expiration
        audioFileName, // Original filename in R2
        coverArt, // Public URL for cover image
        imageFileName, // Original filename in R2
        audioDuration, // Duration extracted from audio metadata
        aiAnalysis // AI-generated tags and metadata
      };

      // Log successful upload with duration info
      console.log(`File uploaded successfully: ${audioFileName}${imageFileName ? ', ' + imageFileName : ''}, Duration: ${audioDuration}s`);

      res.status(200).json(responseData);
    } catch (error) {
      console.error('Upload error:', error);
      res.status(500).json({ message: 'Error uploading files', error: String(error) });
    }
  });

