      const { generateUniqueFilename, uploadFileToR2 } = await import('./r2');

      // Upload to R2
      const filename = generateUniqueFilename(req.file.originalname);
      const fileUrl = await uploadFileToR2(req.file.buffer, filename);

      // Determine file type
      const fileExtension = req.file.originalname.split('.').pop()?.toLowerCase();
      let type = 'text';
      if (['mp3', 'wav', 'm4a', 'aac'].includes(fileExtension || '')) {
        type = 'audio';
      } else if (['md', 'txt'].includes(fileExtension || '')) {
        type = 'script';
      }

      const materialData = {
        formatId,
        filename: req.file.originalname,
        type,
        fileUrl,
        processed: false
      };

      const [material] = await db.insert(schema.podcastMaterials)
        .values(materialData)
        .returning();

