        .where(eq(djMixes.id, id))
        .returning();

      if (!mix) {
        return res.status(404).json({ message: 'DJ mix not found' });
      }

      // Create schedule item
      const scheduleData = {
        type: 'dj_mix',
        itemId: id,
        startTime: new Date(scheduleTime),
        endTime: new Date(new Date(scheduleTime).getTime() + mix.duration * 1000),
        isRecurring: false
      };

      const [scheduleItem] = await db.insert(schema.scheduleItems).values(scheduleData).returning();

      res.json({ mix, scheduleItem });
    } catch (error) {
      res.status(500).json({ message: 'Error scheduling DJ mix', error: String(error) });
    }
  });

  app.delete('/api/dj-mixes/:id', requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const [deleted] = await db.delete(djMixes).where(eq(djMixes.id, id)).returning();

      if (!deleted) {
        return res.status(404).json({ message: 'DJ mix not found' });
      }

      res.json({ message: 'DJ mix deleted successfully' });
    } catch (error) {
      res.status(500).json({ message: 'Error deleting DJ mix', error: String(error) });
    }
  });

  // Speakers API
  app.get('/api/speakers', async (req: Request, res: Response) => {
    try {
      const speakerList = await db.select().from(speakers).orderBy(asc(speakers.code));
      res.json(speakerList);
    } catch (error) {
      res.status(500).json({ message: 'Error fetching speakers', error: String(error) });
    }
  });

  app.post('/api/speakers', requireAdmin, upload.single('file'), async (req: Request, res: Response) => {
    try {
      if (!req.file) {
        return res.status(400).json({ message: 'No voice sample uploaded' });
      }

      const { generateUniqueFilename, uploadFileToR2 } = await import('./r2');

      // Upload voice sample to R2
      const filename = generateUniqueFilename(req.file.originalname);
      const sampleAudioUrl = await uploadFileToR2(req.file.buffer, filename);

      const speakerData = {
        name: req.body.name,
        code: req.body.code.toUpperCase(),
        colorTag: req.body.colorTag,
        voiceType: req.body.voiceType,
        language: req.body.language || 'en',
        personality: req.body.personality || null,
        sampleAudioUrl,
        ttsVoiceId: `tts_${req.body.code.toLowerCase()}_${Date.now()}`, // Mock TTS ID
        isActive: true
      };

      const [speaker] = await db.insert(speakers).values(speakerData).returning();
      res.status(201).json(speaker);
    } catch (error) {
      res.status(500).json({ message: 'Error creating speaker', error: String(error) });
    }
  });

  app.post('/api/speakers/:id/test-tts', requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const { text } = req.body;

      // Mock TTS generation - in real implementation would use OpenAI TTS
      const audioUrl = `/api/placeholder/tts-test-${id}-${Date.now()}.mp3`;
      res.json({ audioUrl });
    } catch (error) {
      res.status(500).json({ message: 'Error generating TTS test', error: String(error) });
    }
  });

  app.delete('/api/speakers/:id', requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const [deleted] = await db.delete(speakers).where(eq(speakers.id, id)).returning();

      if (!deleted) {
        return res.status(404).json({ message: 'Speaker not found' });
      }

      res.json({ message: 'Speaker deleted successfully' });
    } catch (error) {
      res.status(500).json({ message: 'Error deleting speaker', error: String(error) });
    }
  });

  // Dubai Hotspots API
  app.get('/api/dubai-hotspots', async (req: Request, res: Response) => {
    try {
      const hotspotList = await db.select().from(dubaiHotspots)
        .where(eq(dubaiHotspots.isActive, true))
        .orderBy(desc(dubaiHotspots.clickCount));
      res.json(hotspotList);
    } catch (error) {
      res.status(500).json({ message: 'Error fetching Dubai hotspots', error: String(error) });
    }
  });

  app.post('/api/dubai-hotspots', requireAdmin, async (req: Request, res: Response) => {
    try {
      const hotspotData = insertDubaiHotspotSchema.parse(req.body);
      const [hotspot] = await db.insert(dubaiHotspots).values(hotspotData).returning();
      res.status(201).json(hotspot);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: 'Invalid hotspot data', errors: error.errors });
      }
      res.status(500).json({ message: 'Error creating Dubai hotspot', error: String(error) });
    }
  });

  app.post('/api/dubai-hotspots/:id/click', async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const [hotspot] = await db.update(dubaiHotspots)
        .set({ clickCount: db.select().from(dubaiHotspots).where(eq(dubaiHotspots.id, id)) })
        .where(eq(dubaiHotspots.id, id))
        .returning();

      res.json({ success: true });
    } catch (error) {
      res.status(500).json({ message: 'Error tracking click', error: String(error) });
    }
  });

  // Format Chapters API
  app.get('/api/format-chapters/:formatId', async (req: Request, res: Response) => {
    try {
      const formatId = parseInt(req.params.formatId);
      const chapters = await db.select().from(formatChapters)
        .where(eq(formatChapters.formatId, formatId))
        .orderBy(asc(formatChapters.orderIndex));
      res.json(chapters);
    } catch (error) {
      res.status(500).json({ message: 'Error fetching format chapters', error: String(error) });
    }
  });

  app.post('/api/format-chapters', requireAdmin, async (req: Request, res: Response) => {
    try {
      const chapterData = insertFormatChapterSchema.parse(req.body);
      const [chapter] = await db.insert(formatChapters).values(chapterData).returning();
      res.status(201).json(chapter);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: 'Invalid chapter data', errors: error.errors });
      }
      res.status(500).json({ message: 'Error creating format chapter', error: String(error) });
    }
  });

  // Partner Agreements API
  app.get('/api/partner-agreements', async (req: Request, res: Response) => {
    try {
      const agreements = await db.select().from(partnerAgreements).orderBy(desc(partnerAgreements.createdAt));
      res.json(agreements);
    } catch (error) {
      res.status(500).json({ message: 'Error fetching partner agreements', error: String(error) });
    }
  });

  app.post('/api/partner-agreements', requireAdmin, async (req: Request, res: Response) => {
    try {
      const agreementData = insertPartnerAgreementSchema.parse(req.body);
      const [agreement] = await db.insert(partnerAgreements).values(agreementData).returning();
      res.status(201).json(agreement);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: 'Invalid agreement data', errors: error.errors });
      }
      res.status(500).json({ message: 'Error creating partner agreement', error: String(error) });
    }
  });

  // Create HTTP server
  const httpServer = createServer(app);

  return httpServer;
}

