import {
  User, InsertUser, users,
  Track, InsertTrack, tracks,
  Show, InsertShow, shows,
  Episode, InsertEpisode, episodes,
  Playlist, InsertPlaylist, playlists,
  PlaylistTrack, InsertPlaylistTrack, playlistTracks,
  ModeratorMessage, InsertModeratorMessage, moderatorMessages,
  ScheduleItem, InsertScheduleItem, scheduleItems,
  Product, InsertProduct, products,
  Location, InsertLocation, locations,
  Moderator, InsertModerator, moderators,
  ProgramFormat, InsertProgramFormat, programFormats,
  ProgramBlock, InsertProgramBlock, programBlocks,
  Event, InsertEvent, events,
  WeeklyAlbum, InsertWeeklyAlbum, weeklyAlbums,
  AiSuggestion, InsertAiSuggestion, aiSuggestions
} from "@shared/schema";
import { db } from "./db";
import { eq, like, ilike, desc, and, asc, or, lte, gte, isNull, sql } from "drizzle-orm";

export interface IStorage {
  // User management
  getUser(id: number): Promise<User | undefined>;
  getUserByUsername(username: string): Promise<User | undefined>;
  createUser(user: InsertUser): Promise<User>;
  listUsers(): Promise<User[]>;

  // Track management
  getTrack(id: number): Promise<Track | undefined>;
  createTrack(track: InsertTrack): Promise<Track>;
  updateTrack(id: number, track: Partial<InsertTrack>): Promise<Track | undefined>;
  deleteTrack(id: number): Promise<boolean>;
  listTracks(limit?: number): Promise<Track[]>;
  searchTracks(query: string): Promise<Track[]>;
  getTracksWithMood(mood: string): Promise<Track[]>;

  // Show management
  getShow(id: number): Promise<Show | undefined>;
  createShow(show: InsertShow): Promise<Show>;
  updateShow(id: number, show: Partial<InsertShow>): Promise<Show | undefined>;
  deleteShow(id: number): Promise<boolean>;
  listShows(limit?: number): Promise<Show[]>;
  listFeaturedShows(): Promise<Show[]>;

  // Episode management
  getEpisode(id: number): Promise<Episode | undefined>;
  createEpisode(episode: InsertEpisode): Promise<Episode>;
  updateEpisode(id: number, episode: Partial<InsertEpisode>): Promise<Episode | undefined>;
  deleteEpisode(id: number): Promise<boolean>;
  listEpisodesByShow(showId: number): Promise<Episode[]>;
  listRecentEpisodes(limit?: number): Promise<Episode[]>;

  // Playlist management
  getPlaylist(id: number): Promise<Playlist | undefined>;
  createPlaylist(playlist: InsertPlaylist): Promise<Playlist>;
  updatePlaylist(id: number, playlist: Partial<InsertPlaylist>): Promise<Playlist | undefined>;
  deletePlaylist(id: number): Promise<boolean>;
  listPlaylists(): Promise<Playlist[]>;

  // Playlist track management
  getPlaylistTracks(playlistId: number): Promise<Track[]>;
  addTrackToPlaylist(playlistTrack: InsertPlaylistTrack): Promise<PlaylistTrack>;
  removeTrackFromPlaylist(playlistId: number, trackId: number): Promise<boolean>;
  reorderPlaylistTrack(playlistId: number, trackId: number, newPosition: number): Promise<boolean>;

  // Moderator message management
  getModeratorMessage(id: number): Promise<ModeratorMessage | undefined>;
  createModeratorMessage(message: InsertModeratorMessage): Promise<ModeratorMessage>;
  updateModeratorMessage(id: number, message: Partial<InsertModeratorMessage>): Promise<ModeratorMessage | undefined>;
  deleteModeratorMessage(id: number): Promise<boolean>;
  listModeratorMessages(): Promise<ModeratorMessage[]>;
  getModeratorMessagesByTags(tags: string[]): Promise<ModeratorMessage[]>;

  // Schedule management
  getScheduleItem(id: number): Promise<ScheduleItem | undefined>;
  createScheduleItem(scheduleItem: InsertScheduleItem): Promise<ScheduleItem>;
  updateScheduleItem(id: number, scheduleItem: Partial<InsertScheduleItem>): Promise<ScheduleItem | undefined>;
  deleteScheduleItem(id: number): Promise<boolean>;
  listScheduleItems(startDate: Date, endDate: Date): Promise<ScheduleItem[]>;
  getCurrentScheduleItem(): Promise<ScheduleItem | undefined>;

  // Product management
  getProduct(id: number): Promise<Product | undefined>;
  createProduct(product: InsertProduct): Promise<Product>;
  updateProduct(id: number, product: Partial<InsertProduct>): Promise<Product | undefined>;
  deleteProduct(id: number): Promise<boolean>;
  listProducts(limit?: number): Promise<Product[]>;
  getProductsByCategory(category: string): Promise<Product[]>;
  incrementProductImpressions(id: number): Promise<Product | undefined>;
  incrementProductClicks(id: number): Promise<Product | undefined>;

  // Location management
  getLocation(id: number): Promise<Location | undefined>;
  createLocation(location: InsertLocation): Promise<Location>;
  updateLocation(id: number, location: Partial<InsertLocation>): Promise<Location | undefined>;
  deleteLocation(id: number): Promise<boolean>;
  listLocations(limit?: number): Promise<Location[]>;
  getLocationsByCategory(category: string): Promise<Location[]>;
  searchLocations(query: string): Promise<Location[]>;
}

export class MemStorage implements IStorage {
  private users: Map<number, User>;
  private tracks: Map<number, Track>;
  private shows: Map<number, Show>;
  private episodes: Map<number, Episode>;
  private playlists: Map<number, Playlist>;
  private playlistTracks: Map<number, PlaylistTrack>;
  private moderatorMessages: Map<number, ModeratorMessage>;
  private scheduleItems: Map<number, ScheduleItem>;
  private products: Map<number, Product>;
  private locations: Map<number, Location>;

  private userCurrentId: number;
  private trackCurrentId: number;
  private showCurrentId: number;
  private episodeCurrentId: number;
  private playlistCurrentId: number;
  private playlistTrackCurrentId: number;
  private moderatorMessageCurrentId: number;
  private scheduleItemCurrentId: number;
  private productCurrentId: number;
  private locationCurrentId: number;

  constructor() {
    this.users = new Map();
    this.tracks = new Map();
    this.shows = new Map();
    this.episodes = new Map();
    this.playlists = new Map();
    this.playlistTracks = new Map();
    this.moderatorMessages = new Map();
    this.scheduleItems = new Map();
    this.products = new Map();
    this.locations = new Map();

    this.userCurrentId = 1;
    this.trackCurrentId = 1;
    this.showCurrentId = 1;
    this.episodeCurrentId = 1;
    this.playlistCurrentId = 1;
    this.playlistTrackCurrentId = 1;
    this.moderatorMessageCurrentId = 1;
    this.scheduleItemCurrentId = 1;
    this.productCurrentId = 1;
    this.locationCurrentId = 1;

    // Initialize with sample data
    this.initializeSampleData();
  }

  // User methods
  async getUser(id: number): Promise<User | undefined> {
    return this.users.get(id);
  }

  async getUserByUsername(username: string): Promise<User | undefined> {
    return Array.from(this.users.values()).find(
      (user) => user.username === username,
    );
  }

  async createUser(insertUser: InsertUser): Promise<User> {
    const id = this.userCurrentId++;
    const user: User = { ...insertUser, id, createdAt: new Date() };
    this.users.set(id, user);
    return user;
  }

  async listUsers(): Promise<User[]> {
    return Array.from(this.users.values());
  }

  // Track methods
  async getTrack(id: number): Promise<Track | undefined> {
    return this.tracks.get(id);
  }

  async createTrack(insertTrack: InsertTrack): Promise<Track> {
    const id = this.trackCurrentId++;
    const track: Track = { ...insertTrack, id, createdAt: new Date() };
    this.tracks.set(id, track);
    return track;
  }

  async updateTrack(id: number, updateData: Partial<InsertTrack>): Promise<Track | undefined> {
    const track = await this.getTrack(id);
    if (!track) return undefined;

    const updatedTrack = { ...track, ...updateData };
    this.tracks.set(id, updatedTrack);
    return updatedTrack;
  }

  async deleteTrack(id: number): Promise<boolean> {
    return this.tracks.delete(id);
  }

  async listTracks(limit: number = 100): Promise<Track[]> {
    return Array.from(this.tracks.values()).slice(0, limit);
  }

  async searchTracks(query: string): Promise<Track[]> {
    const lowerQuery = query.toLowerCase();
    return Array.from(this.tracks.values()).filter(track => 
      track.title.toLowerCase().includes(lowerQuery) ||
      track.artist.toLowerCase().includes(lowerQuery) ||
      (track.album && track.album.toLowerCase().includes(lowerQuery))
    );
  }

  async getTracksWithMood(mood: string): Promise<Track[]> {
    return Array.from(this.tracks.values()).filter(track => track.mood === mood);
  }

  // Show methods
  async getShow(id: number): Promise<Show | undefined> {
    return this.shows.get(id);
  }

  async createShow(insertShow: InsertShow): Promise<Show> {
    const id = this.showCurrentId++;
    const show: Show = { ...insertShow, id, createdAt: new Date() };
    this.shows.set(id, show);
    return show;
  }

  async updateShow(id: number, updateData: Partial<InsertShow>): Promise<Show | undefined> {
    const show = await this.getShow(id);
    if (!show) return undefined;

    const updatedShow = { ...show, ...updateData };
    this.shows.set(id, updatedShow);
    return updatedShow;
  }

  async deleteShow(id: number): Promise<boolean> {
    return this.shows.delete(id);
  }

  async listShows(limit: number = 100): Promise<Show[]> {
    return Array.from(this.shows.values()).slice(0, limit);
  }

  async listFeaturedShows(): Promise<Show[]> {
    return Array.from(this.shows.values()).filter(show => show.isFeatured);
  }

  // Episode methods
  async getEpisode(id: number): Promise<Episode | undefined> {
    return this.episodes.get(id);
  }

  async createEpisode(insertEpisode: InsertEpisode): Promise<Episode> {
    const id = this.episodeCurrentId++;
    const episode: Episode = { ...insertEpisode, id, createdAt: new Date() };
    this.episodes.set(id, episode);
    return episode;
  }

  async updateEpisode(id: number, updateData: Partial<InsertEpisode>): Promise<Episode | undefined> {
    const episode = await this.getEpisode(id);
    if (!episode) return undefined;

    const updatedEpisode = { ...episode, ...updateData };
    this.episodes.set(id, updatedEpisode);
    return updatedEpisode;
  }

  async deleteEpisode(id: number): Promise<boolean> {
    return this.episodes.delete(id);
  }

  async listEpisodesByShow(showId: number): Promise<Episode[]> {
    return Array.from(this.episodes.values()).filter(episode => episode.showId === showId);
  }

  async listRecentEpisodes(limit: number = 10): Promise<Episode[]> {
    return Array.from(this.episodes.values())
      .sort((a, b) => b.publishDate.getTime() - a.publishDate.getTime())
      .slice(0, limit);
  }

  // Playlist methods
  async getPlaylist(id: number): Promise<Playlist | undefined> {
    return this.playlists.get(id);
  }

  async createPlaylist(insertPlaylist: InsertPlaylist): Promise<Playlist> {
    const id = this.playlistCurrentId++;
    const playlist: Playlist = { ...insertPlaylist, id, createdAt: new Date() };
    this.playlists.set(id, playlist);
    return playlist;
  }

  async updatePlaylist(id: number, updateData: Partial<InsertPlaylist>): Promise<Playlist | undefined> {
    const playlist = await this.getPlaylist(id);
    if (!playlist) return undefined;

    const updatedPlaylist = { ...playlist, ...updateData };
    this.playlists.set(id, updatedPlaylist);
    return updatedPlaylist;
  }

  async deletePlaylist(id: number): Promise<boolean> {
    return this.playlists.delete(id);
  }

  async listPlaylists(): Promise<Playlist[]> {
    return Array.from(this.playlists.values());
  }

  // Playlist tracks methods
  async getPlaylistTracks(playlistId: number): Promise<Track[]> {
    const playlistTracksArray = Array.from(this.playlistTracks.values())
      .filter(item => item.playlistId === playlistId)
      .sort((a, b) => a.position - b.position);

    const tracks: Track[] = [];
    for (const pt of playlistTracksArray) {
      const track = await this.getTrack(pt.trackId);
      if (track) tracks.push(track);
    }

    return tracks;
  }

  async addTrackToPlaylist(insertPlaylistTrack: InsertPlaylistTrack): Promise<PlaylistTrack> {
    const id = this.playlistTrackCurrentId++;
    const playlistTrack: PlaylistTrack = { ...insertPlaylistTrack, id };
    this.playlistTracks.set(id, playlistTrack);
    return playlistTrack;
  }

  async removeTrackFromPlaylist(playlistId: number, trackId: number): Promise<boolean> {
    let found = false;
    for (const [key, value] of this.playlistTracks.entries()) {
      if (value.playlistId === playlistId && value.trackId === trackId) {
        this.playlistTracks.delete(key);
        found = true;
        break;
      }
    }

    // Reorder positions if needed
    if (found) {
      const playlistTracksArray = Array.from(this.playlistTracks.values())
        .filter(item => item.playlistId === playlistId)
        .sort((a, b) => a.position - b.position);

      for (let i = 0; i < playlistTracksArray.length; i++) {
        const pt = playlistTracksArray[i];
        pt.position = i + 1;
        this.playlistTracks.set(pt.id, pt);
      }
    }

    return found;
  }

  async reorderPlaylistTrack(playlistId: number, trackId: number, newPosition: number): Promise<boolean> {
    const playlistTracksArray = Array.from(this.playlistTracks.values())
      .filter(item => item.playlistId === playlistId)
      .sort((a, b) => a.position - b.position);

    if (newPosition < 1 || newPosition > playlistTracksArray.length) return false;

    const itemIndex = playlistTracksArray.findIndex(pt => pt.trackId === trackId);
    if (itemIndex === -1) return false;

    const item = playlistTracksArray[itemIndex];
    const oldPosition = item.position;

    // Reorder positions
    if (oldPosition < newPosition) {
      for (let i = 0; i < playlistTracksArray.length; i++) {
        const pt = playlistTracksArray[i];
        if (pt.position > oldPosition && pt.position <= newPosition) {
          pt.position--;
          this.playlistTracks.set(pt.id, pt);
        }
      }
    } else if (oldPosition > newPosition) {
      for (let i = 0; i < playlistTracksArray.length; i++) {
        const pt = playlistTracksArray[i];
        if (pt.position >= newPosition && pt.position < oldPosition) {
          pt.position++;
          this.playlistTracks.set(pt.id, pt);
        }
      }
    }

    item.position = newPosition;
    this.playlistTracks.set(item.id, item);

    return true;
  }

  // Moderator message methods
  async getModeratorMessage(id: number): Promise<ModeratorMessage | undefined> {
    return this.moderatorMessages.get(id);
  }

  async createModeratorMessage(insertMessage: InsertModeratorMessage): Promise<ModeratorMessage> {
    const id = this.moderatorMessageCurrentId++;
    const message: ModeratorMessage = { ...insertMessage, id, createdAt: new Date() };
    this.moderatorMessages.set(id, message);
    return message;
  }

  async updateModeratorMessage(id: number, updateData: Partial<InsertModeratorMessage>): Promise<ModeratorMessage | undefined> {
    const message = await this.getModeratorMessage(id);
    if (!message) return undefined;

    const updatedMessage = { ...message, ...updateData };
    this.moderatorMessages.set(id, updatedMessage);
    return updatedMessage;
  }

  async deleteModeratorMessage(id: number): Promise<boolean> {
    return this.moderatorMessages.delete(id);
  }

  async listModeratorMessages(): Promise<ModeratorMessage[]> {
    return Array.from(this.moderatorMessages.values());
  }

  async getModeratorMessagesByTags(tags: string[]): Promise<ModeratorMessage[]> {
    return Array.from(this.moderatorMessages.values()).filter(msg => {
      const msgTags = msg.tags as string[];
      return tags.some(tag => msgTags.includes(tag));
    });
  }

  // Schedule methods
  async getScheduleItem(id: number): Promise<ScheduleItem | undefined> {
    return this.scheduleItems.get(id);
  }

  async createScheduleItem(insertScheduleItem: InsertScheduleItem): Promise<ScheduleItem> {
    const id = this.scheduleItemCurrentId++;
    const scheduleItem: ScheduleItem = { ...insertScheduleItem, id, createdAt: new Date() };
    this.scheduleItems.set(id, scheduleItem);
    return scheduleItem;
  }

  async updateScheduleItem(id: number, updateData: Partial<InsertScheduleItem>): Promise<ScheduleItem | undefined> {
    const scheduleItem = await this.getScheduleItem(id);
    if (!scheduleItem) return undefined;

    const updatedScheduleItem = { ...scheduleItem, ...updateData };
    this.scheduleItems.set(id, updatedScheduleItem);
    return updatedScheduleItem;
  }

  async deleteScheduleItem(id: number): Promise<boolean> {
    return this.scheduleItems.delete(id);
  }

  async listScheduleItems(startDate: Date, endDate: Date): Promise<ScheduleItem[]> {
    return Array.from(this.scheduleItems.values()).filter(item => {
      const itemStartTime = new Date(item.startTime);
      return itemStartTime >= startDate && itemStartTime <= endDate;
    });
  }

  async getCurrentScheduleItem(): Promise<ScheduleItem | undefined> {
    const now = new Date();
    const items = Array.from(this.scheduleItems.values());

    // Check for non-recurring specific items first
    for (const item of items) {
      if (!item.isRecurring) {
        const startTime = new Date(item.startTime);
        const endTime = item.endTime ? new Date(item.endTime) : new Date(startTime.getTime() + 3600000); // Default 1 hour

        if (now >= startTime && now <= endTime) {
          return item;
        }
      }
    }

    // Then check recurring items
    for (const item of items) {
      if (item.isRecurring && item.recurrencePattern) {
        const startTime = new Date(item.startTime);
        const endTime = item.endTime ? new Date(item.endTime) : new Date(startTime.getTime() + 3600000);

        const startHour = startTime.getHours();
        const startMinute = startTime.getMinutes();
        const endHour = endTime.getHours();
        const endMinute = endTime.getMinutes();

        const currentHour = now.getHours();
        const currentMinute = now.getMinutes();
        const currentDay = now.getDay(); // 0 = Sunday, 6 = Saturday

        const isTimeInRange = 
          (currentHour > startHour || (currentHour === startHour && currentMinute >= startMinute)) && 
          (currentHour < endHour || (currentHour === endHour && currentMinute <= endMinute));

        if (isTimeInRange) {
          if (item.recurrencePattern === 'daily') {
            return item;
          } else if (item.recurrencePattern === 'weekdays' && currentDay >= 1 && currentDay <= 5) {
            return item;
          } else if (item.recurrencePattern === 'weekends' && (currentDay === 0 || currentDay === 6)) {
            return item;
          } else if (
            (item.recurrencePattern === 'Monday' && currentDay === 1) ||
            (item.recurrencePattern === 'Tuesday' && currentDay === 2) ||
            (item.recurrencePattern === 'Wednesday' && currentDay === 3) ||
            (item.recurrencePattern === 'Thursday' && currentDay === 4) ||
            (item.recurrencePattern === 'Friday' && currentDay === 5) ||
            (item.recurrencePattern === 'Saturday' && currentDay === 6) ||
            (item.recurrencePattern === 'Sunday' && currentDay === 0)
          ) {
            return item;
          }
        }
      }
    }

    return undefined;
  }

  // Product methods
  async getProduct(id: number): Promise<Product | undefined> {
    return this.products.get(id);
  }

  async createProduct(insertProduct: InsertProduct): Promise<Product> {
    const id = this.productCurrentId++;
    const product: Product = { 
      ...insertProduct, 
      id, 
      impressions: 0, 
      clicks: 0,
      createdAt: new Date() 
    };
    this.products.set(id, product);
    return product;
  }

  async updateProduct(id: number, updateData: Partial<InsertProduct>): Promise<Product | undefined> {
    const product = await this.getProduct(id);
    if (!product) return undefined;

    const updatedProduct = { ...product, ...updateData };
    this.products.set(id, updatedProduct);
    return updatedProduct;
  }

  async deleteProduct(id: number): Promise<boolean> {
    return this.products.delete(id);
  }

  async listProducts(limit: number = 100): Promise<Product[]> {
    return Array.from(this.products.values()).slice(0, limit);
  }

  async getProductsByCategory(category: string): Promise<Product[]> {
    return Array.from(this.products.values()).filter(product => product.category === category);
  }

  async incrementProductImpressions(id: number): Promise<Product | undefined> {
    const product = await this.getProduct(id);
    if (!product) return undefined;

    const updatedProduct = { ...product, impressions: product.impressions + 1 };
    this.products.set(id, updatedProduct);
    return updatedProduct;
  }

  async incrementProductClicks(id: number): Promise<Product | undefined> {
    const product = await this.getProduct(id);
    if (!product) return undefined;

    const updatedProduct = { ...product, clicks: product.clicks + 1 };
    this.products.set(id, updatedProduct);
    return updatedProduct;
  }

  // Location methods
  async getLocation(id: number): Promise<Location | undefined> {
    return this.locations.get(id);
  }

  async createLocation(insertLocation: InsertLocation): Promise<Location> {
    const id = this.locationCurrentId++;
    const location: Location = { ...insertLocation, id, createdAt: new Date() };
    this.locations.set(id, location);
    return location;
  }

  async updateLocation(id: number, updateData: Partial<InsertLocation>): Promise<Location | undefined> {
    const location = await this.getLocation(id);
    if (!location) return undefined;

    const updatedLocation = { ...location, ...updateData };
    this.locations.set(id, updatedLocation);
    return updatedLocation;
  }

  async deleteLocation(id: number): Promise<boolean> {
    return this.locations.delete(id);
  }

  async listLocations(limit: number = 100): Promise<Location[]> {
    return Array.from(this.locations.values()).slice(0, limit);
  }

  async getLocationsByCategory(category: string): Promise<Location[]> {
    return Array.from(this.locations.values()).filter(location => location.category === category);
  }

  async searchLocations(query: string): Promise<Location[]> {
    const lowerQuery = query.toLowerCase();
    return Array.from(this.locations.values()).filter(location => 
      location.name.toLowerCase().includes(lowerQuery) ||
      location.description.toLowerCase().includes(lowerQuery) ||
      location.category.toLowerCase().includes(lowerQuery)
    );
  }

  // Initialize sample data for development
  private async initializeSampleData() {
    // Create admin users
    await this.createUser({
      username: "admin",
      password: "adminpassword", // In production this would be hashed
      isAdmin: true,
      email: "admin@goldenpearlradio.com",
      fullName: "Admin User"
    });

    // Add alex user with admin privileges
    await this.createUser({
      username: "alex",
      password: "Adwords123!", // In production this would be hashed
      isAdmin: true,
      email: "alex@goldenpearlradio.com",
      fullName: "Alex Admin"
    });

    // Create sample tracks
    const track1 = await this.createTrack({
      title: "Modern Dubai Beat",
