export class DatabaseStorage implements IStorage {
  // User management
  async getUser(id: number): Promise<User | undefined> {
    const result = await db.select().from(users).where(eq(users.id, id));
    return result.length > 0 ? result[0] : undefined;
  }

  async getUserByUsername(username: string): Promise<User | undefined> {
    const result = await db.select().from(users).where(eq(users.username, username));
    return result.length > 0 ? result[0] : undefined;
  }

  async createUser(user: InsertUser): Promise<User> {
    const result = await db.insert(users).values(user).returning();
    return result[0];
  }

  async listUsers(): Promise<User[]> {
    return await db.select().from(users);
  }

  // Track management
  async getTrack(id: number): Promise<Track | undefined> {
    const result = await db.select().from(tracks).where(eq(tracks.id, id));
    return result.length > 0 ? result[0] : undefined;
  }

  async createTrack(track: InsertTrack): Promise<Track> {
    const result = await db.insert(tracks).values(track).returning();
    return result[0];
  }

  async updateTrack(id: number, updateData: Partial<InsertTrack>): Promise<Track | undefined> {
    const result = await db
      .update(tracks)
      .set(updateData)
      .where(eq(tracks.id, id))
      .returning();

    return result.length > 0 ? result[0] : undefined;
  }

  async deleteTrack(id: number): Promise<boolean> {
    const result = await db.delete(tracks).where(eq(tracks.id, id));
    return !!result;
  }

  async listTracks(limit: number = 100): Promise<Track[]> {
    return await db.select().from(tracks).limit(limit);
  }

  async searchTracks(query: string): Promise<Track[]> {
    const searchQuery = `%${query}%`;
    const queryLike = (column: any) => ilike(column, searchQuery);

    return await db.select().from(tracks).where(
      or(
        queryLike(tracks.title),
        queryLike(tracks.artist),
        queryLike(tracks.album),
        queryLike(tracks.genre)
      )
    );
  }

  async getTracksWithMood(mood: string): Promise<Track[]> {
    return await db.select().from(tracks).where(eq(tracks.mood, mood));
  }

  // Show management
  async getShow(id: number): Promise<Show | undefined> {
    const result = await db.select().from(shows).where(eq(shows.id, id));
    return result.length > 0 ? result[0] : undefined;
  }

  async createShow(show: InsertShow): Promise<Show> {
    const result = await db.insert(shows).values(show).returning();
    return result[0];
  }

  async updateShow(id: number, updateData: Partial<InsertShow>): Promise<Show | undefined> {
