  }

  async listModeratorMessages(): Promise<ModeratorMessage[]> {
    return await db.select().from(moderatorMessages);
  }

  async getModeratorMessagesByTags(tags: string[]): Promise<ModeratorMessage[]> {
    // Simplified approach without complex JSONB operations
    const allMessages = await this.listModeratorMessages();
    return allMessages.filter(msg => {
      if (!msg.tags) return false;
      const msgTags = msg.tags as string[];
      return tags.some(tag => msgTags.includes(tag));
    });
  }

