  // Playlist tracks methods
  async getPlaylistTracks(playlistId: number): Promise<Track[]> {
    const playlistTracksWithPosition = await db.select()
      .from(playlistTracks)
      .where(eq(playlistTracks.playlistId, playlistId))
      .orderBy(asc(playlistTracks.position));

    const trackIds = playlistTracksWithPosition.map(pt => pt.trackId);

    if (trackIds.length === 0) {
      return [];
    }

    return await db.select()
      .from(tracks)
      .where(
        sql`${tracks.id} IN (${sql.join(trackIds, sql`, `)})`
      );
  }

  async addTrackToPlaylist(insertPlaylistTrack: InsertPlaylistTrack): Promise<PlaylistTrack> {
    const result = await db.insert(playlistTracks)
      .values(insertPlaylistTrack)
      .returning();
    return result[0];
  }

  async removeTrackFromPlaylist(playlistId: number, trackId: number): Promise<boolean> {
    // First find the playlistTrack to delete
    const [playlistTrackToDelete] = await db.select()
      .from(playlistTracks)
      .where(
        and(
          eq(playlistTracks.playlistId, playlistId),
          eq(playlistTracks.trackId, trackId)
        )
      );

    if (!playlistTrackToDelete) {
      return false;
    }

    // Delete the playlist track
    const deleted = await db.delete(playlistTracks)
      .where(eq(playlistTracks.id, playlistTrackToDelete.id))
      .returning();

    if (deleted.length === 0) {
      return false;
    }

    // Update positions for remaining tracks
    const remainingTracks = await db.select()
      .from(playlistTracks)
      .where(eq(playlistTracks.playlistId, playlistId))
      .orderBy(asc(playlistTracks.position));

    for (let i = 0; i < remainingTracks.length; i++) {
      const track = remainingTracks[i];
      await db.update(playlistTracks)
        .set({ position: i + 1 })
        .where(eq(playlistTracks.id, track.id));
    }

    return true;
  }

  async reorderPlaylistTrack(playlistId: number, trackId: number, newPosition: number): Promise<boolean> {
    // Find the playlist track to reorder
    const [trackToReorder] = await db.select()
      .from(playlistTracks)
      .where(
        and(
          eq(playlistTracks.playlistId, playlistId),
          eq(playlistTracks.trackId, trackId)
        )
      );

    if (!trackToReorder) {
      return false;
    }

    const oldPosition = trackToReorder.position;

    // Get all playlist tracks
    const allTracks = await db.select()
      .from(playlistTracks)
      .where(eq(playlistTracks.playlistId, playlistId))
      .orderBy(asc(playlistTracks.position));

    // Check if new position is valid
    if (newPosition < 1 || newPosition > allTracks.length) {
      return false;
    }

    // No need to reorder if the position is the same
    if (oldPosition === newPosition) {
      return true;
    }

    // Reorder positions
    if (oldPosition < newPosition) {
      // Moving down: decrease position for items between old and new
      for (const pt of allTracks) {
        if (pt.position > oldPosition && pt.position <= newPosition) {
          await db.update(playlistTracks)
            .set({ position: pt.position - 1 })
            .where(eq(playlistTracks.id, pt.id));
        }
      }
    } else {
      // Moving up: increase position for items between new and old
      for (const pt of allTracks) {
        if (pt.position >= newPosition && pt.position < oldPosition) {
          await db.update(playlistTracks)
            .set({ position: pt.position + 1 })
            .where(eq(playlistTracks.id, pt.id));
        }
      }
    }

    // Update the position of the track being reordered
    await db.update(playlistTracks)
      .set({ position: newPosition })
      .where(eq(playlistTracks.id, trackToReorder.id));

    return true;
  }

