    const currentNonRecurring = await db.select().from(scheduleItems).where(
      and(
        lte(scheduleItems.startTime, now),
        or(
          isNull(scheduleItems.endTime),
          gte(scheduleItems.endTime, now)
        ),
        eq(scheduleItems.isRecurring, false)
      )
    ).orderBy(desc(scheduleItems.startTime)).limit(1);

    if (currentNonRecurring.length > 0) {
      return currentNonRecurring[0];
    }

    // If no non-recurring item is playing, check recurring items
    // This is a simplified implementation and would need more complex logic
