import { getPublicFileUrl, getSignedFileUrl, getDohaMetroSuiteUrl } from './r2';

async function testAudioUrls() {
  console.log('Testing audio URL generation...\n');

  // Test 1: Get public URL for Doha Metro Suite
  const filename = 'the-doha-metro-suite-afcad310.mp3';
  console.log(`Test 1: Public URL for "${filename}"`);
  const publicUrl = getPublicFileUrl(filename);
  console.log(`Result: ${publicUrl}`);

  // Test 2: Get signed URL for Doha Metro Suite
  console.log(`\nTest 2: Signed URL for "${filename}"`);
  try {
    const signedUrl = await getSignedFileUrl(filename);
    console.log(`Result: ${signedUrl}`);
    console.log(`URL contains signature: ${signedUrl.includes('X-Amz-Signature')}`);
  } catch (error) {
    console.error(`Error generating signed URL: ${error}`);
  }

  // Test 3: Get special Doha Metro Suite URL
  console.log('\nTest 3: Special Doha Metro Suite URL');
  const dohaMetroUrl = getDohaMetroSuiteUrl();
  console.log(`Result: ${dohaMetroUrl}`);

  // Test 4: Check URL formats
  console.log('\nTest 4: URL Format Comparison');
  console.log('Correct format (bucket in path):');
  console.log(` https://{ACCOUNT_ID}.r2.cloudflarestorage.com/{BUCKET_NAME}/{FILENAME}`);
  console.log('Incorrect format (bucket in subdomain):');
  console.log(` https://{BUCKET_NAME}.{ACCOUNT_ID}.r2.cloudflarestorage.com/{FILENAME}`);

  // Print summary
  console.log('\nURL Testing Summary:');
  console.log('1. Public URL format looks correct:', publicUrl.includes(`r2.cloudflarestorage.com/goldenpearl/${filename}`));
  console.log('2. Signed URL was successfully generated:', publicUrl !== undefined);
  console.log('3. Doha Metro Suite special URL is valid:', dohaMetroUrl.includes(`r2.cloudflarestorage.com/goldenpearl/${filename}`));
}

testAudioUrls().catch(console.error);

