import { S3Client, ListObjectsV2Command } from '@aws-sdk/client-s3';
import * as dotenv from 'dotenv';

// Load environment variables
dotenv.config();

// Log environment status
console.log('Testing R2 Connection...');
console.log('Environment variables status:');
console.log(`R2_ACCOUNT_ID: ${process.env.R2_ACCOUNT_ID ? 'Set' : 'Missing'}`);
console.log(`R2_ACCESS_KEY_ID: ${process.env.R2_ACCESS_KEY_ID ? 'Set' : 'Missing'}`); 
console.log(`R2_SECRET_ACCESS_KEY: ${process.env.R2_SECRET_ACCESS_KEY ? 'Set (value hidden)' : 'Missing'}`);
console.log(`R2_BUCKET_NAME: ${process.env.R2_BUCKET_NAME ? 'Set' : 'Missing'}`);

// Create R2 client
const r2Client = new S3Client({
  region: 'auto',
  endpoint: `https://${process.env.R2_ACCOUNT_ID}.r2.cloudflarestorage.com`,
  credentials: {
    accessKeyId: process.env.R2_ACCESS_KEY_ID || '',
    secretAccessKey: process.env.R2_SECRET_ACCESS_KEY || ''
  }
});

// Function to test the connection
async function testR2Connection() {
  try {
    // Try to list objects in the bucket
    const command = new ListObjectsV2Command({
      Bucket: process.env.R2_BUCKET_NAME || '',
      MaxKeys: 10
    });

    console.log(`Attempting to list objects in bucket: ${process.env.R2_BUCKET_NAME}`);
    const response = await r2Client.send(command);

    // Log the success and some details from the response
    console.log('✓ Successfully connected to R2 bucket!');
    console.log(`Found ${response.KeyCount || 0} objects in the bucket.`);

    if (response.Contents && response.Contents.length > 0) {
      console.log('First few objects:');
      response.Contents.slice(0, 5).forEach((object, index) => {
        console.log(`  ${index + 1}. ${object.Key} (${object.Size} bytes, Last modified: ${object.LastModified})`);
      });
    } else {
      console.log('The bucket is empty or you do not have permission to list its contents.');
    }

    // Test URL formats
    if (response.Contents && response.Contents.length > 0 && response.Contents[0].Key) {
      const exampleKey = response.Contents[0].Key;
      console.log('\nURL Format Examples:');
      console.log(`Public URL format: https://${process.env.R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${process.env.R2_BUCKET_NAME}/${exampleKey}`);
      console.log(`Alternative format: https://${process.env.R2_BUCKET_NAME}.${process.env.R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${exampleKey}`);
    }

    return true;
  } catch (error) {
    console.error('❌ Error connecting to R2:', error);
    return false;
  }
}

// Run the test
testR2Connection()
