import multer from 'multer';
import { Request } from 'express';

// Set up memory storage for multer
const storage = multer.memoryStorage();

// File filter function to validate file types
const fileFilter = (req: Request, file: Express.Multer.File, cb: multer.FileFilterCallback) => {
  // Allowed file types
  const allowedAudioTypes = ['audio/mpeg', 'audio/mp3', 'audio/wav', 'audio/ogg'];
  const allowedImageTypes = ['image/jpeg', 'image/png', 'image/jpg', 'image/gif', 'image/webp'];

  // Check if the file type is allowed
  if (file.fieldname === 'audio' && allowedAudioTypes.includes(file.mimetype)) {
    cb(null, true);
  } else if (file.fieldname === 'image' && allowedImageTypes.includes(file.mimetype)) {
    cb(null, true);
  } else {
    cb(new Error(`Invalid file type. Expected ${file.fieldname === 'audio' ? 'audio' : 'image'} file.`));
  }
};

// Create a multer instance for audio files
export const audioUpload = multer({
  storage,
  fileFilter,
  limits: {
    fileSize: 30 * 1024 * 1024, // 30MB max size for audio files
  }
});

// General file upload for all file types (podcast materials, documents, etc.)
export const upload = multer({
  storage,
  limits: {
    fileSize: 30 * 1024 * 1024, // 30MB max size
  },
  fileFilter: (req: Request, file: Express.Multer.File, cb: multer.FileFilterCallback) => {
    // Allow all file types for podcast materials
    const allowedTypes = [
      'audio/mpeg', 'audio/mp3', 'audio/wav', 'audio/ogg', 'audio/m4a',
      'text/plain', 'text/markdown', 'application/pdf',
      'image/jpeg', 'image/png', 'image/jpg'
    ];

    if (allowedTypes.includes(file.mimetype) || file.originalname.endsWith('.md') || file.originalname.endsWith('.txt')) {
      cb(null, true);
    } else {
      cb(new Error('Invalid file type. Allowed: audio, text, markdown, PDF, image files.'));
    }
  }
});

// Create a multer instance for image files
export const imageUpload = multer({
  storage,
  fileFilter,
  limits: {
    fileSize: 5 * 1024 * 1024, // 5MB max size for images
  }
});

// Create a multer instance for combined uploads (both audio and images)
export const fileUpload = multer({
  storage,
  fileFilter,
  limits: {
    fileSize: 30 * 1024 * 1024, // 30MB max size
  }
});

