import { pgTable, text, serial, integer, boolean, timestamp, jsonb } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

// User schema
export const users = pgTable("users", {
  id: serial("id").primaryKey(),
  username: text("username").notNull().unique(),
  password: text("password").notNull(),
  isAdmin: boolean("is_admin").default(false).notNull(),
  email: text("email").unique(),
  fullName: text("full_name"),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertUserSchema = createInsertSchema(users).pick({
  username: true,
  password: true,
  email: true,
  fullName: true,
  isAdmin: true
});

// Track/Song schema with enhanced AI tagging
export const tracks = pgTable("tracks", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  artist: text("artist").notNull(),
  album: text("album"),
  duration: integer("duration").notNull(), // Duration in seconds
  url: text("url").notNull(), // URL to audio file
  coverArt: text("cover_art"), // URL to cover art
  genre: text("genre"),
  mood: text("mood"), // e.g., "upbeat", "relaxed", "energetic"
  tempo: integer("tempo"), // BPM
  year: integer("year"),
  // AI-generated tags
  energyLevel: text("energy_level"), // low, medium, high
  timeOfDayFit: text("time_of_day_fit"), // morning, afternoon, evening, night
  vocalType: text("vocal_type"), // instrumental, vocal, mixed
  language: text("language"), // detected language for vocals
  culturalStyle: text("cultural_style"), // e.g., "Gulf Pop", "French Electro"
  aiTags: jsonb("ai_tags"), // Additional AI-generated tags as JSON
  isAiTagged: boolean("is_ai_tagged").default(false),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertTrackSchema = createInsertSchema(tracks).pick({
  title: true,
  artist: true,
  album: true,
  duration: true,
  url: true,
  coverArt: true,
  genre: true,
  mood: true,
  tempo: true,
  year: true,
  energyLevel: true,
  timeOfDayFit: true,
  vocalType: true,
  language: true,
  culturalStyle: true,
  aiTags: true,
  isAiTagged: true
});

// Shows/Programs schema
export const shows = pgTable("shows", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  description: text("description").notNull(),
  hostName: text("host_name"),
  scheduleTime: text("schedule_time"), // e.g., "Daily • 8:00 PM"
  coverImage: text("cover_image"),
  isFeatured: boolean("is_featured").default(false).notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertShowSchema = createInsertSchema(shows).pick({
  title: true,
  description: true,
  hostName: true,
  scheduleTime: true,
  coverImage: true,
  isFeatured: true
});

// Episodes schema
export const episodes = pgTable("episodes", {
  id: serial("id").primaryKey(),
  showId: integer("show_id").notNull(),
  title: text("title").notNull(),
  description: text("description").notNull(),
  audioUrl: text("audio_url").notNull(),
  duration: integer("duration").notNull(), // Duration in seconds
  publishDate: timestamp("publish_date").defaultNow().notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertEpisodeSchema = createInsertSchema(episodes).pick({
  showId: true,
  title: true,
  description: true,
  audioUrl: true,
  duration: true,
  publishDate: true
});

// Playlists schema
export const playlists = pgTable("playlists", {
  id: serial("id").primaryKey(),
  name: text("name").notNull(),
  description: text("description"),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertPlaylistSchema = createInsertSchema(playlists).pick({
  name: true,
  description: true
});

// Playlist Tracks junction table
export const playlistTracks = pgTable("playlist_tracks", {
  id: serial("id").primaryKey(),
  playlistId: integer("playlist_id").notNull(),
  trackId: integer("track_id").notNull(),
  position: integer("position").notNull() // Order in playlist
});

export const insertPlaylistTrackSchema = createInsertSchema(playlistTracks).pick({
  playlistId: true,
  trackId: true,
  position: true
});

// Moderator messages schema
export const moderatorMessages = pgTable("moderator_messages", {
  id: serial("id").primaryKey(),
  content: text("content").notNull(),
  duration: integer("duration").default(30).notNull(), // Duration in seconds
  type: text("type").default("announcement").notNull(), // Type of message: "announcement", "ad", "intro", etc.
  tags: jsonb("tags").default([]).notNull(), // Array of tags for targeting
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertModeratorMessageSchema = createInsertSchema(moderatorMessages).pick({
  content: true,
  duration: true,
  type: true,
  tags: true
});

// Schedule items schema
export const scheduleItems = pgTable("schedule_items", {
  id: serial("id").primaryKey(),
  type: text("type").notNull(), // "track", "show", "message", etc.
  itemId: integer("item_id").notNull(), // ID of the corresponding item
  startTime: timestamp("start_time").notNull(),
  endTime: timestamp("end_time"),
  isRecurring: boolean("is_recurring").default(false).notNull(),
  recurrencePattern: text("recurrence_pattern"), // e.g., "daily", "weekdays", "Mondays"
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertScheduleItemSchema = createInsertSchema(scheduleItems).pick({
  type: true,
  itemId: true,
  startTime: true,
  endTime: true,
  isRecurring: true,
  recurrencePattern: true
});

// Products/Offers schema for affiliate marketing
export const products = pgTable("products", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  description: text("description").notNull(),
  price: text("price").notNull(), // e.g., "AED 350"
  affiliateUrl: text("affiliate_url").notNull(),
  coverImage: text("cover_image"),
  category: text("category").notNull(), // e.g., "experience", "dining", "shopping"
  tags: jsonb("tags").default([]).notNull(), // For targeting specific audiences
  impressions: integer("impressions").default(0).notNull(),
  clicks: integer("clicks").default(0).notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertProductSchema = createInsertSchema(products).pick({
  title: true,
  description: true,
  price: true,
  affiliateUrl: true,
  coverImage: true,
  category: true,
  tags: true
});

// Dubai Guide Locations schema
export const locations = pgTable("locations", {
  id: serial("id").primaryKey(),
  name: text("name").notNull(),
  description: text("description").notNull(),
  category: text("category").notNull(), // e.g., "restaurant", "attraction", "shopping"
  imageUrl: text("image_url"),
  address: text("address"),
  website: text("website"),
  phone: text("phone"),
  rating: integer("rating"), // Rating out of 5
  tags: jsonb("tags").default([]).notNull(), // For better search and targeting
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertLocationSchema = createInsertSchema(locations).pick({
  name: true,
  description: true,
  category: true,
  imageUrl: true,
  address: true,
  website: true,
  phone: true,
  rating: true,
  tags: true
});

// Define types for all schemas
export type InsertUser = z.infer<typeof insertUserSchema>;
export type User = typeof users.$inferSelect;

export type InsertTrack = z.infer<typeof insertTrackSchema>;
export type Track = typeof tracks.$inferSelect;

export type InsertShow = z.infer<typeof insertShowSchema>;
export type Show = typeof shows.$inferSelect;

export type InsertEpisode = z.infer<typeof insertEpisodeSchema>;
export type Episode = typeof episodes.$inferSelect;

export type InsertPlaylist = z.infer<typeof insertPlaylistSchema>;
export type Playlist = typeof playlists.$inferSelect;

export type InsertPlaylistTrack = z.infer<typeof insertPlaylistTrackSchema>;
export type PlaylistTrack = typeof playlistTracks.$inferSelect;

export type InsertModeratorMessage = z.infer<typeof insertModeratorMessageSchema>;
export type ModeratorMessage = typeof moderatorMessages.$inferSelect;

export type InsertScheduleItem = z.infer<typeof insertScheduleItemSchema>;
export type ScheduleItem = typeof scheduleItems.$inferSelect;

export type InsertProduct = z.infer<typeof insertProductSchema>;
export type Product = typeof products.$inferSelect;

export type InsertLocation = z.infer<typeof insertLocationSchema>;
export type Location = typeof locations.$inferSelect;

// Breaking News schema
export const breakingNews = pgTable("breaking_news", {
  id: serial("id").primaryKey(),
  message: text("message").notNull(),
  voiceType: text("voice_type").notNull(), // Selected TTS voice
  priority: text("priority").default("normal").notNull(), // normal, urgent, critical
  isActive: boolean("is_active").default(true).notNull(),
  scheduledFor: timestamp("scheduled_for"),
  expiresAt: timestamp("expires_at"),
  audioUrl: text("audio_url"), // Generated TTS audio file
  insertedIntoSchedule: boolean("inserted_into_schedule").default(false).notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertBreakingNewsSchema = createInsertSchema(breakingNews).pick({
  message: true,
  voiceType: true,
  priority: true,
  scheduledFor: true,
  expiresAt: true,
  isActive: true
});

// DJ Mixes schema
export const djMixes = pgTable("dj_mixes", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  artist: text("artist").notNull(),
  duration: integer("duration").notNull(), // Duration in seconds
  audioUrl: text("audio_url").notNull(),
  coverArt: text("cover_art"),
  description: text("description"),
  genre: text("genre"),
  fadeInDuration: integer("fade_in_duration").default(5).notNull(), // seconds
  fadeOutDuration: integer("fade_out_duration").default(5).notNull(), // seconds
  crossfadeMode: text("crossfade_mode").default("auto").notNull(), // auto, manual, cut
  linkedProducts: jsonb("linked_products").default([]).notNull(), // Auto-suggested products
  isScheduled: boolean("is_scheduled").default(false).notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertDjMixSchema = createInsertSchema(djMixes).pick({
