  storyText: text("story_text"), // Detailed backstory for front page
  isActive: boolean("is_active").default(true).notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertWeeklyAlbumSchema = createInsertSchema(weeklyAlbums).pick({
  title: true,
  description: true,
  coverArt: true,
  releaseWeek: true,
  trackIds: true,
  price: true,
  purchaseUrl: true,
  storyText: true,
  isActive: true
});

// AI content suggestions schema - for smart programming recommendations
export const aiSuggestions = pgTable("ai_suggestions", {
  id: serial("id").primaryKey(),
  blockId: integer("block_id").notNull(),
  suggestionType: text("suggestion_type").notNull(), // "track", "format", "moderator"
  contentId: integer("content_id"), // ID of suggested track/format/moderator
  confidence: integer("confidence"), // AI confidence score 0-100
  reasoning: text("reasoning"), // AI explanation for suggestion
  isApplied: boolean("is_applied").default(false),
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertAiSuggestionSchema = createInsertSchema(aiSuggestions).pick({
  blockId: true,
  suggestionType: true,
  contentId: true,
  confidence: true,
  reasoning: true,
  isApplied: true
});

// Podcast episodes schema - for detailed episode planning and management
export const podcastEpisodes = pgTable("podcast_episodes", {
  id: serial("id").primaryKey(),
  formatId: integer("format_id").notNull(),
  title: text("title").notNull(),
  description: text("description").notNull(),
  scheduledDate: timestamp("scheduled_date").notNull(),
  status: text("status").notNull(), // 'planned', 'recorded', 'published'
  topics: jsonb("topics").default([]).notNull(), // Array of topic strings
  materials: jsonb("materials").default([]).notNull(), // Array of material references
  notes: text("notes"),
  duration: integer("duration"), // in minutes
  createdAt: timestamp("created_at").defaultNow().notNull()
});

export const insertPodcastEpisodeSchema = createInsertSchema(podcastEpisodes).pick({
  formatId: true,
  title: true,
  description: true,
  scheduledDate: true,
  status: true,
  topics: true,
  materials: true,
  notes: true,
  duration: true
});

// Podcast content materials schema - for uploaded scripts, audio notes, research docs
export const podcastMaterials = pgTable("podcast_materials", {
  id: serial("id").primaryKey(),
  formatId: integer("format_id").notNull(),
  filename: text("filename").notNull(),
  type: text("type").notNull(), // 'text', 'audio', 'script'
  uploadDate: timestamp("upload_date").defaultNow().notNull(),
  processed: boolean("processed").default(false).notNull(),
  fileUrl: text("file_url"), // R2 storage URL
  transcription: text("transcription"), // For audio files
  summary: text("summary"), // AI-generated summary
  tags: jsonb("tags").default([]).notNull()
});

export const insertPodcastMaterialSchema = createInsertSchema(podcastMaterials).pick({
  formatId: true,
  filename: true,
  type: true,
  processed: true,
  fileUrl: true,
  transcription: true,
  summary: true,
