import { Switch, Route } from "wouter";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import NotFound from "@/pages/not-found";
import Home from "@/pages/home";
import Archive from "@/pages/Archive";
import Podcasts from "@/pages/Podcasts";
import Shop from "@/pages/Shop";
import PitchUs from "@/pages/PitchUs";
import AdminDashboard from "@/pages/admin/index";
import MusicManager from "@/pages/admin/music-manager";
import ContentManager from "@/pages/admin/content-manager";
import Scheduler from "@/pages/admin/scheduler";
import ProgramScheduler from "@/pages/admin/program-scheduler";
import WeeklyAlbumsManager from "@/pages/admin/weekly-albums";
import PodcastPlanner from "@/pages/admin/podcast-planner";
import BreakingNews from "@/pages/admin/breaking-news";
import DjPanel from "@/pages/admin/dj-panel";
import Speakers from "@/pages/admin/speakers";
import VisitDubai from "@/pages/visit-dubai";
import AppLayout from "@/components/layout/AppLayout";

function Router() {
  return (
    <Switch>
      {/* Main routes */}
      <Route path="/" component={Home} />
      <Route path="/archive" component={Archive} />
      <Route path="/podcasts" component={Podcasts} />
      <Route path="/store" component={Shop} />
      <Route path="/pitch" component={PitchUs} />
      <Route path="/visit-dubai" component={VisitDubai} />

      {/* Admin routes */}
      <Route path="/admin" component={AdminDashboard} />
      <Route path="/admin/music-manager" component={MusicManager} />
      <Route path="/admin/content-manager" component={ContentManager} />
      <Route path="/admin/scheduler" component={Scheduler} />
      <Route path="/admin/program-scheduler" component={ProgramScheduler} />
      <Route path="/admin/weekly-albums" component={WeeklyAlbumsManager} />
      <Route path="/admin/podcast-planner/:formatId" component={PodcastPlanner} />
      <Route path="/admin/breaking-news" component={BreakingNews} />
      <Route path="/admin/dj-panel" component={DjPanel} />
      <Route path="/admin/speakers" component={Speakers} />

      {/* Fallback to 404 */}
      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <AppLayout>
          <Router />
        </AppLayout>
        <Toaster />
      </TooltipProvider>
    </QueryClientProvider>
  );
}

export default App;

