import { useQuery } from "@tanstack/react-query";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ShoppingCart, Music, Calendar } from "lucide-react";
import type { WeeklyAlbum } from "@shared/schema";

export default function CDOfTheWeek() {
  const { data: weeklyAlbum, isLoading } = useQuery<WeeklyAlbum>({
    queryKey: ['/api/weekly-albums/current']
  });

  if (isLoading) {
    return (
      <section className="mb-8">
        <div className="flex items-center gap-2 mb-4">
          <Music className="h-6 w-6 text-radio-gold" />
          <h2 className="font-poppins text-xl font-semibold">CD of the Week</h2>
        </div>
        <Card className="overflow-hidden">
          <div className="flex flex-col md:flex-row">
            <div className="md:w-1/3">
              <div className="aspect-square bg-gray-200 animate-pulse"></div>
            </div>
            <CardContent className="md:w-2/3 p-6">
              <div className="h-6 w-3/4 bg-gray-200 animate-pulse mb-3"></div>
              <div className="h-4 w-full bg-gray-200 animate-pulse mb-2"></div>
              <div className="h-4 w-5/6 bg-gray-200 animate-pulse mb-4"></div>
              <div className="flex items-center gap-4">
                <div className="h-10 w-32 bg-gray-200 animate-pulse"></div>
                <div className="h-6 w-20 bg-gray-200 animate-pulse"></div>
              </div>
            </CardContent>
          </div>
        </Card>
      </section>
    );
  }

  if (!weeklyAlbum) {
    return null;
  }

  const handlePurchaseClick = () => {
    if (weeklyAlbum.purchaseUrl) {
      window.open(weeklyAlbum.purchaseUrl, '_blank');
    }
  };

  return (
    <section className="mb-8">
      <div className="flex items-center gap-2 mb-4">
        <Music className="h-6 w-6 text-radio-gold" />
        <h2 className="font-poppins text-xl font-semibold">CD of the Week</h2>
        <Badge variant="secondary" className="ml-auto">
          <Calendar className="h-3 w-3 mr-1" />
          Week {weeklyAlbum.releaseWeek.split('-')[1]}
        </Badge>
      </div>

      <Card className="overflow-hidden hover:shadow-lg transition-shadow">
        <div className="flex flex-col md:flex-row">
          <div className="md:w-1/3">
            <div className="aspect-square relative group">
              {weeklyAlbum.coverArt ? (
                <img
                  src={weeklyAlbum.coverArt.startsWith('@assets/') 
                    ? weeklyAlbum.coverArt.replace('@assets/', '/attached_assets/')
                    : weeklyAlbum.coverArt}
                  alt={`${weeklyAlbum.title} album cover`}
                  className="w-full h-full object-cover transition-transform group-hover:scale-105"
                />
              ) : (
                <div className="w-full h-full bg-gradient-to-br from-radio-gold/20 to-radio-dark/20 flex items-center justify-center">
                  <Music className="h-16 w-16 text-radio-gold/50" />
                </div>
              )}
              {weeklyAlbum.purchaseUrl && (
                <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                  <Button 
                    onClick={handlePurchaseClick}
                    className="bg-radio-gold hover:bg-radio-gold/90 text-radio-dark"
                  >
                    <ShoppingCart className="h-4 w-4 mr-2" />
                    Buy Now
                  </Button>
                </div>
              )}
            </div>
          </div>

          <CardContent className="md:w-2/3 p-6">
            <div className="flex items-start justify-between mb-3">
              <h3 className="font-poppins text-2xl font-bold text-radio-dark">
                {weeklyAlbum.title}
              </h3>
              {weeklyAlbum.price && (
                <Badge variant="outline" className="text-radio-gold border-radio-gold">
                  {weeklyAlbum.price}
                </Badge>
              )}
            </div>

            <p className="text-gray-600 mb-4 leading-relaxed">
              {weeklyAlbum.description}
            </p>

            {weeklyAlbum.storyText && (
              <p className="text-sm text-gray-500 mb-4 italic">
                {weeklyAlbum.storyText}
              </p>
            )}

            <div className="flex items-center gap-4">
              {weeklyAlbum.purchaseUrl && (
                <Button 
                  onClick={handlePurchaseClick}
                  className="bg-radio-gold hover:bg-radio-gold/90 text-radio-dark"
                >
                  <ShoppingCart className="h-4 w-4 mr-2" />
                  Purchase Album
                </Button>
              )}
              <span className="text-xs text-gray-500">
                Curated by Golden Pearl Radio Dubai
              </span>
            </div>
          </CardContent>
        </div>
      </Card>
    </section>
  );
}

client/src/hooks/use-mobile.tsx.content:
import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

client/src/hooks/use-toast.ts.content:
import * as React from "react"

import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

