import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Calendar } from "@/components/ui/calendar";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Clock, Music, Mic, Calendar as CalendarIcon, Archive as ArchiveIcon, Info } from "lucide-react";

interface ProgramBlock {
  id: number;
  dayOfWeek: number;
  startHour: number;
  endHour: number;
  title: string;
  blockType: 'music' | 'content' | 'mixed';
  description?: string;
}

export default function Archive() {
  const [selectedDate, setSelectedDate] = useState<Date | undefined>(new Date());
  const [selectedHour, setSelectedHour] = useState<number | null>(null);
  const [viewMode, setViewMode] = useState<'schedule' | 'detailed'>('schedule');

  const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const hours = Array.from({ length: 24 }, (_, i) => i);

  // Fetch program blocks (lightweight data)
  const { data: programBlocks } = useQuery<ProgramBlock[]>({
    queryKey: ['/api/program-blocks'],
  });

  const getSelectedDayBlocks = () => {
    if (!selectedDate || !programBlocks) return [];
    const dayOfWeek = selectedDate.getDay();
    return programBlocks.filter(block => block.dayOfWeek === dayOfWeek);
  };

  const getBlockIcon = (blockType: string) => {
    switch (blockType) {
      case 'music':
        return <Music className="h-4 w-4 text-blue-500" />;
      case 'content':
        return <Mic className="h-4 w-4 text-green-500" />;
      case 'mixed':
        return <Clock className="h-4 w-4 text-purple-500" />;
      default:
        return <Clock className="h-4 w-4" />;
    }
  };

  const getBlockColor = (block: ProgramBlock) => {
    switch (block.blockType) {
      case 'music':
        return 'bg-blue-100 border-blue-300 text-blue-800';
      case 'content':
        return 'bg-green-100 border-green-300 text-green-800';
      case 'mixed':
        return 'bg-purple-100 border-purple-300 text-purple-800';
      default:
        return 'bg-gray-100 border-gray-300 text-gray-800';
    }
  };

  const renderDaySchedule = () => {
    const dayBlocks = getSelectedDayBlocks();

    return (
      <div className="space-y-2">
        {hours.map(hour => {
          const hourBlocks = dayBlocks.filter(block => 
            hour >= block.startHour && hour < block.endHour
          );

          return (
            <div 
              key={hour} 
              className={`border rounded-lg p-3 cursor-pointer transition-colors ${
                selectedHour === hour ? 'bg-blue-50 border-blue-300' : 'hover:bg-gray-50'
              }`}
              onClick={() => setSelectedHour(selectedHour === hour ? null : hour)}
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <div className="font-mono text-sm text-gray-600 w-16">
                    {String(hour).padStart(2, '0')}:00
                  </div>
                  {hourBlocks.length > 0 ? (
                    <div className="flex items-center space-x-2">
                      {getBlockIcon(hourBlocks[0].blockType)}
                      <span className="font-medium">{hourBlocks[0].title}</span>
                      <Badge variant="outline" className="text-xs">
                        {hourBlocks[0].blockType}
                      </Badge>
                    </div>
                  ) : (
                    <span className="text-gray-400 italic">No scheduled programming</span>
                  )}
                </div>
                {viewMode === 'detailed' && (
                  <Button size="sm" variant="ghost">
                    View Details
                  </Button>
                )}
              </div>

              {selectedHour === hour && hourBlocks.length > 0 && (
                <div className="mt-3 pt-3 border-t border-gray-200">
                  <div className="text-sm text-gray-600 space-y-2">
                    <p><strong>Program:</strong> {hourBlocks[0].title}</p>
                    <p><strong>Type:</strong> {hourBlocks[0].blockType}</p>
                    <p><strong>Description:</strong> {hourBlocks[0].description || 'Standard programming block'}</p>
                    {viewMode === 'detailed' && (
                      <div className="bg-yellow-50 p-3 rounded border-l-4 border-yellow-400 mt-3">
                        <div className="flex items-start space-x-2">
                          <Info className="h-4 w-4 text-yellow-600 mt-0.5" />
                          <div className="text-sm">
                            <p className="font-medium text-yellow-800">Archive Service Notice</p>
                            <p className="text-yellow-700">
                              Detailed track listings and minute-by-minute archives are available as a premium service. 
                              Contact us for access to complete broadcast history and track identification.
                            </p>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center space-x-3 mb-6">
          <ArchiveIcon className="h-8 w-8 text-radio-orange" />
          <h1 className="text-3xl font-bold text-gray-900">Program Archive</h1>
        </div>

        <Tabs defaultValue="weekly" className="space-y-6">
          <TabsList>
            <TabsTrigger value="weekly">Weekly Schedule</TabsTrigger>
            <TabsTrigger value="calendar">Calendar View</TabsTrigger>
          </TabsList>

          <TabsContent value="weekly" className="space-y-6">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Date Selection */}
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center space-x-2">
                    <CalendarIcon className="h-5 w-5" />
                    <span>Select Date</span>
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <Calendar
                    mode="single"
                    selected={selectedDate}
                    onSelect={setSelectedDate}
                    className="rounded-md border"
                  />
                  <div className="mt-4 space-y-2">
                    <div className="flex items-center justify-between">
                      <span className="text-sm text-gray-600">Archive Detail Level:</span>
                    </div>
                    <div className="flex space-x-2">
                      <Button
                        size="sm"
                        variant={viewMode === 'schedule' ? 'default' : 'outline'}
                        onClick={() => setViewMode('schedule')}
                      >
                        Schedule Only
                      </Button>
                      <Button
                        size="sm"
                        variant={viewMode === 'detailed' ? 'default' : 'outline'}
                        onClick={() => setViewMode('detailed')}
                      >
                        Detailed View
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>

              {/* Program Schedule */}
              <div className="lg:col-span-2">
                <Card>
                  <CardHeader>
                    <CardTitle>
                      {selectedDate ? (
                        `Program Schedule - ${selectedDate.toLocaleDateString('en-US', { 
                          weekday: 'long', 
                          year: 'numeric', 
                          month: 'long', 
                          day: 'numeric' 
                        })}`
                      ) : (
                        'Select a date to view schedule'
                      )}
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    {selectedDate ? (
                      <div className="max-h-96 overflow-y-auto">
                        {renderDaySchedule()}
                      </div>
                    ) : (
                      <div className="text-center py-8 text-gray-500">
                        <CalendarIcon className="h-12 w-12 mx-auto mb-4 text-gray-300" />
                        <p>Please select a date to view the program schedule</p>
                      </div>
                    )}
                  </CardContent>
                </Card>
              </div>
            </div>
          </TabsContent>

          <TabsContent value="calendar" className="space-y-6">
            <Card>
              <CardHeader>
                <CardTitle>Program Calendar Overview</CardTitle>
                <p className="text-sm text-gray-600">
                  View programming patterns across the week
                </p>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-7 gap-2 mb-4">
                  {days.map((day, index) => (
                    <div key={day} className="text-center font-medium text-sm text-gray-700 p-2">
                      {day}
                    </div>
                  ))}
                </div>

                <div className="grid grid-cols-7 gap-2">
                  {days.map((day, dayIndex) => {
                    const dayBlocks = programBlocks?.filter(block => block.dayOfWeek === dayIndex) || [];

                    return (
                      <div key={day} className="space-y-1">
                        {Array.from({ length: 8 }, (_, i) => i * 3).map(hour => {
                          const hourBlocks = dayBlocks.filter(block => 
                            hour >= block.startHour && hour < block.endHour
                          );

                          return (
                            <div
                              key={`${dayIndex}-${hour}`}
                              className={`h-8 rounded text-xs flex items-center justify-center cursor-pointer ${
                                hourBlocks.length > 0 
                                  ? getBlockColor(hourBlocks[0])
                                  : 'bg-gray-100 text-gray-500'
                              }`}
                              title={hourBlocks.length > 0 ? hourBlocks[0].title : 'No programming'}
                            >
                              {String(hour).padStart(2, '0')}:00
                            </div>
                          );
                        })}
                      </div>
                    );
                  })}
                </div>

                <div className="mt-6 flex flex-wrap gap-4 text-sm">
                  <div className="flex items-center space-x-2">
                    <div className="w-4 h-4 bg-blue-100 border border-blue-300 rounded"></div>
                    <span>Music Programming</span>
                  </div>
                  <div className="flex items-center space-x-2">
                    <div className="w-4 h-4 bg-green-100 border border-green-300 rounded"></div>
                    <span>Talk/Content Shows</span>
                  </div>
                  <div className="flex items-center space-x-2">
                    <div className="w-4 h-4 bg-purple-100 border border-purple-300 rounded"></div>
                    <span>Mixed Programming</span>
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>

        {/* Cost Information */}
        <Card className="mt-6 bg-orange-50 border-orange-200">
          <CardContent className="pt-6">
            <div className="flex items-start space-x-3">
              <Info className="h-5 w-5 text-orange-600 mt-0.5" />
              <div>
                <h3 className="font-medium text-orange-900">Archive Services</h3>
                <p className="text-sm text-orange-800 mt-1">
                  Current archive shows program schedules and block types. For detailed track listings, 
                  timestamps, and complete broadcast history, premium archive services are available. 
                  Contact Golden Pearl Radio for enterprise archive access.
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

client/src/pages/Podcasts.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Play, Clock, Calendar, User, Headphones, Mic2 } from "lucide-react";

interface Show {
  id: number;
  title: string;
  description: string;
  hostName: string | null;
  scheduleTime: string | null;
  coverImage: string | null;
  isFeatured: boolean;
  createdAt: Date;
}

interface Episode {
  id: number;
  title: string;
  description: string;
  duration: number;
  audioUrl: string;
  publishDate: Date;
  showId: number;
  createdAt: Date;
}

export default function Podcasts() {
  const { data: shows, isLoading: showsLoading } = useQuery<Show[]>({
    queryKey: ['/api/shows'],
  });

  const { data: featuredShows } = useQuery<Show[]>({
    queryKey: ['/api/shows/featured'],
  });

  const { data: recentEpisodes } = useQuery<Episode[]>({
    queryKey: ['/api/episodes/recent'],
  });

  const formatDuration = (seconds: number) => {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes}:${remainingSeconds.toString().padStart(2, '0')}`;
  };

  const getShowsByCategory = () => {
    if (!shows) return {};

    const categories: { [key: string]: Show[] } = {
      'Talk Radio': [],
      'Music Shows': [],
      'News & Current Affairs': [],
      'Cultural Programs': [],
      'Entertainment': []
    };

    shows.forEach(show => {
      // Simple categorization based on show title and description
      const title = show.title.toLowerCase();
      const description = show.description.toLowerCase();

      if (title.includes('talk') || description.includes('discussion') || description.includes('interview')) {
        categories['Talk Radio'].push(show);
      } else if (title.includes('music') || description.includes('music') || description.includes('song')) {
        categories['Music Shows'].push(show);
      } else if (title.includes('news') || description.includes('news') || description.includes('current')) {
        categories['News & Current Affairs'].push(show);
      } else if (title.includes('culture') || description.includes('cultural') || description.includes('heritage')) {
        categories['Cultural Programs'].push(show);
      } else {
        categories['Entertainment'].push(show);
      }
    });

    return categories;
  };

  const showCategories = getShowsByCategory();

  if (showsLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <Headphones className="h-12 w-12 mx-auto mb-4 text-radio-orange animate-pulse" />
          <p className="text-gray-600">Loading podcast content...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="container mx-auto px-4 py-8">
        {/* Header */}
        <div className="text-center mb-8">
          <div className="flex items-center justify-center space-x-3 mb-4">
            <Headphones className="h-8 w-8 text-radio-orange" />
            <h1 className="text-4xl font-bold text-gray-900">Golden Pearl Podcasts</h1>
          </div>
          <p className="text-lg text-gray-600 max-w-2xl mx-auto">
            Discover our diverse collection of talk radio shows, cultural programs, and on-demand content
          </p>
        </div>

        <Tabs defaultValue="featured" className="space-y-8">
          <TabsList className="grid grid-cols-3 w-full max-w-md mx-auto">
            <TabsTrigger value="featured">Featured</TabsTrigger>
            <TabsTrigger value="categories">Categories</TabsTrigger>
            <TabsTrigger value="recent">Recent</TabsTrigger>
          </TabsList>

          <TabsContent value="featured" className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {featuredShows?.map(show => (
                <Card key={show.id} className="hover:shadow-lg transition-shadow">
                  <CardHeader className="pb-3">
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <CardTitle className="text-lg mb-1">{show.title}</CardTitle>
                        {show.hostName && (
                          <div className="flex items-center text-sm text-gray-600 mb-2">
                            <User className="h-3 w-3 mr-1" />
                            {show.hostName}
                          </div>
                        )}
                      </div>
                      <Badge className="bg-radio-orange text-white">Featured</Badge>
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-3">
                    <p className="text-sm text-gray-600 line-clamp-3">{show.description}</p>
                    {show.scheduleTime && (
                      <div className="flex items-center text-xs text-gray-500">
                        <Clock className="h-3 w-3 mr-1" />
                        {show.scheduleTime}
                      </div>
                    )}
                    <Button className="w-full" size="sm">
                      <Play className="h-3 w-3 mr-2" />
                      Listen Now
                    </Button>
                  </CardContent>
                </Card>
              ))}
            </div>
          </TabsContent>

          <TabsContent value="categories" className="space-y-8">
            {Object.entries(showCategories).map(([category, categoryShows]) => (
              categoryShows.length > 0 && (
                <div key={category}>
                  <div className="flex items-center space-x-3 mb-4">
                    <Mic2 className="h-5 w-5 text-radio-orange" />
                    <h2 className="text-xl font-semibold text-gray-900">{category}</h2>
                    <Badge variant="outline">{categoryShows.length} shows</Badge>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                    {categoryShows.map(show => (
                      <Card key={show.id} className="hover:shadow-md transition-shadow">
                        <CardContent className="p-4">
                          <h3 className="font-medium mb-2 line-clamp-2">{show.title}</h3>
                          {show.hostName && (
                            <div className="flex items-center text-xs text-gray-600 mb-2">
                              <User className="h-3 w-3 mr-1" />
                              {show.hostName}
                            </div>
                          )}
                          <p className="text-xs text-gray-500 line-clamp-2 mb-3">{show.description}</p>
                          <Button size="sm" variant="outline" className="w-full">
                            <Play className="h-3 w-3 mr-1" />
                            Listen
                          </Button>
                        </CardContent>
                      </Card>
                    ))}
                  </div>
                </div>
              )
            ))}
          </TabsContent>

          <TabsContent value="recent" className="space-y-6">
            <div className="space-y-4">
              {recentEpisodes?.map(episode => (
                <Card key={episode.id} className="hover:shadow-md transition-shadow">
                  <CardContent className="p-4">
                    <div className="flex items-start justify-between">
                      <div className="flex-1 min-w-0">
                        <h3 className="font-medium mb-1 line-clamp-1">{episode.title}</h3>
                        <p className="text-sm text-gray-600 line-clamp-2 mb-2">{episode.description}</p>
                        <div className="flex items-center space-x-4 text-xs text-gray-500">
                          <div className="flex items-center">
                            <Calendar className="h-3 w-3 mr-1" />
                            {new Date(episode.publishDate).toLocaleDateString()}
                          </div>
                          <div className="flex items-center">
                            <Clock className="h-3 w-3 mr-1" />
                            {formatDuration(episode.duration)}
                          </div>
                        </div>
                      </div>
                      <Button size="sm" className="ml-4">
                        <Play className="h-3 w-3 mr-1" />
                        Play
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </TabsContent>
        </Tabs>

        {/* Info Section */}
        <Card className="mt-8 bg-gradient-to-r from-radio-orange/10 to-radio-gold/10 border-radio-orange/20">
          <CardContent className="pt-6">
            <div className="text-center">
              <h3 className="text-lg font-semibold text-gray-900 mb-2">
                Experience Dubai's Premier Talk Radio
              </h3>
              <p className="text-gray-700 max-w-2xl mx-auto">
                From morning talk shows to evening cultural programs, Golden Pearl Radio delivers 
                diverse content that reflects Dubai's multicultural spirit. Our podcast collection 
                features the best of our live programming, available on-demand.
              </p>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

client/src/pages/Shop.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { ShoppingBag, Star, MapPin, Calendar, ExternalLink, Radio } from "lucide-react";

interface Product {
  id: number;
  title: string;
  description: string;
  price: string;
  affiliateUrl: string;
  category: string;
  coverImage: string | null;
  tags: unknown;
  impressions: number;
  clicks: number;
  createdAt: Date;
}

interface Event {
  id: number;
  title: string;
  eventDate: string;
  venue?: string;
  category?: string;
  isPromoted: boolean;
}

export default function Shop() {
  const { data: products, isLoading: productsLoading } = useQuery<Product[]>({
    queryKey: ['/api/products'],
  });

  const { data: events } = useQuery<Event[]>({
    queryKey: ['/api/events'],
  });

  const featuredProducts = products?.filter(product => 
    product.tags && Array.isArray(product.tags) && 
    (product.tags as string[]).includes('featured')
  ) || [];

  const promotedEvents = events?.filter(event => event.isPromoted) || [];

  const productsByCategory = products?.reduce((acc, product) => {
    if (!acc[product.category]) {
      acc[product.category] = [];
    }
    acc[product.category].push(product);
    return acc;
  }, {} as Record<string, Product[]>) || {};

  const handleProductClick = async (product: Product) => {
    // Track click
    try {
      await fetch(`/api/products/${product.id}/click`, { method: 'POST' });
    } catch (error) {
      console.error('Failed to track click:', error);
    }

    // Open affiliate link
    window.open(product.affiliateUrl, '_blank');
  };

  if (productsLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <ShoppingBag className="h-12 w-12 mx-auto mb-4 text-radio-orange animate-pulse" />
          <p className="text-gray-600">Loading shop content...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="container mx-auto px-4 py-8">
        {/* Header */}
        <div className="text-center mb-8">
          <div className="flex items-center justify-center space-x-3 mb-4">
            <ShoppingBag className="h-8 w-8 text-radio-orange" />
            <h1 className="text-4xl font-bold text-gray-900">Golden Pearl Shop</h1>
          </div>
          <p className="text-lg text-gray-600 max-w-2xl mx-auto">
            Discover exclusive products and events curated by Golden Pearl Radio Dubai
          </p>
        </div>

        <Tabs defaultValue="featured" className="space-y-8">
          <TabsList className="grid grid-cols-4 w-full max-w-lg mx-auto">
            <TabsTrigger value="featured">Featured</TabsTrigger>
            <TabsTrigger value="events">Events</TabsTrigger>
            <TabsTrigger value="categories">Categories</TabsTrigger>
            <TabsTrigger value="all">All Products</TabsTrigger>
          </TabsList>

          <TabsContent value="featured" className="space-y-6">
            {featuredProducts.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {featuredProducts.map(product => (
                  <Card key={product.id} className="hover:shadow-lg transition-shadow cursor-pointer" onClick={() => handleProductClick(product)}>
                    <CardHeader className="pb-3">
                      <div className="flex items-start justify-between">
                        <div className="flex-1">
                          <CardTitle className="text-lg mb-1">{product.title}</CardTitle>
                          <div className="flex items-center space-x-2 mb-2">
                            <Badge className="bg-radio-orange text-white">Featured</Badge>
                            <Badge variant="outline">{product.category}</Badge>
                          </div>
                        </div>
                        <div className="text-right">
                          <div className="font-bold text-lg text-radio-orange">{product.price}</div>
                        </div>
                      </div>
                    </CardHeader>
                    <CardContent className="space-y-3">
                      <p className="text-sm text-gray-600 line-clamp-3">{product.description}</p>
                      <div className="flex items-center justify-between text-xs text-gray-500">
                        <span>{product.impressions} views</span>
                        <span>{product.clicks} clicks</span>
                      </div>
                      <Button className="w-full" size="sm">
                        <ExternalLink className="h-3 w-3 mr-2" />
                        Shop Now
                      </Button>
                    </CardContent>
                  </Card>
                ))}
              </div>
            ) : (
              <div className="text-center py-12">
                <Star className="h-12 w-12 mx-auto mb-4 text-gray-300" />
                <p className="text-gray-500">No featured products available</p>
              </div>
            )}
          </TabsContent>

          <TabsContent value="events" className="space-y-6">
            {promotedEvents.length > 0 ? (
              <div className="space-y-4">
                <div className="bg-radio-orange/10 p-4 rounded-lg border border-radio-orange/20">
                  <div className="flex items-center space-x-2 mb-2">
                    <Radio className="h-4 w-4 text-radio-orange" />
                    <span className="font-medium text-radio-orange">Promoted by Golden Pearl Radio</span>
                  </div>
                  <p className="text-sm text-gray-700">
                    Events featured on our shows come with exclusive listener benefits and promotional coverage.
                  </p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {promotedEvents.map(event => (
                    <Card key={event.id} className="hover:shadow-lg transition-shadow">
                      <CardHeader>
                        <div className="flex items-start justify-between">
                          <div className="flex-1">
                            <CardTitle className="text-lg mb-2">{event.title}</CardTitle>
                            <div className="space-y-1 text-sm text-gray-600">
                              <div className="flex items-center">
                                <Calendar className="h-3 w-3 mr-1" />
                                {new Date(event.eventDate).toLocaleDateString('en-US', {
                                  weekday: 'long',
                                  year: 'numeric',
                                  month: 'long',
                                  day: 'numeric'
                                })}
                              </div>
                              {event.venue && (
                                <div className="flex items-center">
                                  <MapPin className="h-3 w-3 mr-1" />
                                  {event.venue}
                                </div>
                              )}
                            </div>
                          </div>
                          <Badge className="bg-green-600 text-white">Promoted</Badge>
                        </div>
                      </CardHeader>
                      <CardContent>
                        <div className="space-y-3">
                          <div className="bg-yellow-50 p-3 rounded border-l-4 border-yellow-400">
                            <div className="text-sm">
                              <p className="font-medium text-yellow-800 mb-1">Golden Pearl Radio Exclusive</p>
                              <p className="text-yellow-700">
                                Mention "Golden Pearl Radio" for special listener benefits
                              </p>
                            </div>
                          </div>
                          <Button className="w-full">
                            <ExternalLink className="h-3 w-3 mr-2" />
                            Get Tickets
                          </Button>
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </div>
            ) : (
              <div className="text-center py-12">
                <Calendar className="h-12 w-12 mx-auto mb-4 text-gray-300" />
                <p className="text-gray-500">No promoted events available</p>
              </div>
            )}
          </TabsContent>

          <TabsContent value="categories" className="space-y-8">
            {Object.entries(productsByCategory).map(([category, categoryProducts]) => (
              <div key={category}>
                <div className="flex items-center space-x-3 mb-4">
                  <h2 className="text-xl font-semibold text-gray-900 capitalize">{category}</h2>
                  <Badge variant="outline">{categoryProducts.length} products</Badge>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                  {categoryProducts.map(product => (
                    <Card key={product.id} className="hover:shadow-md transition-shadow cursor-pointer" onClick={() => handleProductClick(product)}>
                      <CardContent className="p-4">
                        <h3 className="font-medium mb-2 line-clamp-2">{product.title}</h3>
                        <p className="text-xs text-gray-500 line-clamp-2 mb-3">{product.description}</p>
                        <div className="flex items-center justify-between mb-3">
                          <span className="font-bold text-radio-orange">{product.price}</span>
                          <Badge variant="outline" className="text-xs">{product.category}</Badge>
                        </div>
                        <Button size="sm" variant="outline" className="w-full">
                          <ExternalLink className="h-3 w-3 mr-1" />
                          View
                        </Button>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </div>
            ))}
          </TabsContent>

          <TabsContent value="all" className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {products?.map(product => (
                <Card key={product.id} className="hover:shadow-lg transition-shadow cursor-pointer" onClick={() => handleProductClick(product)}>
                  <CardHeader className="pb-3">
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <CardTitle className="text-lg mb-1">{product.title}</CardTitle>
                        <Badge variant="outline">{product.category}</Badge>
                      </div>
                      <div className="text-right">
                        <div className="font-bold text-lg text-radio-orange">{product.price}</div>
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-3">
                    <p className="text-sm text-gray-600 line-clamp-3">{product.description}</p>
                    <div className="flex items-center justify-between text-xs text-gray-500">
                      <span>{product.impressions} views</span>
                      <span>{product.clicks} clicks</span>
                    </div>
                    <Button className="w-full" size="sm">
                      <ExternalLink className="h-3 w-3 mr-2" />
                      Shop Now
                    </Button>
                  </CardContent>
                </Card>
              ))}
            </div>
          </TabsContent>
        </Tabs>

        {/* Radio Partnership Info */}
        <Card className="mt-8 bg-gradient-to-r from-radio-orange/10 to-radio-gold/10 border-radio-orange/20">
          <CardContent className="pt-6">
            <div className="text-center">
              <h3 className="text-lg font-semibold text-gray-900 mb-2">
                Golden Pearl Radio Partnership Program
              </h3>
              <p className="text-gray-700 max-w-2xl mx-auto">
                All products and events in our shop are carefully curated and promoted through our radio programming. 
                When you purchase through Golden Pearl Shop, you're supporting quality content and discovering 
                Dubai's finest offerings.
              </p>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

