import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Track, Show, Product } from "@shared/schema";
import { Button } from "@/components/ui/button";
import { ProgramCard } from "@/components/ui/program-card";
import { OfferCard } from "@/components/ui/offer-card";
import { useAudioController } from "@/components/radio/AudioController";
import { TabView } from "@/components/ui/tab-view";
import CDOfTheWeek from "@/components/CDOfTheWeek";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Card, CardContent } from "@/components/ui/card";
import { Headphones, ExternalLink, Music } from "lucide-react";

interface NowPlayingResponse {
  type: 'track' | 'show';
  data: Track | Show;
  nextTracks: Track[];
}

export default function Home() {
  const { setTrackUrl } = useAudioController();
  const [showWhatsPlaying, setShowWhatsPlaying] = useState(false);

  // Fetch current playing content
  const { data: nowPlaying, isLoading: isNowPlayingLoading } = useQuery<NowPlayingResponse>({
    queryKey: ['/api/now-playing'],
    refetchInterval: 30000, // Refresh every 30 seconds
  });

  // Fetch recent tracks history - fallback to regular tracks if recent fails
  const { data: recentTracks } = useQuery<Track[]>({
    queryKey: ['/api/tracks'],
    select: (data) => data.slice(-3).reverse(), // Last 3 tracks in reverse order
  });

  // Fetch featured shows
  const { data: featuredShows, isLoading: isShowsLoading } = useQuery<Show[]>({
    queryKey: ['/api/shows/featured'],
  });

  // Fetch recommended products
  const { data: products, isLoading: isProductsLoading } = useQuery<Product[]>({
    queryKey: ['/api/products'],
    select: (data) => data.slice(0, 3), // Limit to 3 products
  });

  const handlePlayShow = (show: Show) => {
    console.log(`Playing ${show.title}`);

    if (nowPlaying?.nextTracks?.length && nowPlaying.nextTracks.length > 0) {
      setTrackUrl(nowPlaying.nextTracks[0].url);
    }
  };

  const generateAppleMusicUrl = (track: Track) => {
    // Generate Apple Music search URL for the track
    const query = encodeURIComponent(`${track.title} ${track.artist}`);
    return `https://music.apple.com/search?term=${query}`;
  };

  const handleTrackClick = (track: Track) => {
    window.open(generateAppleMusicUrl(track), '_blank');
  };

  const currentTrack = nowPlaying?.type === 'track' ? nowPlaying.data as Track : null;
  const allRecentTracks = [
    ...(currentTrack ? [currentTrack] : []),
    ...(recentTracks || [])
  ].slice(0, 4); // Current + last 3

  return (
    <div>
      {/* What's Playing Button - Fixed Position */}
      <div className="fixed top-20 right-4 z-50">
        <Dialog open={showWhatsPlaying} onOpenChange={setShowWhatsPlaying}>
          <DialogTrigger asChild>
            <Button
              size="lg"
              className="bg-radio-orange hover:bg-radio-orange/90 text-white rounded-full shadow-lg"
            >
              <Headphones className="h-5 w-5 mr-2" />
              🎧 What's Playing?
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle className="flex items-center space-x-2">
                <Music className="h-5 w-5" />
                <span>What's Playing on Golden Pearl Radio</span>
              </DialogTitle>
            </DialogHeader>

            <div className="space-y-4">
              {/* Currently Playing */}
              {currentTrack && (
                <div className="bg-radio-orange/10 p-4 rounded-lg border-l-4 border-radio-orange">
                  <div className="flex items-center space-x-2 mb-2">
                    <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
                    <span className="text-sm font-medium text-radio-orange">NOW PLAYING</span>
                  </div>
                  <div 
                    className="cursor-pointer hover:bg-white/50 p-2 rounded transition-colors"
                    onClick={() => handleTrackClick(currentTrack)}
                  >
                    <div className="flex items-center space-x-3">
                      <div className="w-12 h-12 bg-gray-200 rounded-lg flex items-center justify-center">
                        <Music className="h-6 w-6 text-gray-400" />
                      </div>
                      <div className="flex-1">
                        <h4 className="font-medium text-gray-900">{currentTrack.title}</h4>
                        <p className="text-sm text-gray-600">{currentTrack.artist}</p>
                      </div>
                      <ExternalLink className="h-4 w-4 text-gray-400" />
                    </div>
                  </div>
                </div>
              )}

              {/* Recently Played */}
              <div>
                <h4 className="font-medium text-gray-900 mb-3">Recently Played</h4>
                <div className="space-y-2">
                  {recentTracks?.slice(0, 3).map((track, index) => (
                    <div 
                      key={track.id}
                      className="cursor-pointer hover:bg-gray-50 p-2 rounded transition-colors"
                      onClick={() => handleTrackClick(track)}
                    >
                      <div className="flex items-center space-x-3">
                        <div className="w-10 h-10 bg-gray-200 rounded-lg flex items-center justify-center">
                          <Music className="h-4 w-4 text-gray-400" />
                        </div>
                        <div className="flex-1">
                          <h5 className="text-sm font-medium text-gray-900">{track.title}</h5>
                          <p className="text-xs text-gray-600">{track.artist}</p>
                        </div>
                        <ExternalLink className="h-3 w-3 text-gray-400" />
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="text-xs text-gray-500 text-center pt-2 border-t">
                Click any song to find it on Apple Music
              </div>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      <div className="container mx-auto px-4 py-8">
        {/* Featured Shows Section */}
        <h2 className="font-poppins text-xl font-semibold mb-4">Featured Shows</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
          {isShowsLoading ? (
            Array(3).fill(0).map((_, i) => (
              <div key={i} className="bg-white rounded-lg shadow-md overflow-hidden">
                <div className="h-40 bg-gray-200 animate-pulse"></div>
                <div className="p-4">
                  <div className="h-6 w-2/3 bg-gray-200 animate-pulse mb-2"></div>
                  <div className="h-4 bg-gray-200 animate-pulse mb-3"></div>
                  <div className="flex justify-between items-center">
                    <div className="h-4 w-1/3 bg-gray-200 animate-pulse"></div>
                    <div className="h-6 w-6 rounded-full bg-gray-200 animate-pulse"></div>
                  </div>
                </div>
              </div>
            ))
          ) : (
            featuredShows?.map((show) => (
              <ProgramCard 
                key={show.id} 
                show={show} 
                onClick={() => handlePlayShow(show)}
              />
            ))
          )}
        </div>

        {/* Dubai Guide Preview */}
        <div className="bg-radio-orange text-radio-cream rounded-xl shadow-md p-6 mb-8">
          <div className="flex flex-col md:flex-row items-center">
            <div className="md:w-2/3 mb-6 md:mb-0 md:pr-6">
              <h2 className="font-poppins text-xl font-semibold mb-2">Discover Dubai With Us</h2>
              <p className="mb-4">
                Get exclusive recommendations for dining, entertainment, shopping, and cultural experiences tailored to your interests.
              </p>
              <Button 
                className="bg-radio-cream text-radio-orange hover:bg-white hover:text-radio-orange rounded-full font-medium"
                onClick={() => window.location.href = '/guide'}
              >
                Explore Dubai Guide
              </Button>
            </div>
            <div className="md:w-1/3">
              <img 
                src="https://images.unsplash.com/photo-1582672171646-3c0616e1185b?ixlib=rb-1.2.1&auto=format&fit=crop&w=500&q=80" 
                alt="Dubai landmark"
                className="w-full h-40 object-cover rounded-lg"
              />
            </div>
          </div>
        </div>

        {/* Recommended Products */}
        <h2 className="font-poppins text-xl font-semibold mb-4">Recommended For You</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          {isProductsLoading ? (
            Array(3).fill(0).map((_, i) => (
              <div key={i} className="bg-white rounded-lg shadow-md overflow-hidden">
                <div className="p-4">
                  <div className="flex items-center justify-between mb-3">
                    <div className="h-6 w-2/3 bg-gray-200 animate-pulse"></div>
                    <div className="h-4 w-10 bg-gray-200 animate-pulse"></div>
                  </div>
                  <div className="h-4 bg-gray-200 animate-pulse mb-3"></div>
                  <div className="flex justify-between items-center">
                    <div className="h-5 w-20 bg-gray-200 animate-pulse"></div>
                    <div className="h-8 w-24 bg-gray-200 animate-pulse"></div>
                  </div>
                </div>
              </div>
            ))
          ) : (
            products?.map((product) => (
              <OfferCard key={product.id} product={product} />
