client/src/pages/visit-dubai.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ExternalLink, MapPin, Star, Clock, DollarSign } from "lucide-react";
import { queryClient } from "@/lib/queryClient";
import type { DubaiHotspot } from "@shared/schema";

export default function VisitDubaiPage() {
  const [selectedHotspot, setSelectedHotspot] = useState<DubaiHotspot | null>(null);
  const [hoveredHotspot, setHoveredHotspot] = useState<number | null>(null);

  // Fetch Dubai hotspots
  const { data: hotspots = [], isLoading } = useQuery({
    queryKey: ['/api/dubai-hotspots']
  });

  // Track hotspot click
  const trackClick = useMutation({
    mutationFn: async (hotspotId: number) => {
      const response = await fetch(`/api/dubai-hotspots/${hotspotId}/click`, {
        method: 'POST'
      });
      if (!response.ok) throw new Error('Failed to track click');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/dubai-hotspots'] });
    }
  });

  const handleHotspotClick = (hotspot: DubaiHotspot) => {
    setSelectedHotspot(hotspot);
    trackClick.mutate(hotspot.id);
  };

  const handleBooking = (hotspot: DubaiHotspot) => {
    if (hotspot.ticketUrl) {
      const urlWithAffiliate = `${hotspot.ticketUrl}?ref=golden-pearl-radio&promo=${hotspot.affiliateCode || 'GOLDENPEARL10'}`;
      window.open(urlWithAffiliate, '_blank');
    }
  };

  const getCategoryColor = (category: string) => {
    const colors = {
      attraction: "#3B82F6",
      restaurant: "#EF4444", 
      shopping: "#10B981",
      entertainment: "#8B5CF6"
    };
    return colors[category as keyof typeof colors] || "#6B7280";
  };

  const getCategoryIcon = (category: string) => {
    switch (category) {
      case 'attraction': return '🏛️';
      case 'restaurant': return '🍽️';
      case 'shopping': return '🛍️';
      case 'entertainment': return '🎭';
      default: return '📍';
    }
  };

  if (isLoading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-amber-50">
      {/* Header */}
      <div className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 py-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold text-gray-900">Visit Dubai</h1>
              <p className="text-gray-600 mt-1">Discover the best of Dubai with Golden Pearl Radio</p>
            </div>
            <Badge variant="outline" className="text-lg px-3 py-1">
              {hotspots.length} Featured Locations
            </Badge>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Interactive Map */}
          <div className="lg:col-span-2">
            <Card className="h-[600px]">
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <MapPin className="h-5 w-5" />
                  Dubai Interactive Map
                </CardTitle>
                <CardDescription>
                  Click on hotspots to explore attractions, restaurants, and entertainment
                </CardDescription>
              </CardHeader>
              <CardContent className="h-[500px] relative">
                {/* SVG Dubai Map */}
                <svg 
                  viewBox="0 0 800 600" 
                  className="w-full h-full border rounded-lg bg-gradient-to-br from-blue-100 to-amber-100"
                >
                  {/* Dubai Coastline */}
                  <path
                    d="M50 150 Q200 100 400 120 Q600 140 750 160 L750 180 Q600 160 400 140 Q200 120 50 170 Z"
                    fill="#3B82F6"
                    opacity="0.3"
                  />

                  {/* Palm Jumeirah */}
                  <circle cx="250" cy="180" r="30" fill="#10B981" opacity="0.4" />
                  <text x="250" y="220" textAnchor="middle" className="text-xs fill-gray-600">Palm Jumeirah</text>

                  {/* Dubai Marina */}
                  <rect x="200" y="200" width="40" height="60" fill="#8B5CF6" opacity="0.4" />
                  <text x="220" y="280" textAnchor="middle" className="text-xs fill-gray-600">Marina</text>

                  {/* Downtown Dubai */}
                  <rect x="400" y="300" width="50" height="80" fill="#EF4444" opacity="0.4" />
                  <text x="425" y="400" textAnchor="middle" className="text-xs fill-gray-600">Downtown</text>

                  {/* Dubai Mall Area */}
                  <rect x="380" y="320" width="30" height="40" fill="#F59E0B" opacity="0.4" />

                  {/* Burj Al Arab */}
                  <polygon points="320,250 340,280 300,280" fill="#FFD700" opacity="0.6" />
                  <text x="320" y="300" textAnchor="middle" className="text-xs fill-gray-600">Burj Al Arab</text>

                  {/* Hotspots */}
                  {hotspots.map((hotspot: DubaiHotspot) => (
                    <g key={hotspot.id}>
                      <circle
                        cx={hotspot.xPosition}
                        cy={hotspot.yPosition}
                        r={hoveredHotspot === hotspot.id ? "12" : "8"}
                        fill={getCategoryColor(hotspot.category)}
                        className="cursor-pointer transition-all duration-200 hover:opacity-80"
                        onMouseEnter={() => setHoveredHotspot(hotspot.id)}
                        onMouseLeave={() => setHoveredHotspot(null)}
                        onClick={() => handleHotspotClick(hotspot)}
                      />
                      <text
                        x={hotspot.xPosition}
                        y={hotspot.yPosition + 4}
                        textAnchor="middle"
                        className="text-xs fill-white font-medium pointer-events-none"
                      >
                        {getCategoryIcon(hotspot.category)}
                      </text>
                      {hoveredHotspot === hotspot.id && (
                        <text
                          x={hotspot.xPosition}
                          y={hotspot.yPosition - 15}
                          textAnchor="middle"
                          className="text-sm fill-gray-800 font-medium pointer-events-none"
                        >
                          {hotspot.name}
                        </text>
                      )}
                    </g>
                  ))}
                </svg>
              </CardContent>
            </Card>
          </div>

          {/* Categories & Featured */}
          <div className="space-y-6">
            {/* Category Filter */}
            <Card>
              <CardHeader>
                <CardTitle>Categories</CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                {['attraction', 'restaurant', 'shopping', 'entertainment'].map(category => {
                  const count = hotspots.filter((h: DubaiHotspot) => h.category === category).length;
                  return (
                    <div key={category} className="flex items-center justify-between">
                      <div className="flex items-center gap-3">
                        <div 
                          className="w-4 h-4 rounded-full"
                          style={{ backgroundColor: getCategoryColor(category) }}
                        />
                        <span className="capitalize font-medium">{category}</span>
                      </div>
                      <Badge variant="secondary">{count}</Badge>
                    </div>
                  );
                })}
              </CardContent>
            </Card>

            {/* Featured Locations */}
            <Card>
              <CardHeader>
                <CardTitle>Featured Locations</CardTitle>
                <CardDescription>Most popular destinations</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                {hotspots
                  .filter((h: DubaiHotspot) => h.clickCount > 0)
                  .sort((a: DubaiHotspot, b: DubaiHotspot) => b.clickCount - a.clickCount)
                  .slice(0, 5)
                  .map((hotspot: DubaiHotspot) => (
                    <div 
                      key={hotspot.id}
                      className="flex items-center gap-3 p-3 border rounded-lg hover:bg-gray-50 cursor-pointer"
                      onClick={() => handleHotspotClick(hotspot)}
                    >
                      <div 
                        className="w-3 h-3 rounded-full"
                        style={{ backgroundColor: getCategoryColor(hotspot.category) }}
                      />
                      <div className="flex-1">
                        <div className="font-medium text-sm">{hotspot.name}</div>
                        <div className="text-xs text-gray-500 capitalize">{hotspot.category}</div>
                      </div>
                      <Badge variant="outline" className="text-xs">
                        {hotspot.clickCount} views
                      </Badge>
                    </div>
                  ))}
              </CardContent>
            </Card>
          </div>
        </div>
      </div>

      {/* Hotspot Detail Modal */}
      <Dialog open={!!selectedHotspot} onOpenChange={() => setSelectedHotspot(null)}>
        <DialogContent className="max-w-2xl">
          {selectedHotspot && (
            <>
              <DialogHeader>
                <DialogTitle className="flex items-center gap-2">
                  <span>{getCategoryIcon(selectedHotspot.category)}</span>
                  {selectedHotspot.name}
                  <Badge 
                    className="ml-2"
                    style={{ backgroundColor: getCategoryColor(selectedHotspot.category) }}
                  >
                    {selectedHotspot.category}
                  </Badge>
                </DialogTitle>
                <DialogDescription>
                  {selectedHotspot.description}
                </DialogDescription>
              </DialogHeader>

              <div className="space-y-4">
                {selectedHotspot.imageUrl && (
                  <img 
                    src={selectedHotspot.imageUrl} 
                    alt={selectedHotspot.name}
                    className="w-full h-48 object-cover rounded-lg"
                  />
                )}

                <div className="grid grid-cols-2 gap-4">
                  {selectedHotspot.priceRange && (
                    <div className="flex items-center gap-2">
                      <DollarSign className="h-4 w-4 text-green-600" />
                      <span className="text-sm">{selectedHotspot.priceRange}</span>
                    </div>
                  )}

                  <div className="flex items-center gap-2">
                    <Star className="h-4 w-4 text-yellow-500" />
                    <span className="text-sm">Popular destination</span>
                  </div>
                </div>

                {selectedHotspot.ticketUrl && (
                  <div className="bg-gradient-to-r from-blue-50 to-purple-50 p-4 rounded-lg border">
                    <div className="flex items-center justify-between">
                      <div>
                        <h4 className="font-medium">Book Now</h4>
                        <p className="text-sm text-gray-600">
                          Exclusive Golden Pearl Radio offer
                        </p>
                        {selectedHotspot.surcharge > 0 && (
                          <p className="text-xs text-green-600">
                            Use code: {selectedHotspot.affiliateCode || 'GOLDENPEARL10'} for {selectedHotspot.surcharge}% off
                          </p>
                        )}
                      </div>
                      <Button 
                        onClick={() => handleBooking(selectedHotspot)}
                        className="bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700"
                      >
                        <ExternalLink className="w-4 h-4 mr-2" />
                        Book Now
                      </Button>
                    </div>
                  </div>
                )}

                <div className="text-xs text-gray-500 flex items-center gap-4">
                  <span>{selectedHotspot.clickCount} views</span>
                  <span>{selectedHotspot.conversionCount} bookings</span>
                  <span>Promoted by Golden Pearl Radio</span>
                </div>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/types/howler.d.ts.content:
declare module 'howler' {
  export class Howl {
    constructor(options: HowlOptions);
    play(id?: number): number;
    pause(id?: number): this;
    stop(id?: number): this;
    seek(seek?: number, id?: number): number | this;
    playing(id?: number): boolean;
    duration(id?: number): number;
    volume(volume?: number, id?: number): number | this;
    fade(from: number, to: number, duration: number, id?: number): this;
    rate(rate?: number, id?: number): number | this;
    mute(muted?: boolean, id?: number): boolean | this;
    loop(loop?: boolean, id?: number): boolean | this;
    state(): 'unloaded' | 'loading' | 'loaded';
    load(): this;
    unload(): this;
    on(event: string, callback: Function, id?: number): this;
    once(event: string, callback: Function, id?: number): this;
    off(event: string, callback?: Function, id?: number): this;
  }

  export class Howler {
    static volume(volume?: number): number | Howler;
    static mute(muted?: boolean): boolean | Howler;
    static stop(): Howler;
    static codecs(ext: string): boolean;
    static unload(): Howler;
  }

  export interface HowlOptions {
    src: string | string[];
    volume?: number;
    html5?: boolean;
    loop?: boolean;
    preload?: boolean;
    autoplay?: boolean;
    mute?: boolean;
    rate?: number;
    pool?: number;
    format?: string[];
    xhr?: {
      method?: string;
      headers?: Record<string, string>;
      withCredentials?: boolean;
    };
    // Additional properties that exist in Howler.js but not in the TypeScript definition
    xhrWithCredentials?: boolean;
    onload?: () => void;
    onloaderror?: (id: number, error: any) => void;
    onplayerror?: (id: number, error: any) => void;
    onplay?: (id: number) => void;
    onend?: (id: number) => void;
    onpause?: (id: number) => void;
    onstop?: (id: number) => void;
    onmute?: (id: number) => void;
    onvolume?: (id: number) => void;
    onrate?: (id: number) => void;
    onseek?: (id: number) => void;
    onfade?: (id: number) => void;
    onunlock?: () => void;
  }
}

