import React, { useState, useRef, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Play, Pause, Volume2, VolumeX } from 'lucide-react';
import { Howl, HowlOptions } from 'howler';
import { Slider } from '@/components/ui/slider';
import { toast } from '@/hooks/use-toast';

// Bucket name and account constants - must match the server-side configuration
const R2_BUCKET_NAME = 'goldenpearl';
const R2_ACCOUNT_ID = '9483a930fdaec4bd11fa3caf88dad91d';

interface AudioPreviewProps {
  url: string;
  title?: string;
  artist?: string;
  onPlay?: () => void;
  onStop?: () => void;
  size?: 'sm' | 'md' | 'lg';
  showControls?: boolean;
}

export function AudioPreview({ 
  url, 
  title, 
  artist, 
  onPlay, 
  onStop, 
  size = 'md',
  showControls = false
}: AudioPreviewProps) {
  const [playing, setPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(0.75);
  const [muted, setMuted] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const howlRef = useRef<Howl | null>(null);
  const reqAnimRef = useRef<number | null>(null);

  // Clean up any existing Howl instances and animation frames
  const cleanupHowl = () => {
    if (reqAnimRef.current) {
      cancelAnimationFrame(reqAnimRef.current);
      reqAnimRef.current = null;
    }

    if (howlRef.current) {
      howlRef.current.unload();
      howlRef.current = null;
    }
  };

  // Update the progress of the audio playback
  const updateProgress = () => {
    if (howlRef.current && playing) {
      const currentPos = howlRef.current.seek() as number;
      setCurrentTime(currentPos);
      reqAnimRef.current = requestAnimationFrame(updateProgress);
    }
  };

  // Toggle play/pause
  const togglePlayPause = () => {
    if (!howlRef.current) {
      // Initialize if not already done
      playAudio();
      return;
    }

    if (playing) {
      howlRef.current.pause();
      setPlaying(false);
      if (onStop) onStop();
    } else {
      howlRef.current.play();
      setPlaying(true);
      if (onPlay) onPlay();
    }
  };

  // Toggle mute state
  const toggleMute = () => {
    if (!howlRef.current) return;

    setMuted(!muted);
    howlRef.current.mute(!muted);
  };

  // Handle volume change
  const handleVolumeChange = (values: number[]) => {
    if (!howlRef.current) return;

    const newVolume = values[0];
    setVolume(newVolume);
    howlRef.current.volume(newVolume);

    // If we're adjusting volume and it was muted, unmute it
    if (muted && newVolume > 0) {
      setMuted(false);
      howlRef.current.mute(false);
    }
  };

  // Process audio URL to handle various formats
  const processAudioUrl = (sourceUrl: string): string => {
    // Empty URL check
    if (!sourceUrl) return '';

    // Remove any existing cache-busting query parameters (timestamp)
    let processedUrl = sourceUrl.split('&timestamp=')[0].split('?timestamp=')[0];

    // Auto detect and log CloudFlare R2 URLs
    if (processedUrl.includes('r2.cloudflarestorage.com')) {
      console.log('Detected R2 CloudFlare Storage URL');
    }

    // Special handling for Doha Metro Suite track
    if (processedUrl.includes('the-doha-metro-suite')) {
      console.log('Doha Metro Suite track detected');

      // Extract the base URL without any query parameters
      if (processedUrl.includes('?')) {
        processedUrl = processedUrl.split('?')[0];
      }

      console.log('Using clean base URL for Doha Metro Suite:', processedUrl);
    }

    // Add a cache-busting timestamp to prevent browser caching
    if (!processedUrl.includes('timestamp=')) {
      processedUrl = processedUrl + (processedUrl.includes('?') ? '&' : '?') + `timestamp=${Date.now()}&force_html5=true`;
    }

    return processedUrl;
  };

  // Initialize and play the audio
  const playAudio = () => {
    // Clean up any existing instances first
    cleanupHowl();

    // If no URL is provided, exit early
    if (!url) {
      setError('No audio URL provided');
      return;
    }

    try {
      // Process the URL to handle caching, CDN issues, etc.
      const processedUrl = processAudioUrl(url);
      console.log(`Loading audio preview from: ${processedUrl}`);

      // Determine if we have an MP3 file or another format
      const isMp3 = processedUrl.toLowerCase().endsWith('.mp3') || 
                    processedUrl.toLowerCase().includes('.mp3?') ||
                    processedUrl.includes('the-doha-metro-suite');

      // Special handling for URLs
      let dohaMetroUseDirectUrl = false;
      let finalUrl = processedUrl;

      // Check for incorrect URL format with bucket in subdomain
      if (processedUrl.includes(`${R2_BUCKET_NAME}.${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/`)) {
        console.log('Detected incorrect R2 URL format with bucket in subdomain');

        // Extract the filename
        const parts = processedUrl.split('/');
        const filename = parts[parts.length - 1].split('?')[0];

        // Reconstruct with correct format (bucket in path)
        const correctedUrl = `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${R2_BUCKET_NAME}/${filename}?timestamp=${Date.now()}&force_html5=true`;
        console.log('Corrected URL format:', correctedUrl);
        finalUrl = correctedUrl;
      }

      // Directly check if URL has X-Amz-Signature parameter, which indicates signed URLs that may expire
      if (processedUrl.includes('X-Amz-Signature') && processedUrl.includes('r2.cloudflarestorage.com')) {
        console.log('Detected signed R2 URL, extracting filename to create direct URL');

        try {
          // Extract the filename from the URL - it's part of the path before the query parameters
          const urlWithoutQuery = processedUrl.split('?')[0];
          const parts = urlWithoutQuery.split('/');
          const filename = parts[parts.length - 1];

          if (filename) {
            // Create a direct URL format that doesn't rely on signatures
            const directUrl = `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${R2_BUCKET_NAME}/${filename}?timestamp=${Date.now()}&force_html5=true`;
            console.log('Converted signed URL to direct URL:', directUrl);
            finalUrl = directUrl;
          }
        } catch (e) {
          console.error('Error parsing signed URL:', e);
          // Keep the original URL if parsing fails
        }
      }

      // Special handling for the Doha Metro Suite track
      if (processedUrl.includes('the-doha-metro-suite')) {
        // If it includes query parameters (signed URL), we'll first try with the base URL
        if (processedUrl.includes('?')) {
          dohaMetroUseDirectUrl = true;
          // Use the proper direct URL format with bucket in the path 
          const baseDohaUrl = `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${R2_BUCKET_NAME}/the-doha-metro-suite-afcad310.mp3?timestamp=${Date.now()}&force_html5=true`;
          console.log('Trying direct URL for Doha Metro Suite:', baseDohaUrl);
          finalUrl = baseDohaUrl;
        }
      }

      // Create Howl configuration
      const config: HowlOptions = {
        src: [finalUrl],
        html5: true, // Always use HTML5 Audio for streaming
        volume: volume,
        format: isMp3 ? ['mp3'] : undefined,
        autoplay: false, // Don't auto-play, we'll manually call play()
        preload: true,  // Preload the audio file
        xhr: {
          method: 'GET',
          headers: {
            'Cache-Control': 'no-cache',
            'Pragma': 'no-cache',
            'Accept': 'audio/mp3,audio/*;q=0.9,*/*;q=0.8'
          },
          withCredentials: false
        },
        xhrWithCredentials: false,
        onload: () => {
          console.log('Audio preview loaded successfully');
          if (howlRef.current) {
            setDuration(howlRef.current.duration());
          }
          setError(null);
        },
        onloaderror: (id, err) => {
          console.error('Error loading audio preview:', err);

          // For the Doha Metro Suite, if we're using the signed URL and it fails,
          // try constructing a direct URL to the R2 bucket or use the special API endpoint
          if (url.includes('the-doha-metro-suite') && !dohaMetroUseDirectUrl) {
            console.log('Trying alternate URL format for Doha Metro Suite');

            // First try using our special API endpoint for Doha Metro Suite
            console.log('Fetching Doha Metro Suite URL from API...');

            fetch('/api/track/doha-metro-suite')
              .then(response => response.json())
              .then(data => {
                console.log('Got special URL from API:', data.url);

                // Create a new Howl instance with the API-provided URL
                cleanupHowl();
                const apiUrl = data.url + `?timestamp=${Date.now()}&force_html5=true`;
                console.log('Using API URL:', apiUrl);

                const apiConfig = {
                  ...config,
                  src: [apiUrl],
                  onloaderror: () => {
                    console.log('API URL failed, falling back to direct URL formats');
                    tryFallbackUrls();
                  }
                };

                howlRef.current = new Howl(apiConfig);
                howlRef.current.play();
              })
              .catch(error => {
                console.error('Error fetching special URL:', error);
                tryFallbackUrls();
              });

            return;
          }

          setError('Unable to load audio. The file may be unavailable or the URL may have expired.');
          setPlaying(false);
        },
        onplayerror: (id, err) => {
          console.error('Error playing audio preview:', err);

          // Try refreshing the URL if it's a signed URL from R2
          if (url.includes('r2.cloudflarestorage.com') && url.includes('X-Amz-Signature')) {
            console.log('Trying to refresh expired signed URL');
            const refreshedUrl = processAudioUrl(url);

            // Create a new Howl instance with the refreshed URL
            cleanupHowl();
            howlRef.current = new Howl({
              ...config,
              src: [refreshedUrl],
              onplayerror: () => {
                console.error('Refreshed URL also failed');
                setError('Error playing audio. The format may be unsupported or the file is corrupted.');
                setPlaying(false);

                toast({
                  title: "Playback Error",
                  description: "Could not play this track even after refreshing the URL.",
                  variant: "destructive"
                });
              }
            });

            // Try to play with the refreshed URL
            howlRef.current.play();
            return;
          }

          setError('Error playing audio. The format may be unsupported or the file is corrupted.');
          setPlaying(false);

          toast({
            title: "Playback Error",
            description: "Could not play this track. The URL may be invalid or expired.",
            variant: "destructive"
          });
        },
        onplay: () => {
          setPlaying(true);
          reqAnimRef.current = requestAnimationFrame(updateProgress);
          if (onPlay) onPlay();
        },
        onpause: () => {
          setPlaying(false);
          if (onStop) onStop();
        },
        onstop: () => {
          setPlaying(false);
          if (onStop) onStop();
        },
        onend: () => {
          setPlaying(false);
          setCurrentTime(0);
          if (onStop) onStop();
        }
      };

      // Function to try fallback URLs for Doha Metro Suite
      const tryFallbackUrls = () => {
        // Format 1: R2 bucket in path (recommended format)
        const directUrl1 = `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${R2_BUCKET_NAME}/the-doha-metro-suite-afcad310.mp3?timestamp=${Date.now()}&force_html5=true`;
        console.log('Trying direct URL format 1:', directUrl1);

        // Create a new Howl instance with the first fallback URL
        cleanupHowl();
        howlRef.current = new Howl({
          ...config,
          src: [directUrl1],
          onloaderror: () => {
            console.log('First URL format failed, trying second format');

            // Format 2: Alternative URL pattern (public bucket endpoint)
            const directUrl2 = `https://pub-${R2_ACCOUNT_ID}.r2.dev/${R2_BUCKET_NAME}/the-doha-metro-suite-afcad310.mp3?force_html5=true`;
            console.log('Trying URL format 2:', directUrl2);

            // Try second URL format if first fails
            cleanupHowl();
            howlRef.current = new Howl({
              ...config, 
              src: [directUrl2],
              onloaderror: () => {
                console.error('All URL formats failed for Doha Metro Suite');
                setError('Unable to load audio after trying multiple URL formats. Please check if the file exists in R2 storage.');
                setPlaying(false);
              }
            });

            // Try to play with the second URL format
            howlRef.current.play();
          }
        });

        // Try to play with the first fallback URL
        howlRef.current.play();
      }

      // Create and store Howl instance
      howlRef.current = new Howl(config);
      howlRef.current.play();

    } catch (err) {
      console.error('Error setting up audio preview:', err);
      setError('Failed to initialize audio player');
    }
  };

  // Format time for display (MM:SS)
  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  // Cleanup on unmount or URL change
  useEffect(() => {
    return () => {
      cleanupHowl();
    };
  }, [url]);

  // Size classes
  const sizeClasses = {
    sm: 'h-8 w-8',
    md: 'h-10 w-10',
    lg: 'h-12 w-12'
  };

  return (
    <div className="flex items-center space-x-2">
      <Button
        variant="outline"
        size="icon"
        onClick={togglePlayPause}
        className={`rounded-full bg-primary/10 hover:bg-primary/20 ${sizeClasses[size]}`}
        disabled={!url}
      >
        {playing ? (
          <Pause className="h-4 w-4" />
        ) : (
          <Play className="h-4 w-4" />
        )}
      </Button>

      {showControls && (
        <>
          <div className="flex-1">
            <div className="flex justify-between text-xs text-muted-foreground">
              <span>{formatTime(currentTime)}</span>
              <span>{formatTime(duration)}</span>
            </div>
            <Slider
              value={[currentTime]}
              max={duration || 100}
              step={0.1}
              disabled={!url || duration === 0}
              onValueChange={(value) => {
                if (howlRef.current) {
                  howlRef.current.seek(value[0]);
                  setCurrentTime(value[0]);
                }
              }}
              className="my-1"
            />
          </div>

          <Button
            variant="ghost"
            size="icon"
            onClick={toggleMute}
            className="h-8 w-8"
            disabled={!url}
          >
            {muted ? (
              <VolumeX className="h-4 w-4" />
            ) : (
              <Volume2 className="h-4 w-4" />
            )}
          </Button>

          <Slider
            value={[volume]}
            max={1}
            step={0.01}
            disabled={!url}
            onValueChange={handleVolumeChange}
            className="w-20"
          />
        </>
      )}

      {error && <p className="text-destructive text-xs">{error}</p>}
    </div>
  );
}

