import { useState, useEffect, useRef, createContext, useContext } from 'react';
import { Howl, Howler, HowlOptions } from 'howler';

// Bucket name and account constants - must match the server-side configuration
const R2_BUCKET_NAME = 'goldenpearl';
const R2_ACCOUNT_ID = '9483a930fdaec4bd11fa3caf88dad91d';

interface AudioControllerContextProps {
  playing: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  togglePlayPause: () => void;
  skipForward: () => void;
  skipBackward: () => void;
  setVolume: (volume: number) => void;
  setTrackUrl: (url: string) => void;
  error: string | null;
}

const AudioControllerContext = createContext<AudioControllerContextProps>({
  playing: false,
  currentTime: 0,
  duration: 0,
  volume: 1,
  togglePlayPause: () => {},
  skipForward: () => {},
  skipBackward: () => {},
  setVolume: () => {},
  setTrackUrl: () => {},
  error: null,
});

export function AudioControllerProvider({ children }: { children: React.ReactNode }) {
  const [playing, setPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolumeState] = useState(1);
  const [error, setError] = useState<string | null>(null);
  const soundRef = useRef<Howl | null>(null);

  const setTrackUrl = (url: string) => {
    // Reset error state
    setError(null);

    // Unload previous track if it exists
    if (soundRef.current) {
      soundRef.current.unload();
    }

    if (url) {
      // Process the URL: add cache-busting and potentially correct the URL format
      let trackUrl = url;

      // Clean URL by removing any existing cache-busting parameters
      trackUrl = trackUrl.split('&timestamp=')[0].split('?timestamp=')[0];

      // Auto-detect URL storage type for improved logging
      if (trackUrl.includes('r2.cloudflarestorage.com')) {
        console.log('Detected CloudFlare R2 URL');
      } else if (trackUrl.includes('/goldenpearl/')) {
        console.log('URL with /goldenpearl/ path format detected');
      }

      // Special handling for Doha Metro Suite which often has URL issues
      if (url.includes('the-doha-metro-suite')) {
        console.log('Doha Metro Suite track detected - using special handling');

        // First try to get the URL from our special API endpoint
        fetch('/api/track/doha-metro-suite')
          .then(response => response.json())
          .then(data => {
            if (data && data.url) {
              console.log('Using special API URL for Doha Metro Suite:', data.url);
              if (soundRef.current) {
                // If we already have a sound instance, unload it
                soundRef.current.unload();
              }
              // Create new howl instance with the correct URL
              const apiUrl = data.url + `?timestamp=${Date.now()}&force_html5=true`;
              const howlConfig: HowlOptions = {
                src: [apiUrl],
                html5: true,
                volume: volume,
                format: ['mp3'],
                xhr: {
                  method: 'GET',
                  headers: {
                    'Cache-Control': 'no-cache',
                  },
                  withCredentials: false
                },
                onplay: () => {
                  setPlaying(true);
                  requestAnimationFrame(updateProgress);
                }
              };
              soundRef.current = new Howl(howlConfig);
              soundRef.current.play();
            }
          })
          .catch(error => {
            console.error('Error fetching from API, using fallback:', error);
            // If API fails, use direct URL format as fallback
            if (url.includes('?')) {
              const directUrl = `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${R2_BUCKET_NAME}/the-doha-metro-suite-afcad310.mp3?timestamp=${Date.now()}&force_html5=true`;
              console.log('Using fallback direct URL for Doha Metro Suite:', directUrl);
              trackUrl = directUrl;
            }
          });

        // Return early, as we've handled this special case
        return;
      }

      // Check for invalid URL format (bucket in subdomain instead of path)
      if (url.includes(`${R2_BUCKET_NAME}.${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/`)) {
        console.log('Detected incorrect R2 URL format with bucket in subdomain');
        // Extract the filename
        const parts = url.split('/');
        const filename = parts[parts.length - 1].split('?')[0];
        // Reconstruct with correct format (bucket in path)
        const correctedUrl = `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com/${R2_BUCKET_NAME}/${filename}?timestamp=${Date.now()}&force_html5=true`;
        console.log('Corrected URL format:', correctedUrl);
        trackUrl = correctedUrl;
      }

      // Add cache-busting parameters if not already present
      if (!trackUrl.includes('timestamp=')) {
        trackUrl = trackUrl + (trackUrl.includes('?') ? '&' : '?') + `timestamp=${Date.now()}&force_html5=true`;
      }

      try {
        // Determine if we're using an MP3 file or other format
        const isMp3 = trackUrl.toLowerCase().endsWith('.mp3') || 
                      trackUrl.toLowerCase().includes('.mp3?') || 
                      trackUrl.includes('the-doha-metro-suite');

        // Create Howl configuration with format-specific settings
        const howlConfig: HowlOptions = {
          src: [trackUrl],
          html5: true, // Always use HTML5 Audio for better streaming support
          volume: volume,
          format: isMp3 ? ['mp3'] : undefined, // Explicit format can help with some files
          xhr: {
            method: 'GET',
            headers: {
              // Add cache control to prevent caching issues with signed URLs
              'Cache-Control': 'no-cache',
            },
            withCredentials: false
          },
          onload: () => {
            console.log('Track loaded successfully');
            if (soundRef.current) {
              setDuration(soundRef.current.duration() || 0);
            }
            setError(null);
          },
          onloaderror: (id, err) => {
            console.error('Error loading track:', err);
            setError('Unable to load audio track. The file may be unavailable or the URL might have expired.');

            // For signed URLs from R2, this is where you'd handle refreshing the URL
            if (url.includes('r2.cloudflarestorage.com') && url.includes('X-Amz-Expires')) {
              setError('The audio URL has expired. Please reload the track list to get fresh URLs.');

              // The track id is usually embedded in the url filename for R2 uploads
              // We can try to fetch a fresh URL via the API
              fetch('/api/tracks')
                .then(res => res.json())
                .then(tracks => {
                  // Find a track with a matching URL pattern
                  const urlParts = url.split('?')[0].split('/');
                  const filename = urlParts.length > 0 ? urlParts[urlParts.length - 1] : '';
                  const filenameBase = filename ? filename.split('-')[0] : '';

                  const matchingTrack = tracks.find((track: any) => 
                    track.url && typeof track.url === 'string' && 
                    filenameBase && track.url.includes(filenameBase)
                  );

                  if (matchingTrack && matchingTrack.url) {
                    console.log('Found matching track with fresh URL, retrying playback');
                    // Retry with new URL
                    setTrackUrl(matchingTrack.url);
                  }
                })
                .catch(error => {
                  console.error('Failed to refresh track URL:', error);
                });
            }
          },
          onplayerror: (id, err) => {
            console.error('Error playing audio:', err);
            setError('Error playing audio. Please try a different track.');
          },
          onplay: () => {
            setPlaying(true);
            requestAnimationFrame(updateProgress);
          },
          onpause: () => {
            setPlaying(false);
          },
          onstop: () => {
            setPlaying(false);
          },
          onend: () => {
            console.log('Track ended');
            // Track ended naturally - can be handled by RadioPlayer for playlist navigation
            setPlaying(false);
            setCurrentTime(0);
          }
        };

        // Create the Howl instance with our config
        soundRef.current = new Howl(howlConfig);
      } catch (err) {
        console.error('Error creating Howl instance:', err);
        setError('Failed to initialize audio player. Please try again.');
      }
    } else {
      setError('No audio URL provided');
    }
  };

  const updateProgress = () => {
    if (soundRef.current && playing) {
      const currentSeek = soundRef.current.seek();
      if (typeof currentSeek === 'number') {
        setCurrentTime(currentSeek);
      }
      requestAnimationFrame(updateProgress);
    }
  };

  const togglePlayPause = () => {
    if (!soundRef.current) return;

    if (playing) {
      soundRef.current.pause();
    } else {
      soundRef.current.play();
    }
  };

  const skipForward = () => {
    if (!soundRef.current) return;

    const newTime = Math.min(currentTime + 10, duration);
    soundRef.current.seek(newTime);
    setCurrentTime(newTime);
  };

  const skipBackward = () => {
    if (!soundRef.current) return;

    const newTime = Math.max(currentTime - 10, 0);
    soundRef.current.seek(newTime);
    setCurrentTime(newTime);
  };

  const setVolume = (newVolume: number) => {
    if (!soundRef.current) return;

    setVolumeState(newVolume);
    soundRef.current.volume(newVolume);
  };

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (soundRef.current) {
        soundRef.current.unload();
      }
    };
  }, []);

  return (
    <AudioControllerContext.Provider
      value={{
        playing,
        currentTime,
        duration,
        volume,
        togglePlayPause,
        skipForward,
        skipBackward,
        setVolume,
        setTrackUrl,
        error
      }}
    >
      {children}
    </AudioControllerContext.Provider>
  );
}

export function useAudioController() {
  return useContext(AudioControllerContext);
}

