import { useState, useEffect } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Track, Show } from '@shared/schema';
import { useAudioController } from './AudioController';
import { Link } from 'wouter';

type NowPlayingResponse = {
  type: 'track' | 'show';
  data: Track | Show;
  nextTracks: Track[];
};

export default function RadioPlayer() {
  const { 
    playing, 
    currentTime, 
    duration, 
    togglePlayPause, 
    skipForward, 
    skipBackward, 
    setTrackUrl,
    error
  } = useAudioController();

  const [currentTrack, setCurrentTrack] = useState<Track | null>(null);
  const [showInfo, setShowInfo] = useState<Show | null>(null);
  const [playlistTracks, setPlaylistTracks] = useState<Track[]>([]);
  const [currentTrackIndex, setCurrentTrackIndex] = useState(0);

  // Fetch Main playlist tracks
  // Fetch tracks from the Main playlist (id: 1)
  const { data: playlistData } = useQuery<{id: number, trackId: number, position: number}[]>({
    queryKey: ['/api/playlists/1/tracks'],
  });

  // Fetch the actual track data for all tracks in the playlist
  const { data: tracks } = useQuery<Track[]>({
    queryKey: ['/api/tracks'],
    enabled: !!playlistData && playlistData.length > 0,
  });

  // Fetch current playing track/show (as a fallback)
  const { data: nowPlaying } = useQuery<NowPlayingResponse>({
    queryKey: ['/api/now-playing'],
    refetchInterval: 30000, // Refetch every 30 seconds
    enabled: !playlistData || playlistData.length === 0, // Only fetch if no playlist data
  });

  // Combine playlist data with track data to get full track objects with URLs
  useEffect(() => {
    if (playlistData && tracks && playlistData.length > 0 && tracks.length > 0) {
      // Map playlistData to actual track objects
      const sortedPlaylistItems = [...playlistData].sort((a, b) => a.position - b.position);
      const playlistWithTracks = sortedPlaylistItems.map(item => {
        // Find the corresponding track by ID
        return tracks.find(track => track.id === item.trackId);
      }).filter((track): track is Track => !!track); // Type guard to ensure non-null tracks

      if (playlistWithTracks.length > 0) {
        setPlaylistTracks(playlistWithTracks);

        // Set the initial track if not already playing
        if (!currentTrack) {
          const initialTrack = playlistWithTracks[0];
          if (initialTrack) {
            setCurrentTrack(initialTrack);
            setCurrentTrackIndex(0);

            // Only set track URL if not already playing something
            if (!playing && initialTrack.url) {
              console.log(`Setting initial track: ${initialTrack.title} URL: ${initialTrack.url}`);
              setTrackUrl(initialTrack.url);
            }
          }
        }
      }
    }
  }, [playlistData, tracks, playing, currentTrack, setTrackUrl]);

  // Function to play a specific track from the playlist
  const playTrack = (track: Track, index: number) => {
    if (track && track.url) {
      console.log(`Playing track: ${track.title}`);
      setCurrentTrack(track);
      setCurrentTrackIndex(index);
      setTrackUrl(track.url);
    }
  };

  // Listen for track ended event and play next track
  useEffect(() => {
    // Only auto-advance if we're close to the end and the track is actually playing
    if (playing && duration > 0 && currentTime >= duration - 0.5) {
      console.log("Track ended - playing next track");
      playNextTrack(); 
    }
  }, [currentTime, duration, playing]);

  // Update track information when now playing data is loaded (as fallback)
  useEffect(() => {
    // Only use now playing data if we don't have playlist data
    if (nowPlaying && (!playlistTracks || playlistTracks.length === 0)) {
      if (nowPlaying.type === 'track') {
        setCurrentTrack(nowPlaying.data as Track);
        setShowInfo(null);
        setTrackUrl((nowPlaying.data as Track).url);
      } else {
        setShowInfo(nowPlaying.data as Show);
        const firstTrack = nowPlaying.nextTracks[0];
        if (firstTrack) {
          setCurrentTrack(firstTrack);
          setTrackUrl(firstTrack.url);
        }
      }
    }
  }, [nowPlaying, playlistTracks, setTrackUrl]);

  // Format time for display (MM:SS)
  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  // Calculate progress percentage
  const progressPercentage = duration > 0 ? (currentTime / duration) * 100 : 0;

  // Handle playlist navigation
  const playNextTrack = () => {
    if (!playlistTracks || playlistTracks.length === 0) {
      // If no playlist, just skip forward 10 seconds in the current track
      skipForward();
      return;
    }

    // Calculate next index with wrapping
    const nextIndex = (currentTrackIndex + 1) % playlistTracks.length;
    const nextTrack = playlistTracks[nextIndex];

    if (nextTrack) {
      console.log(`Playing next track: ${nextTrack.title}`);
      setCurrentTrack(nextTrack);
      setCurrentTrackIndex(nextIndex);
      if (nextTrack.url) {
        setTrackUrl(nextTrack.url);
      }
    }
  };

  const playPreviousTrack = () => {
    if (!playlistTracks || playlistTracks.length === 0) {
      // If no playlist, just skip backward 10 seconds in the current track
      skipBackward();
      return;
    }

    // Calculate previous index with wrapping
    const prevIndex = currentTrackIndex === 0 ? playlistTracks.length - 1 : currentTrackIndex - 1;
    const prevTrack = playlistTracks[prevIndex];

    if (prevTrack) {
      console.log(`Playing previous track: ${prevTrack.title}`);
      setCurrentTrack(prevTrack);
      setCurrentTrackIndex(prevIndex);
      if (prevTrack.url) {
        setTrackUrl(prevTrack.url);
      }
    }
  };

  return (
    <div className="bg-[#F05335] text-[#F9EAC7]">
      <div className="container mx-auto px-4 py-8 text-center">
        <h1 className="font-poppins font-bold text-5xl mb-4">
          GOLDEN PEARL<br />RADIO/DUBAI
        </h1>
        <p className="text-xl mb-8">
          Explore Dubai with the ultimate soundtrack<br />for your trip
        </p>

        {/* Player exactly matching design in Screenshot 2025-05-04 at 14.03.21.png */}
        <div className="max-w-md mx-auto mb-10">
          <div className="rounded-xl overflow-hidden shadow-lg">
            {/* Player display area */}
            <div className="bg-[#F9EAC7] text-[#333333] p-4">
              <div className="flex justify-between items-center">
                <div className="text-left font-bold text-xl">
                  {showInfo?.title || currentTrack?.title || 'Modern Dubai Beat'}
                </div>
                <div className="text-right text-2xl font-bold">
                  {formatTime(currentTime) || '00:00'}
                </div>
              </div>

              {/* Progress slider */}
              <div className="w-full bg-[#333333] h-2 mt-3 rounded-full">
                <div 
                  className="bg-[#333333] h-2 rounded-full relative" 
                  style={{ width: `${progressPercentage}%` }}
                >
                  <div className="absolute top-1/2 right-0 transform translate-x-1/2 -translate-y-1/2 w-4 h-4 bg-black rounded-full"></div>
                </div>
              </div>

              {/* Error message */}
              {error && (
                <div className="mt-2 text-red-600 text-sm">
                  {error}
                </div>
              )}
            </div>

            {/* Player controls exactly matching the design image */}
            <div className="bg-[#555549] p-4 flex justify-between items-center">
              {/* Left arrow button */}
              <button className="text-[#F9EAC7] hover:opacity-90" onClick={playPreviousTrack}>
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                  <path d="M10 16L5 12L10 8" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </button>

              {/* Back button */}
              <button className="text-[#F9EAC7] hover:opacity-90" onClick={skipBackward}>
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                  <path d="M19 20L9 12L19 4V20Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </button>

              {/* Play/Pause button */}
              <button 
                className="bg-[#333333] w-12 h-12 rounded-full flex items-center justify-center text-[#F9EAC7]"
                onClick={togglePlayPause}
              >
                {playing ? (
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor">
                    <rect x="6" y="4" width="4" height="16"/>
                    <rect x="14" y="4" width="4" height="16"/>
                  </svg>
                ) : (
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor">
                    <path d="M6 4L18 12L6 20V4Z"/>
                  </svg>
                )}
              </button>

              {/* Forward button */}
              <button className="text-[#F9EAC7] hover:opacity-90" onClick={skipForward}>
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                  <path d="M5 4L15 12L5 20V4Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </button>

              {/* Right arrow button */}
              <button className="text-[#F9EAC7] hover:opacity-90" onClick={playNextTrack}>
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                  <path d="M14 8L19 12L14 16" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </button>
            </div>
          </div>
        </div>

        {/* Playlist track list */}
        {playlistTracks.length > 0 && (
          <div className="max-w-md mx-auto mb-8 bg-[#F9EAC7] rounded-xl p-4 text-[#333333]">
            <h3 className="font-bold text-xl mb-3">Current Playlist</h3>
            <ul className="divide-y divide-gray-200">
              {playlistTracks.map((track, index) => (
                <li key={track.id} className={`py-3 px-2 cursor-pointer hover:bg-[#F1DEB3] ${currentTrackIndex === index ? 'bg-[#F1DEB3] font-bold' : ''}`}
                    onClick={() => playTrack(track, index)}>
                  <div className="flex justify-between items-center">
                    <div className="flex items-center">
                      {currentTrackIndex === index && playing ? (
                        <svg className="w-4 h-4 mr-2" viewBox="0 0 24 24" fill="currentColor">
                          <rect x="6" y="4" width="4" height="16"/>
                          <rect x="14" y="4" width="4" height="16"/>
                        </svg>
                      ) : (
                        <svg className="w-4 h-4 mr-2" viewBox="0 0 24 24" fill="currentColor">
                          <path d="M6 4L18 12L6 20V4Z"/>
                        </svg>
                      )}
                      <span>{track.title}</span>
                    </div>
                    <span className="text-sm text-gray-500">{track.artist || "Unknown Artist"}</span>
                  </div>
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* Navigation Icons - 4 evenly spaced buttons with consistent fat line aesthetic */}
        <div className="grid grid-cols-4 gap-4 max-w-md mx-auto">
          {/* Live Radio Icon - Sound waves with center dot */}
          <div className="text-center">
            <div className="w-20 h-20 mx-auto mb-2 rounded-lg bg-[#F9EAC7] border-2 border-[#333333] shadow-md flex flex-col items-center justify-center">
              <div className="relative">
                <svg width="60" height="40" viewBox="0 0 24 24" fill="none" stroke="#333333" strokeWidth="2.5">
                  {/* Left sound waves - taller with more curve */}
                  <path d="M2 12C2 7 4 3 8 3" strokeLinecap="round"></path>
                  <path d="M6 12C6 9 7 6 10 6" strokeLinecap="round"></path>
                  {/* Right sound waves - taller with more curve */}
                  <path d="M22 12C22 7 20 3 16 3" strokeLinecap="round"></path>
                  <path d="M18 12C18 9 17 6 14 6" strokeLinecap="round"></path>
                  {/* Center dot */}
                  <circle cx="12" cy="12" r="2" fill="#333333" stroke="none"></circle>
                </svg>
                <div className="text-center mt-2">
                  <span className="text-xs font-bold text-[#333333]">LIVE</span>
                </div>
              </div>
            </div>
          </div>

          {/* Podcasts Icon - Two people with fat lines */}
          <div className="text-center">
            <div className="w-20 h-20 mx-auto mb-2 rounded-lg bg-[#F9EAC7] border-2 border-[#333333] shadow-md flex flex-col items-center justify-center">
              <svg width="60" height="60" viewBox="0 0 24 24" fill="none" stroke="#333333" strokeWidth="2.5">
                <circle cx="7" cy="8" r="3"></circle>
                <circle cx="17" cy="8" r="3"></circle>
                <line x1="7" y1="11" x2="7" y2="16" strokeLinecap="round"></line>
                <line x1="17" y1="11" x2="17" y2="16" strokeLinecap="round"></line>
                <line x1="7" y1="16" x2="17" y2="16" strokeLinecap="round"></line>
              </svg>
              <span className="text-xs font-bold text-[#333333]">Podcast</span>
            </div>
          </div>

          {/* Archive Icon - Simple box */}
          <div className="text-center">
            <div className="w-20 h-20 mx-auto mb-2 rounded-lg bg-[#F9EAC7] border-2 border-[#333333] shadow-md flex flex-col items-center justify-center">
              <svg width="60" height="60" viewBox="0 0 24 24" fill="none" stroke="#333333" strokeWidth="2.5">
                <rect x="4" y="6" width="16" height="12" rx="1"></rect>
              </svg>
              <span className="text-xs font-bold text-[#333333]">Archive</span>
            </div>
          </div>

          {/* Store Icon - Shopping basket */}
          <div className="text-center">
            <div className="w-20 h-20 mx-auto mb-2 rounded-lg bg-[#F9EAC7] border-2 border-[#333333] shadow-md flex flex-col items-center justify-center">
              <svg width="60" height="60" viewBox="0 0 24 24" fill="none" stroke="#333333" strokeWidth="2.5">
                <path d="M4 10h16l-1 8H5l-1-8z" strokeLinejoin="round"></path>
                <path d="M7 10V7a5 5 0 0 1 10 0v3" strokeLinecap="round"></path>
              </svg>
              <span className="text-xs font-bold text-[#333333]">Store</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

