import { Product } from '@shared/schema';
import { Button } from '@/components/ui/button';
import { ExternalLink } from 'lucide-react';

interface OfferCardProps {
  product: Product;
}

export function OfferCard({ product }: OfferCardProps) {
  const handleClick = () => {
    // In a real implementation, this would increment clicks and redirect
    fetch(`/api/products/${product.id}/click`, {
      method: 'POST',
    });
    window.open(product.affiliateUrl, '_blank');
  };

  return (
    <div className="bg-white rounded-lg shadow-md overflow-hidden">
      {product.coverImage && (
        <img 
          src={product.coverImage} 
          alt={product.title}
          className="w-full h-48 object-cover"
        />
      )}
      <div className="p-4">
        <div className="flex justify-between items-start mb-2">
          <h3 className="font-poppins font-medium text-lg">{product.title}</h3>
          <span className="bg-gray-100 text-gray-800 text-xs px-2 py-1 rounded">
            {product.category}
          </span>
        </div>
        <p className="text-sm text-gray-600 mb-4 line-clamp-2">
          {product.description}
        </p>
        <div className="flex justify-between items-center">
          <span className="text-radio-orange font-bold">{product.price}</span>
          <Button
            variant="default"
            size="sm"
            className="bg-radio-orange text-white hover:bg-radio-orange/90 rounded-full flex items-center"
            onClick={handleClick}
          >
            Shop Now
            <ExternalLink className="ml-1 h-3 w-3" />
          </Button>
        </div>
      </div>
    </div>
  );
}

