    { value: "normal", label: "Normal", color: "bg-blue-500" },
    { value: "urgent", label: "Urgent", color: "bg-orange-500" },
    { value: "critical", label: "Critical", color: "bg-red-500" }
  ];

  // Fetch breaking news
  const { data: breakingNewsList = [], isLoading } = useQuery({
    queryKey: ['/api/breaking-news']
  });

  // Create breaking news
  const createBreakingNews = useMutation({
    mutationFn: async (data: InsertBreakingNews) => {
      const response = await fetch('/api/breaking-news', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
      });
      if (!response.ok) throw new Error('Failed to create breaking news');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/breaking-news'] });
      toast({
        title: "Breaking News Created",
        description: "TTS audio is being generated and will be ready shortly"
      });
      setNewMessage("");
      setScheduledFor("");
      setExpiresAt("");
    }
  });

  // Generate TTS preview
  const generatePreview = useMutation({
    mutationFn: async ({ message, voice }: { message: string, voice: string }) => {
      const response = await fetch('/api/breaking-news/preview', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message, voiceType: voice })
      });
      if (!response.ok) throw new Error('Failed to generate preview');
      return response.json();
    },
    onSuccess: (data) => {
      if (data.audioUrl) {
        const audio = new Audio(data.audioUrl);
        audio.onended = () => setIsPlaying(false);
        setPreviewAudio(audio);
        audio.play();
        setIsPlaying(true);
      }
    }
  });

  // Insert into schedule
  const insertIntoSchedule = useMutation({
    mutationFn: async (newsId: number) => {
      const response = await fetch(`/api/breaking-news/${newsId}/schedule`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' }
      });
      if (!response.ok) throw new Error('Failed to insert into schedule');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/breaking-news'] });
      queryClient.invalidateQueries({ queryKey: ['/api/schedule'] });
      toast({
        title: "Breaking News Scheduled",
        description: "Message has been inserted into the program schedule"
      });
    }
  });

  // Delete breaking news
  const deleteBreakingNews = useMutation({
    mutationFn: async (id: number) => {
      const response = await fetch(`/api/breaking-news/${id}`, {
        method: 'DELETE'
      });
      if (!response.ok) throw new Error('Failed to delete breaking news');
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/breaking-news'] });
      toast({
        title: "Breaking News Deleted",
        description: "Message has been removed"
      });
    }
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim()) return;

    const data: InsertBreakingNews = {
      message: newMessage.trim(),
      voiceType: selectedVoice,
      priority,
      scheduledFor: scheduledFor ? new Date(scheduledFor) : undefined,
      expiresAt: expiresAt ? new Date(expiresAt) : undefined,
      isActive: true
    };

    createBreakingNews.mutate(data);
  };

  const handlePreview = () => {
    if (!newMessage.trim()) return;

    if (isPlaying && previewAudio) {
      previewAudio.pause();
      setIsPlaying(false);
      return;
    }

    generatePreview.mutate({ message: newMessage, voice: selectedVoice });
  };

  const getPriorityColor = (priority: string) => {
    const priorityObj = priorities.find(p => p.value === priority);
    return priorityObj?.color || "bg-gray-500";
  };

  if (isLoading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-red-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-3">
        <AlertTriangle className="h-6 w-6 text-red-600" />
        <h1 className="text-2xl font-bold">Breaking News System</h1>
        <Badge variant="outline" className="ml-auto">
          {breakingNewsList.filter((news: BreakingNews) => news.isActive).length} Active
        </Badge>
      </div>

      {/* Create New Breaking News */}
      <Card>
        <CardHeader>
          <CardTitle>Create Breaking News</CardTitle>
          <CardDescription>
            Generate TTS breaking news messages that can be inserted into any program block
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <Label htmlFor="message">Breaking News Message</Label>
              <Textarea
                id="message"
                value={newMessage}
                onChange={(e) => setNewMessage(e.target.value)}
                placeholder="Enter your breaking news message here..."
                className="min-h-[100px]"
                required
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <Label>Voice Type</Label>
                <Select value={selectedVoice} onValueChange={setSelectedVoice}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {voices.map(voice => (
                      <SelectItem key={voice.id} value={voice.id}>
                        {voice.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label>Priority</Label>
                <Select value={priority} onValueChange={setPriority}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {priorities.map(p => (
                      <SelectItem key={p.value} value={p.value}>
                        <div className="flex items-center gap-2">
                          <div className={`w-2 h-2 rounded-full ${p.color}`} />
                          {p.label}
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="flex items-end">
                <Button
                  type="button"
                  variant="outline"
                  onClick={handlePreview}
                  disabled={!newMessage.trim() || generatePreview.isPending}
                  className="w-full"
                >
                  {isPlaying ? (
                    <>
                      <Pause className="w-4 h-4 mr-2" />
                      Stop Preview
                    </>
                  ) : (
                    <>
                      <Play className="w-4 h-4 mr-2" />
                      Preview Voice
                    </>
                  )}
                </Button>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <Label htmlFor="scheduledFor">Schedule For (Optional)</Label>
                <Input
                  id="scheduledFor"
                  type="datetime-local"
                  value={scheduledFor}
                  onChange={(e) => setScheduledFor(e.target.value)}
                />
              </div>

              <div>
                <Label htmlFor="expiresAt">Expires At (Optional)</Label>
                <Input
                  id="expiresAt"
                  type="datetime-local"
                  value={expiresAt}
                  onChange={(e) => setExpiresAt(e.target.value)}
                />
              </div>
            </div>

            <Button 
              type="submit" 
              className="w-full bg-red-600 hover:bg-red-700"
              disabled={createBreakingNews.isPending || !newMessage.trim()}
            >
              Create Breaking News
            </Button>
          </form>
        </CardContent>
      </Card>

      {/* Active Breaking News */}
      <div className="grid gap-4">
        {breakingNewsList.map((news: BreakingNews) => (
          <Card key={news.id} className={`${!news.isActive ? 'opacity-60' : ''}`}>
            <CardContent className="p-4">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-2">
                    <Badge className={`${getPriorityColor(news.priority)} text-white`}>
                      {news.priority.toUpperCase()}
                    </Badge>
                    <span className="text-sm text-muted-foreground">
                      {voices.find(v => v.id === news.voiceType)?.name}
                    </span>
                    {news.scheduledFor && (
                      <div className="flex items-center gap-1 text-sm text-muted-foreground">
                        <Clock className="w-3 h-3" />
                        {new Date(news.scheduledFor).toLocaleString()}
                      </div>
                    )}
                  </div>

                  <p className="text-sm mb-3">{news.message}</p>

                  <div className="flex items-center gap-2">
                    {news.audioUrl && (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => {
                          const audio = new Audio(news.audioUrl);
                          audio.play();
                        }}
                      >
                        <Play className="w-3 h-3 mr-1" />
                        Play
                      </Button>
                    )}

                    {!news.insertedIntoSchedule && news.isActive && (
                      <Button
                        size="sm"
                        onClick={() => insertIntoSchedule.mutate(news.id)}
                        disabled={insertIntoSchedule.isPending}
                        className="bg-orange-600 hover:bg-orange-700"
                      >
                        <Calendar className="w-3 h-3 mr-1" />
                        Insert into Schedule
                      </Button>
                    )}

                    {news.insertedIntoSchedule && (
                      <Badge variant="secondary">
                        Scheduled
                      </Badge>
                    )}
                  </div>
                </div>

                <Button
                  size="sm"
                  variant="ghost"
                  onClick={() => deleteBreakingNews.mutate(news.id)}
                  disabled={deleteBreakingNews.isPending}
                  className="text-red-600 hover:bg-red-50"
                >
                  <Trash2 className="w-4 h-4" />
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {breakingNewsList.length === 0 && (
        <Card>
          <CardContent className="p-12 text-center">
            <AlertTriangle className="w-12 h-12 text-gray-400 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900 mb-2">No Breaking News</h3>
            <p className="text-gray-500">Create your first breaking news message above.</p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

