import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { 
  Card, 
  CardContent, 
  CardHeader, 
  CardTitle, 
  CardDescription 
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { Show, Episode, ModeratorMessage, insertShowSchema, insertEpisodeSchema, insertModeratorMessageSchema } from "@shared/schema";
import { 
  Radio, 
  Plus, 
  Trash2, 
  Edit, 
  Search, 
  AlertTriangle,
  MessageSquare,
  CalendarDays,
  Tag,
  AlarmCheck,
  Clock
} from "lucide-react";
import { AdminLayout } from "./index";

// Extended schema with client-side validation
const showFormSchema = z.object({
  title: z.string().min(1, "Title is required"),
  description: z.string().min(1, "Description is required"),
  hostName: z.string().optional(),
  scheduleTime: z.string().optional(),
  coverImage: z.string().url("Must be a valid URL").optional().or(z.literal("")),
  isFeatured: z.boolean().default(false),
});

const episodeFormSchema = z.object({
  showId: z.coerce.number().positive("Show must be selected"),
  title: z.string().min(1, "Title is required"),
  description: z.string().min(1, "Description is required"),
  audioUrl: z.string().url("Must be a valid URL"),
  duration: z.coerce.number().min(1, "Duration must be at least 1 second"),
  publishDate: z.string(), // Input as string, convert to Date when submitting
});

const messageFormSchema = z.object({
  content: z.string().min(1, "Content is required"),
  duration: z.coerce.number().min(5, "Duration must be at least 5 seconds"),
  type: z.string().min(1, "Type is required"),
  tags: z.array(z.string()).default([]),
});

export default function ContentManager() {
  const [activeTab, setActiveTab] = useState("shows");
  const [isShowFormOpen, setIsShowFormOpen] = useState(false);
  const [isEpisodeFormOpen, setIsEpisodeFormOpen] = useState(false);
  const [isMessageFormOpen, setIsMessageFormOpen] = useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [selectedShow, setSelectedShow] = useState<Show | null>(null);
  const [selectedEpisode, setSelectedEpisode] = useState<Episode | null>(null);
  const [selectedMessage, setSelectedMessage] = useState<ModeratorMessage | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [tagInput, setTagInput] = useState("");
  const [selectedTags, setSelectedTags] = useState<string[]>([]);

  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Show form
  const showForm = useForm<z.infer<typeof showFormSchema>>({
    resolver: zodResolver(showFormSchema),
    defaultValues: {
      title: "",
      description: "",
      hostName: "",
      scheduleTime: "",
      coverImage: "",
      isFeatured: false,
    },
  });

  // Episode form
  const episodeForm = useForm<z.infer<typeof episodeFormSchema>>({
    resolver: zodResolver(episodeFormSchema),
    defaultValues: {
      showId: 0,
      title: "",
      description: "",
      audioUrl: "",
      duration: 0,
      publishDate: new Date().toISOString().split('T')[0],
    },
  });

  // Message form
  const messageForm = useForm<z.infer<typeof messageFormSchema>>({
    resolver: zodResolver(messageFormSchema),
    defaultValues: {
      content: "",
      duration: 30,
      type: "announcement",
      tags: [],
    },
  });

  // Fetch shows
  const { data: shows, isLoading: isLoadingShows } = useQuery<Show[]>({
    queryKey: ['/api/shows'],
  });

  // Fetch episodes
  const { data: episodes, isLoading: isLoadingEpisodes } = useQuery<Episode[]>({
    queryKey: ['/api/episodes/recent'],
  });

  // Fetch moderator messages
  const { data: messages, isLoading: isLoadingMessages } = useQuery<ModeratorMessage[]>({
    queryKey: ['/api/messages'],
  });

  // Create show mutation
  const createShowMutation = useMutation({
    mutationFn: async (showData: z.infer<typeof showFormSchema>) => {
      const response = await apiRequest('POST', '/api/shows', showData);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/shows'] });
      setIsShowFormOpen(false);
      showForm.reset();
      toast({
        title: "Show Created",
        description: "The show has been successfully added.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to create show: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Update show mutation
  const updateShowMutation = useMutation({
    mutationFn: async ({ id, data }: { id: number, data: Partial<z.infer<typeof showFormSchema>> }) => {
      const response = await apiRequest('PUT', `/api/shows/${id}`, data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/shows'] });
      setIsShowFormOpen(false);
      setSelectedShow(null);
      showForm.reset();
      toast({
        title: "Show Updated",
        description: "The show has been successfully updated.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to update show: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Delete show mutation
  const deleteShowMutation = useMutation({
    mutationFn: async (id: number) => {
      await apiRequest('DELETE', `/api/shows/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/shows'] });
      setIsDeleteDialogOpen(false);
      setSelectedShow(null);
      toast({
        title: "Show Deleted",
        description: "The show has been successfully removed.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to delete show: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Create episode mutation
  const createEpisodeMutation = useMutation({
    mutationFn: async (episodeData: z.infer<typeof episodeFormSchema>) => {
      const formattedData = {
        ...episodeData,
        publishDate: new Date(episodeData.publishDate),
      };
      const response = await apiRequest('POST', '/api/episodes', formattedData);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/episodes/recent'] });
      setIsEpisodeFormOpen(false);
      episodeForm.reset();
      toast({
        title: "Episode Created",
        description: "The episode has been successfully added.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to create episode: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Create message mutation
  const createMessageMutation = useMutation({
    mutationFn: async (messageData: z.infer<typeof messageFormSchema>) => {
      const response = await apiRequest('POST', '/api/messages', messageData);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/messages'] });
      setIsMessageFormOpen(false);
      messageForm.reset();
      setSelectedTags([]);
      toast({
        title: "Message Created",
        description: "The moderator message has been successfully added.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to create message: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Handle show form submission
  const onSubmitShow = (data: z.infer<typeof showFormSchema>) => {
    if (selectedShow) {
      updateShowMutation.mutate({ id: selectedShow.id, data });
    } else {
      createShowMutation.mutate(data);
    }
  };

  // Handle episode form submission
  const onSubmitEpisode = (data: z.infer<typeof episodeFormSchema>) => {
    createEpisodeMutation.mutate(data);
  };

  // Handle message form submission
  const onSubmitMessage = (data: z.infer<typeof messageFormSchema>) => {
    createMessageMutation.mutate({
      ...data,
      tags: selectedTags,
    });
  };

  // Open show form for editing
  const handleEditShow = (show: Show) => {
    setSelectedShow(show);
    showForm.reset({
      title: show.title,
      description: show.description,
      hostName: show.hostName || "",
      scheduleTime: show.scheduleTime || "",
      coverImage: show.coverImage || "",
      isFeatured: show.isFeatured,
    });
    setIsShowFormOpen(true);
  };

  // Open delete confirmation
  const handleDeleteConfirm = (show: Show) => {
    setSelectedShow(show);
    setIsDeleteDialogOpen(true);
  };

  // Format duration as MM:SS
  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Add a tag to the selected tags
  const addTag = () => {
    if (tagInput.trim() && !selectedTags.includes(tagInput.trim())) {
      setSelectedTags([...selectedTags, tagInput.trim()]);
      setTagInput('');
    }
  };

  // Remove a tag from selected tags
  const removeTag = (tag: string) => {
    setSelectedTags(selectedTags.filter(t => t !== tag));
  };

  // Filter shows based on search query
  const filteredShows = shows?.filter(show => 
    show.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    show.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
    (show.hostName && show.hostName.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  return (
    <AdminLayout>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 md:px-8">
        <h1 className="text-2xl font-semibold text-gray-900 mb-6">Content Manager</h1>

        <Tabs defaultValue="shows" value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="mb-6">
            <TabsTrigger value="shows">Shows</TabsTrigger>
            <TabsTrigger value="episodes">Episodes</TabsTrigger>
            <TabsTrigger value="messages">Moderator Messages</TabsTrigger>
          </TabsList>

          {/* Shows Tab */}
          <TabsContent value="shows">
            <div className="flex justify-between items-center mb-4">
              <div className="relative w-64">
                <Search className="absolute left-2 top-1/2 transform -translate-y-1/2 text-gray-500" size={18} />
                <Input
                  placeholder="Search shows..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-10"
                />
              </div>
              <Button 
                onClick={() => {
                  setSelectedShow(null);
                  showForm.reset();
                  setIsShowFormOpen(true);
                }}
              >
                <Plus className="mr-2 h-4 w-4" /> Add Show
              </Button>
            </div>

            <Card>
              <CardContent className="p-0">
                {isLoadingShows ? (
                  <div className="flex justify-center items-center h-64">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
                  </div>
                ) : filteredShows?.length === 0 ? (
                  <div className="text-center py-10">
                    <Radio className="h-12 w-12 mx-auto text-gray-400" />
                    <h3 className="mt-2 text-sm font-medium text-gray-900">No shows found</h3>
                    <p className="mt-1 text-sm text-gray-500">
                      {searchQuery ? 'No shows match your search criteria.' : 'Get started by adding a new show.'}
                    </p>
                    <div className="mt-6">
                      <Button
                        onClick={() => {
                          setSelectedShow(null);
                          showForm.reset();
                          setIsShowFormOpen(true);
                        }}
                      >
                        <Plus className="mr-2 h-4 w-4" /> Add Show
                      </Button>
                    </div>
                  </div>
                ) : (
                  <div className="overflow-x-auto">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Title</TableHead>
                          <TableHead>Host</TableHead>
                          <TableHead>Schedule</TableHead>
                          <TableHead>Featured</TableHead>
                          <TableHead className="text-right">Actions</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {filteredShows?.map((show) => (
                          <TableRow key={show.id}>
                            <TableCell className="font-medium">{show.title}</TableCell>
                            <TableCell>{show.hostName || '—'}</TableCell>
                            <TableCell>{show.scheduleTime || '—'}</TableCell>
                            <TableCell>
                              {show.isFeatured ? (
                                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                                  Featured
                                </span>
                              ) : '—'}
                            </TableCell>
                            <TableCell className="text-right">
                              <Button 
                                variant="ghost" 
                                size="icon" 
                                onClick={() => handleEditShow(show)} 
                                className="h-8 w-8"
                              >
                                <Edit className="h-4 w-4" />
                              </Button>
                              <Button 
                                variant="ghost" 
                                size="icon" 
                                onClick={() => handleDeleteConfirm(show)} 
                                className="h-8 w-8 text-red-500 hover:text-red-700"
                              >
                                <Trash2 className="h-4 w-4" />
                              </Button>
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          {/* Episodes Tab */}
          <TabsContent value="episodes">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-medium">Recent Episodes</h2>
              <Button 
                onClick={() => {
                  setSelectedEpisode(null);
                  episodeForm.reset();
                  setIsEpisodeFormOpen(true);
                }}
              >
                <Plus className="mr-2 h-4 w-4" /> Add Episode
              </Button>
            </div>

            <Card>
              <CardContent className="p-0">
                {isLoadingEpisodes ? (
                  <div className="flex justify-center items-center h-64">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
                  </div>
                ) : episodes?.length === 0 ? (
                  <div className="text-center py-10">
                    <Radio className="h-12 w-12 mx-auto text-gray-400" />
                    <h3 className="mt-2 text-sm font-medium text-gray-900">No episodes found</h3>
                    <p className="mt-1 text-sm text-gray-500">
                      Get started by adding a new episode to one of your shows.
                    </p>
                    <div className="mt-6">
                      <Button
                        onClick={() => {
                          setSelectedEpisode(null);
                          episodeForm.reset();
                          setIsEpisodeFormOpen(true);
                        }}
                      >
                        <Plus className="mr-2 h-4 w-4" /> Add Episode
                      </Button>
                    </div>
                  </div>
                ) : (
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Title</TableHead>
                        <TableHead>Show</TableHead>
                        <TableHead>Duration</TableHead>
                        <TableHead>Published</TableHead>
                        <TableHead className="text-right">Actions</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {episodes?.map((episode) => {
                        const showTitle = shows?.find(s => s.id === episode.showId)?.title || 'Unknown Show';
                        return (
                          <TableRow key={episode.id}>
                            <TableCell className="font-medium">{episode.title}</TableCell>
                            <TableCell>{showTitle}</TableCell>
                            <TableCell>{formatDuration(episode.duration)}</TableCell>
                            <TableCell>
                              {new Date(episode.publishDate).toLocaleDateString()}
                            </TableCell>
                            <TableCell className="text-right">
                              <Button variant="ghost" size="icon" className="h-8 w-8">
                                <Edit className="h-4 w-4" />
                              </Button>
                              <Button variant="ghost" size="icon" className="h-8 w-8 text-red-500 hover:text-red-700">
                                <Trash2 className="h-4 w-4" />
                              </Button>
                            </TableCell>
                          </TableRow>
                        );
                      })}
                    </TableBody>
                  </Table>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          {/* Moderator Messages Tab */}
          <TabsContent value="messages">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-medium">Moderator Messages</h2>
              <Button 
                onClick={() => {
                  setSelectedMessage(null);
                  messageForm.reset();
                  setSelectedTags([]);
                  setIsMessageFormOpen(true);
                }}
              >
                <Plus className="mr-2 h-4 w-4" /> Add Message
              </Button>
            </div>

            <Card>
              <CardContent className="p-0">
                {isLoadingMessages ? (
                  <div className="flex justify-center items-center h-64">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
                  </div>
                ) : messages?.length === 0 ? (
                  <div className="text-center py-10">
                    <MessageSquare className="h-12 w-12 mx-auto text-gray-400" />
                    <h3 className="mt-2 text-sm font-medium text-gray-900">No messages found</h3>
                    <p className="mt-1 text-sm text-gray-500">
                      Add moderator messages to be played during broadcasts.
                    </p>
                    <div className="mt-6">
                      <Button
                        onClick={() => {
                          setSelectedMessage(null);
                          messageForm.reset();
                          setSelectedTags([]);
                          setIsMessageFormOpen(true);
                        }}
                      >
                        <Plus className="mr-2 h-4 w-4" /> Add Message
                      </Button>
                    </div>
                  </div>
                ) : (
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Content</TableHead>
                        <TableHead>Type</TableHead>
                        <TableHead>Duration</TableHead>
                        <TableHead>Tags</TableHead>
                        <TableHead className="text-right">Actions</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {messages?.map((message) => (
                        <TableRow key={message.id}>
                          <TableCell className="font-medium">
                            {message.content.length > 50 
                              ? `${message.content.substring(0, 50)}...` 
                              : message.content}
                          </TableCell>
                          <TableCell>
                            <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                              {message.type}
                            </span>
                          </TableCell>
                          <TableCell>{formatDuration(message.duration)}</TableCell>
                          <TableCell>
                            <div className="flex flex-wrap gap-1">
                              {(message.tags as string[]).map((tag, index) => (
                                <span 
                                  key={index}
                                  className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-gray-100 text-gray-800"
                                >
                                  {tag}
                                </span>
                              ))}
                            </div>
                          </TableCell>
                          <TableCell className="text-right">
                            <Button variant="ghost" size="icon" className="h-8 w-8">
                              <Edit className="h-4 w-4" />
                            </Button>
                            <Button variant="ghost" size="icon" className="h-8 w-8 text-red-500 hover:text-red-700">
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                )}
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>

        {/* Show Form Dialog */}
        <Dialog open={isShowFormOpen} onOpenChange={setIsShowFormOpen}>
          <DialogContent className="sm:max-w-lg">
            <DialogHeader>
              <DialogTitle>{selectedShow ? 'Edit Show' : 'Add New Show'}</DialogTitle>
              <DialogDescription>
                {selectedShow 
                  ? 'Update the show information.'
                  : 'Add a new show to your radio lineup.'}
              </DialogDescription>
            </DialogHeader>

            <Form {...showForm}>
              <form onSubmit={showForm.handleSubmit(onSubmitShow)} className="space-y-4">
                <FormField
                  control={showForm.control}
                  name="title"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Title *</FormLabel>
                      <FormControl>
                        <Input placeholder="Show title" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={showForm.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Description *</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="Show description" 
                          className="min-h-24" 
                          {...field} 
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="grid grid-cols-2 gap-4">
                  <FormField
                    control={showForm.control}
                    name="hostName"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Host Name</FormLabel>
                        <FormControl>
                          <Input placeholder="Host name (optional)" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={showForm.control}
                    name="scheduleTime"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Schedule Time</FormLabel>
                        <FormControl>
                          <Input placeholder="e.g., Daily • 8:00 PM" {...field} />
                        </FormControl>
                        <FormDescription>Format: Frequency • Time</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
