                <FormField
                  control={showForm.control}
                  name="isFeatured"
                  render={({ field }) => (
                    <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                      <div className="space-y-0.5">
                        <FormLabel className="text-base">Featured Show</FormLabel>
                        <FormDescription>
                          Feature this show on the homepage and in promotional areas
                        </FormDescription>
                      </div>
