import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Slider } from "@/components/ui/slider";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { queryClient } from "@/lib/queryClient";
import { Upload, Play, Pause, Calendar, Settings, Music, ShoppingBag, Clock, Trash2 } from "lucide-react";
import type { DjMix, InsertDjMix } from "@shared/schema";

export default function DjPanelPage() {
  const { toast } = useToast();
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [title, setTitle] = useState("");
  const [artist, setArtist] = useState("");
  const [description, setDescription] = useState("");
  const [genre, setGenre] = useState("");
  const [fadeInDuration, setFadeInDuration] = useState([5]);
  const [fadeOutDuration, setFadeOutDuration] = useState([5]);
  const [crossfadeMode, setCrossfadeMode] = useState("auto");
  const [isUploading, setIsUploading] = useState(false);

  const crossfadeModes = [
    { value: "auto", label: "Auto Crossfade", description: "Smooth automatic transitions" },
    { value: "manual", label: "Manual Cut Points", description: "Precise DJ-controlled cuts" },
    { value: "cut", label: "Hard Cut", description: "Immediate transitions" }
  ];

  const genres = [
    "House", "Techno", "Deep House", "Progressive", "Trance", "Ambient", 
    "Arabic Pop", "Fusion", "Jazz", "Electronic", "World Music", "Lounge"
  ];

  // Fetch DJ mixes
  const { data: djMixes = [], isLoading } = useQuery({
    queryKey: ['/api/dj-mixes']
  });

  // Upload DJ mix
  const uploadDjMix = useMutation({
    mutationFn: async (formData: FormData) => {
      setIsUploading(true);
      const response = await fetch('/api/dj-mixes/upload', {
        method: 'POST',
        body: formData
      });
      if (!response.ok) throw new Error('Failed to upload DJ mix');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/dj-mixes'] });
      toast({
        title: "DJ Mix Uploaded",
        description: "Mix has been processed and suggested products are being generated"
      });
      resetForm();
    },
    onSettled: () => {
      setIsUploading(false);
    }
  });

  // Schedule DJ mix
  const scheduleDjMix = useMutation({
    mutationFn: async ({ mixId, scheduleTime }: { mixId: number, scheduleTime: string }) => {
      const response = await fetch(`/api/dj-mixes/${mixId}/schedule`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ scheduleTime: new Date(scheduleTime) })
      });
      if (!response.ok) throw new Error('Failed to schedule DJ mix');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/dj-mixes'] });
      queryClient.invalidateQueries({ queryKey: ['/api/schedule'] });
      toast({
        title: "DJ Mix Scheduled",
        description: "Mix has been added to the program schedule with automatic block adjustments"
      });
    }
  });

  // Delete DJ mix
  const deleteDjMix = useMutation({
    mutationFn: async (id: number) => {
      const response = await fetch(`/api/dj-mixes/${id}`, {
        method: 'DELETE'
      });
      if (!response.ok) throw new Error('Failed to delete DJ mix');
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/dj-mixes'] });
      toast({
        title: "DJ Mix Deleted",
        description: "Mix has been removed from the system"
      });
    }
  });

  const resetForm = () => {
    setUploadFile(null);
    setTitle("");
    setArtist("");
    setDescription("");
    setGenre("");
    setFadeInDuration([5]);
    setFadeOutDuration([5]);
    setCrossfadeMode("auto");
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!uploadFile || !title || !artist) return;

    const formData = new FormData();
    formData.append('file', uploadFile);
    formData.append('title', title);
    formData.append('artist', artist);
    formData.append('description', description);
    formData.append('genre', genre);
    formData.append('fadeInDuration', fadeInDuration[0].toString());
    formData.append('fadeOutDuration', fadeOutDuration[0].toString());
    formData.append('crossfadeMode', crossfadeMode);

    uploadDjMix.mutate(formData);
  };

  const formatDuration = (seconds: number) => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    return hours > 0 ? `${hours}h ${minutes}m` : `${minutes}m`;
  };

  if (isLoading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Music className="h-6 w-6 text-purple-600" />
        <h1 className="text-2xl font-bold">DJ Panel - Music Flow Control</h1>
        <Badge variant="outline" className="ml-auto">
          {djMixes.filter((mix: DjMix) => mix.isScheduled).length} Scheduled
        </Badge>
      </div>

      {/* Upload New DJ Mix */}
      <Card>
        <CardHeader>
          <CardTitle>Upload DJ Mix</CardTitle>
          <CardDescription>
            Upload 2-3 hour DJ mixes that will be registered as full program blocks with automatic scheduling
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <Label htmlFor="file-upload">Audio File (MP3, WAV)</Label>
              <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-gray-300 border-dashed rounded-md">
                <div className="space-y-1 text-center">
                  <Upload className="mx-auto h-12 w-12 text-gray-400" />
                  <div className="flex text-sm text-gray-600">
                    <label htmlFor="file-upload" className="relative cursor-pointer bg-white rounded-md font-medium text-purple-600 hover:text-purple-500">
                      <span>Upload a file</span>
                      <input
                        id="file-upload"
                        type="file"
                        accept="audio/*"
                        className="sr-only"
                        onChange={(e) => setUploadFile(e.target.files?.[0] || null)}
                      />
                    </label>
                    <p className="pl-1">or drag and drop</p>
                  </div>
                  <p className="text-xs text-gray-500">MP3, WAV up to 500MB</p>
                  {uploadFile && (
                    <p className="text-sm text-green-600 font-medium">{uploadFile.name}</p>
                  )}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <Label htmlFor="title">Mix Title</Label>
                <Input
                  id="title"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="e.g., Sunday Deep House Session"
                  required
                />
              </div>

              <div>
                <Label htmlFor="artist">DJ Name</Label>
                <Input
                  id="artist"
                  value={artist}
                  onChange={(e) => setArtist(e.target.value)}
                  placeholder="e.g., DJ Omar"
                  required
                />
              </div>
            </div>

            <div>
              <Label htmlFor="description">Description</Label>
              <Textarea
                id="description"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                placeholder="Brief description of the mix style and content..."
                rows={3}
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <Label>Genre</Label>
                <Select value={genre} onValueChange={setGenre}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select genre" />
                  </SelectTrigger>
                  <SelectContent>
                    {genres.map(g => (
                      <SelectItem key={g} value={g.toLowerCase()}>
                        {g}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label>Crossfade Mode</Label>
                <Select value={crossfadeMode} onValueChange={setCrossfadeMode}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {crossfadeModes.map(mode => (
                      <SelectItem key={mode.value} value={mode.value}>
                        <div>
                          <div className="font-medium">{mode.label}</div>
                          <div className="text-xs text-muted-foreground">{mode.description}</div>
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <Label>Fade In Duration: {fadeInDuration[0]}s</Label>
                <Slider
                  value={fadeInDuration}
                  onValueChange={setFadeInDuration}
                  max={30}
                  min={0}
                  step={1}
                  className="mt-2"
                />
              </div>

              <div>
                <Label>Fade Out Duration: {fadeOutDuration[0]}s</Label>
                <Slider
                  value={fadeOutDuration}
                  onValueChange={setFadeOutDuration}
                  max={30}
                  min={0}
                  step={1}
                  className="mt-2"
                />
              </div>
            </div>

            <Button 
              type="submit" 
              className="w-full bg-purple-600 hover:bg-purple-700"
              disabled={isUploading || !uploadFile || !title || !artist}
            >
              {isUploading ? "Uploading..." : "Upload DJ Mix"}
            </Button>
          </form>
        </CardContent>
      </Card>

      {/* DJ Mix Library */}
      <div className="grid gap-4">
        {djMixes.map((mix: DjMix) => (
          <Card key={mix.id}>
            <CardContent className="p-4">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-2">
                    <h3 className="font-semibold">{mix.title}</h3>
                    <Badge variant="secondary">{mix.artist}</Badge>
                    {mix.genre && (
                      <Badge variant="outline">{mix.genre}</Badge>
                    )}
                    {mix.isScheduled && (
                      <Badge className="bg-green-600">Scheduled</Badge>
                    )}
                  </div>

                  {mix.description && (
                    <p className="text-sm text-muted-foreground mb-3">{mix.description}</p>
                  )}

                  <div className="flex items-center gap-4 text-sm text-muted-foreground mb-3">
                    <div className="flex items-center gap-1">
                      <Clock className="w-3 h-3" />
                      {formatDuration(mix.duration)}
                    </div>
                    <div className="flex items-center gap-1">
                      <Settings className="w-3 h-3" />
                      {crossfadeModes.find(m => m.value === mix.crossfadeMode)?.label}
                    </div>
                    <div>Fade: {mix.fadeInDuration}s / {mix.fadeOutDuration}s</div>
                  </div>

                  {mix.linkedProducts && Array.isArray(mix.linkedProducts) && mix.linkedProducts.length > 0 && (
                    <div className="flex items-center gap-2 mb-3">
                      <ShoppingBag className="w-4 h-4 text-green-600" />
                      <span className="text-sm text-green-600">
                        {mix.linkedProducts.length} suggested products
                      </span>
                    </div>
                  )}

                  <div className="flex items-center gap-2">
                    {mix.audioUrl && (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => {
                          const audio = new Audio(mix.audioUrl);
                          audio.play();
                        }}
                      >
                        <Play className="w-3 h-3 mr-1" />
                        Play
                      </Button>
                    )}

                    {!mix.isScheduled && (
                      <Button
                        size="sm"
                        onClick={() => {
                          const scheduleTime = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
                          scheduleDjMix.mutate({ mixId: mix.id, scheduleTime });
                        }}
                        disabled={scheduleDjMix.isPending}
                        className="bg-purple-600 hover:bg-purple-700"
                      >
                        <Calendar className="w-3 h-3 mr-1" />
                        Schedule Mix
                      </Button>
                    )}
                  </div>
                </div>

                <Button
                  size="sm"
                  variant="ghost"
                  onClick={() => deleteDjMix.mutate(mix.id)}
                  disabled={deleteDjMix.isPending}
                  className="text-red-600 hover:bg-red-50"
                >
                  <Trash2 className="w-4 h-4" />
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {djMixes.length === 0 && (
        <Card>
          <CardContent className="p-12 text-center">
            <Music className="w-12 h-12 text-gray-400 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900 mb-2">No DJ Mixes</h3>
            <p className="text-gray-500">Upload your first DJ mix to get started.</p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

