import { useState, useRef, useEffect } from "react";
import { Link } from "wouter";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { 
  Card, 
  CardContent, 
  CardHeader, 
  CardTitle, 
  CardDescription 
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { Track, Playlist, insertTrackSchema } from "@shared/schema";
import { 
  Music, 
  Plus, 
  Trash2, 
  Edit, 
  Play, 
  Pause,
  Search, 
  AlertTriangle,
  ArrowUpDown,
  ListMusic,
  ArrowLeft,
  Upload
} from "lucide-react";
import { AudioPreview } from "@/components/admin/AudioPreview";
import { AdminLayout } from "./index";

// Extended schema with client-side validation
const trackFormSchema = z.object({
  title: z.string().min(1, "Title is required"),
  artist: z.string().min(1, "Artist is required"),
  album: z.string().optional(),
  duration: z.coerce.number().min(1, "Duration must be at least 1 second"),
  url: z.string().url("Must be a valid URL"),
  coverArt: z.string().url("Must be a valid URL").optional().or(z.literal("")),
  genre: z.string().optional(),
  mood: z.string().optional(),
  tempo: z.coerce.number().optional(),
  year: z.coerce.number().optional(),
});

// File upload schema
const fileUploadSchema = z.object({
  audioFile: z.instanceof(File).optional(),
  imageFile: z.instanceof(File).optional(),
});

// Playlist form schema
const playlistFormSchema = z.object({
  name: z.string().min(1, "Playlist name is required"),
  description: z.string().optional(),
});

export default function MusicManager() {
  const [isTrackFormOpen, setIsTrackFormOpen] = useState(false);
  const [isPlaylistFormOpen, setIsPlaylistFormOpen] = useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [selectedTrack, setSelectedTrack] = useState<Track | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [sortConfig, setSortConfig] = useState<{
    key: keyof Track | "",
    direction: "ascending" | "descending"
  }>({ key: "", direction: "ascending" });
  const [uploadedFiles, setUploadedFiles] = useState<{
    audioUrl?: string;
    coverArt?: string;
    audioDuration?: number;
    audioFileName?: string;
    imageFileName?: string;
  }>({});
  const [isUploading, setIsUploading] = useState(false);
  const [nowPlaying, setNowPlaying] = useState<number | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);

  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Track form
  const trackForm = useForm<z.infer<typeof trackFormSchema>>({
    resolver: zodResolver(trackFormSchema),
    defaultValues: {
      title: "",
      artist: "",
      album: "",
      duration: 0,
      url: "",
      coverArt: "",
      genre: "",
      mood: "",
      tempo: 0,
      year: new Date().getFullYear(),
    },
  });

  // Playlist form
  const playlistForm = useForm<z.infer<typeof playlistFormSchema>>({
    resolver: zodResolver(playlistFormSchema),
    defaultValues: {
      name: "",
      description: "",
    },
  });

  // Fetch tracks
  const { data: tracks, isLoading: isLoadingTracks } = useQuery<Track[]>({
    queryKey: ['/api/tracks'],
  });

  // Fetch playlists
  const { data: playlists, isLoading: isLoadingPlaylists } = useQuery<Playlist[]>({
    queryKey: ['/api/playlists'],
  });

  // File upload mutation
  const uploadFilesMutation = useMutation({
    mutationFn: async (files: FormData) => {
      // Try to get audio duration if supported by browser
      const audioFile = files.get('audio') as File;

      // If we have an audio file, let's try to get its duration
      let audioDuration = 0;
      if (audioFile) {
        try {
          audioDuration = await new Promise<number>((resolve, reject) => {
            const audio = document.createElement('audio');
            audio.preload = 'metadata';

            audio.onloadedmetadata = () => {
              // Convert duration from seconds to integer seconds
              resolve(Math.round(audio.duration));
              URL.revokeObjectURL(audio.src);
            };

            audio.onerror = () => {
              reject("Failed to load audio metadata");
              URL.revokeObjectURL(audio.src);
            };

            audio.src = URL.createObjectURL(audioFile);
          });
        } catch (e) {
          console.error("Could not determine audio duration:", e);
        }
      }

      // Add duration to formData if available
      if (audioDuration > 0) {
        files.append('audioDuration', audioDuration.toString());
      }

      const response = await fetch('/api/upload', {
        method: 'POST',
        body: files,
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message || 'Failed to upload files');
      }

      return response.json();
    },
    onSuccess: (data) => {
      // Update the uploadedFiles state with all the response data
      setUploadedFiles({
        audioUrl: data.audioUrl,
        coverArt: data.coverArt,
        audioDuration: data.audioDuration,
        audioFileName: data.audioFileName,
        imageFileName: data.imageFileName
      });

      // Prefer using the signed URL if available, otherwise fall back to public URL
      if (data.signedAudioUrl || data.audioUrl) {
        trackForm.setValue('url', data.signedAudioUrl || data.audioUrl);

        // Use the duration from the server or our client-side duration
        if (data.audioDuration && data.audioDuration > 0) {
          trackForm.setValue('duration', data.audioDuration);
          console.log(`Setting duration to ${data.audioDuration} seconds`);
        } else {
          // Fallback to minimum duration - this should rarely happen with our extraction
          trackForm.setValue('duration', 1);
          console.log("Could not detect duration, setting to minimum value");
        }
      }

      if (data.coverArt) {
        trackForm.setValue('coverArt', data.coverArt);
      }

      // Apply AI-generated tags if available
      if (data.aiAnalysis) {
        const analysis = data.aiAnalysis;
        console.log('Applying AI analysis to form:', analysis);

        if (analysis.genre) trackForm.setValue('genre', analysis.genre);
        if (analysis.mood) trackForm.setValue('mood', analysis.mood);
        if (analysis.tempo) trackForm.setValue('tempo', analysis.tempo);
        if (analysis.energyLevel) trackForm.setValue('energyLevel', analysis.energyLevel);
        if (analysis.timeOfDayFit) trackForm.setValue('timeOfDayFit', analysis.timeOfDayFit);
        if (analysis.vocalType) trackForm.setValue('vocalType', analysis.vocalType);
        if (analysis.language) trackForm.setValue('language', analysis.language);
        if (analysis.culturalStyle) trackForm.setValue('culturalStyle', analysis.culturalStyle);
        if (analysis.aiTags) trackForm.setValue('aiTags', analysis.aiTags);

        // Mark as AI-tagged
        trackForm.setValue('isAiTagged', true);
      }

      // Show different toast messages depending on what was uploaded
      if (data.audioUrl && data.coverArt) {
        toast({
          title: "Files Uploaded",
          description: `Audio file (${formatDuration(data.audioDuration || 0)}) and cover art uploaded successfully.`,
        });
      } else if (data.audioUrl) {
        toast({
          title: "Audio Uploaded",
          description: `Audio file uploaded successfully. Duration: ${formatDuration(data.audioDuration || 0)}`,
        });
      } else if (data.coverArt) {
        toast({
          title: "Cover Art Uploaded",
          description: "Cover image has been uploaded successfully.",
        });
      }

      setIsUploading(false);
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to upload files: ${error}`,
        variant: "destructive",
      });
      setIsUploading(false);
    },
  });

  // Handle file upload
  const handleFileUpload = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const audioFile = formData.get('audio') as File;

    if (!audioFile || audioFile.size === 0) {
      toast({
        title: "Error",
        description: "Please select an audio file to upload",
        variant: "destructive",
      });
      return;
    }

    setIsUploading(true);
    uploadFilesMutation.mutate(formData);
  };

  // Create track mutation
  const createTrackMutation = useMutation({
    mutationFn: async (trackData: z.infer<typeof trackFormSchema>) => {
      const response = await apiRequest('POST', '/api/tracks', trackData);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/tracks'] });
      setIsTrackFormOpen(false);
      setUploadedFiles({});
      trackForm.reset();
      toast({
        title: "Track Created",
        description: "The track has been successfully added to the library.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to create track: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Update track mutation
  const updateTrackMutation = useMutation({
    mutationFn: async ({ id, data }: { id: number, data: Partial<z.infer<typeof trackFormSchema>> }) => {
      const response = await apiRequest('PUT', `/api/tracks/${id}`, data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/tracks'] });
      setIsTrackFormOpen(false);
      setSelectedTrack(null);
      trackForm.reset();
      toast({
        title: "Track Updated",
        description: "The track has been successfully updated.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to update track: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Delete track mutation
  const deleteTrackMutation = useMutation({
    mutationFn: async (id: number) => {
      await apiRequest('DELETE', `/api/tracks/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/tracks'] });
      setIsDeleteDialogOpen(false);
      setSelectedTrack(null);
      toast({
        title: "Track Deleted",
        description: "The track has been successfully removed from the library.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to delete track: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Create playlist mutation
  const createPlaylistMutation = useMutation({
    mutationFn: async (playlistData: z.infer<typeof playlistFormSchema>) => {
      const response = await apiRequest('POST', '/api/playlists', playlistData);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/playlists'] });
      setIsPlaylistFormOpen(false);
      playlistForm.reset();
      toast({
        title: "Playlist Created",
        description: "The playlist has been successfully created.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to create playlist: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Handle track form submission
  const onSubmitTrack = (data: z.infer<typeof trackFormSchema>) => {
    if (selectedTrack) {
      updateTrackMutation.mutate({ id: selectedTrack.id, data });
    } else {
      createTrackMutation.mutate(data);
    }
  };

  // Handle playlist form submission
  const onSubmitPlaylist = (data: z.infer<typeof playlistFormSchema>) => {
    createPlaylistMutation.mutate(data);
  };

  // Open track form for editing
  const handleEditTrack = (track: Track) => {
    setSelectedTrack(track);
    trackForm.reset({
      title: track.title,
      artist: track.artist,
      album: track.album || "",
      duration: track.duration,
      url: track.url,
      coverArt: track.coverArt || "",
      genre: track.genre || "",
      mood: track.mood || "",
      tempo: track.tempo || 0,
      year: track.year || new Date().getFullYear(),
    });
    setIsTrackFormOpen(true);
  };

  // Open delete confirmation
  const handleDeleteConfirm = (track: Track) => {
    setSelectedTrack(track);
    setIsDeleteDialogOpen(true);
  };

  // Format seconds as MM:SS
  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Filter tracks based on search query
  const filteredTracks = tracks?.filter(track => 
    track.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    track.artist.toLowerCase().includes(searchQuery.toLowerCase()) ||
    (track.album && track.album.toLowerCase().includes(searchQuery.toLowerCase())) ||
    (track.genre && track.genre.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  // Sort tracks
  const sortedTracks = filteredTracks && sortConfig.key ? [...filteredTracks].sort((a, b) => {
    const aValue = a[sortConfig.key as keyof Track];
    const bValue = b[sortConfig.key as keyof Track];

    // Handle null/undefined values
    if (aValue === null || aValue === undefined) return sortConfig.direction === "ascending" ? -1 : 1;
    if (bValue === null || bValue === undefined) return sortConfig.direction === "ascending" ? 1 : -1;

    // Compare based on value type
    if (typeof aValue === 'string' && typeof bValue === 'string') {
      return sortConfig.direction === "ascending" 
        ? aValue.localeCompare(bValue) 
        : bValue.localeCompare(aValue);
    }

    return sortConfig.direction === "ascending" 
      ? (aValue < bValue ? -1 : 1)
      : (aValue > bValue ? -1 : 1);
  }) : filteredTracks;

  // Handle column sorting
  const handleSort = (key: keyof Track) => {
    setSortConfig({
      key,
      direction: sortConfig.key === key && sortConfig.direction === "ascending" 
        ? "descending" 
        : "ascending"
    });
  };

  // Handle play/pause with AudioPreview integration
  const handlePlayPause = (trackId: number, trackUrl: string) => {
    // Toggle playing state for this track
    if (nowPlaying === trackId) {
      // If this track is already playing, stop it
      setNowPlaying(null);
      setIsPlaying(false);
    } else {
      // Mark this track as playing
      setNowPlaying(trackId);
      setIsPlaying(true);

      const track = tracks?.find(t => t.id === trackId);
      if (track) {
        toast({
          title: "Now Playing",
          description: `${track.title} by ${track.artist}`,
        });
      }
    }
  };

  return (
    <AdminLayout>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 md:px-8">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-semibold text-gray-900">Music Manager</h1>
          <Button variant="outline" onClick={() => window.location.href = '/admin'}>
            <ArrowLeft className="mr-2 h-4 w-4" /> Back to Admin
          </Button>
        </div>

        <Tabs defaultValue="library">
          <TabsList className="mb-6">
            <TabsTrigger value="library">Music Library</TabsTrigger>
            <TabsTrigger value="playlists">Playlists</TabsTrigger>
            <TabsTrigger value="analytics">Analytics</TabsTrigger>
          </TabsList>

          <TabsContent value="library">
            <div className="flex justify-between items-center mb-4">
              <div className="relative w-64">
                <Search className="absolute left-2 top-1/2 transform -translate-y-1/2 text-gray-500" size={18} />
                <Input
                  placeholder="Search tracks..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-10"
                />
              </div>
              <Button 
                onClick={() => {
                  setSelectedTrack(null);
                  trackForm.reset();
                  setIsTrackFormOpen(true);
                }}
              >
                <Plus className="mr-2 h-4 w-4" /> Add Track
              </Button>
            </div>

            <Card>
              <CardContent className="p-0">
                {isLoadingTracks ? (
                  <div className="flex justify-center items-center h-64">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
                  </div>
                ) : sortedTracks?.length === 0 ? (
                  <div className="text-center py-10">
                    <Music className="h-12 w-12 mx-auto text-gray-400" />
                    <h3 className="mt-2 text-sm font-medium text-gray-900">No tracks found</h3>
                    <p className="mt-1 text-sm text-gray-500">
                      {searchQuery ? 'No tracks match your search criteria.' : 'Get started by adding a new track.'}
                    </p>
                    <div className="mt-6">
                      <Button
                        onClick={() => {
                          setSelectedTrack(null);
                          trackForm.reset();
                          setIsTrackFormOpen(true);
                        }}
                      >
                        <Plus className="mr-2 h-4 w-4" /> Add Track
                      </Button>
                    </div>
                  </div>
                ) : (
                  <div className="overflow-x-auto">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead className="w-10"></TableHead>
                          <TableHead className="cursor-pointer" onClick={() => handleSort('title')}>
                            <div className="flex items-center">
                              Title
                              {sortConfig.key === 'title' && (
                                <ArrowUpDown className="ml-1 h-4 w-4" />
                              )}
                            </div>
                          </TableHead>
                          <TableHead className="cursor-pointer" onClick={() => handleSort('artist')}>
                            <div className="flex items-center">
                              Artist
                              {sortConfig.key === 'artist' && (
                                <ArrowUpDown className="ml-1 h-4 w-4" />
                              )}
                            </div>
                          </TableHead>
                          <TableHead>Album</TableHead>
                          <TableHead className="cursor-pointer" onClick={() => handleSort('duration')}>
                            <div className="flex items-center">
                              Duration
                              {sortConfig.key === 'duration' && (
                                <ArrowUpDown className="ml-1 h-4 w-4" />
                              )}
                            </div>
                          </TableHead>
                          <TableHead>Genre</TableHead>
                          <TableHead>Mood</TableHead>
                          <TableHead className="text-right">Actions</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {sortedTracks?.map((track) => (
                          <TableRow key={track.id}>
                            <TableCell>
                              {nowPlaying === track.id ? (
                                <AudioPreview 
                                  url={track.url} 
                                  size="sm"
                                  onPlay={() => setIsPlaying(true)}
                                  onStop={() => {
                                    setIsPlaying(false);
                                    setNowPlaying(null);
                                  }}
                                />
                              ) : (
                                <Button 
                                  variant="ghost" 
                                  size="icon" 
                                  className="h-8 w-8"
                                  onClick={() => handlePlayPause(track.id, track.url)}
                                >
                                  <Play className="h-4 w-4" />
                                </Button>
                              )}
                            </TableCell>
                            <TableCell className="font-medium">{track.title}</TableCell>
                            <TableCell>{track.artist}</TableCell>
                            <TableCell>{track.album || '—'}</TableCell>
                            <TableCell>{formatDuration(track.duration)}</TableCell>
                            <TableCell>{track.genre || '—'}</TableCell>
                            <TableCell>{track.mood || '—'}</TableCell>
                            <TableCell className="text-right">
                              <Button 
                                variant="ghost" 
                                size="icon" 
                                onClick={() => handleEditTrack(track)} 
                                className="h-8 w-8"
                              >
                                <Edit className="h-4 w-4" />
                              </Button>
                              <Button 
                                variant="ghost" 
                                size="icon" 
                                onClick={() => handleDeleteConfirm(track)} 
                                className="h-8 w-8 text-red-500 hover:text-red-700"
                              >
                                <Trash2 className="h-4 w-4" />
                              </Button>
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="playlists">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-medium">Manage Playlists</h2>
              <Button onClick={() => setIsPlaylistFormOpen(true)}>
                <Plus className="mr-2 h-4 w-4" /> Create Playlist
              </Button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {isLoadingPlaylists ? (
                Array(3).fill(0).map((_, i) => (
                  <Card key={i} className="h-48 animate-pulse">
                    <CardContent className="p-6">
                      <div className="h-5 w-2/3 bg-gray-200 rounded mb-4"></div>
                      <div className="h-4 w-3/4 bg-gray-200 rounded mb-2"></div>
                      <div className="h-4 w-1/2 bg-gray-200 rounded mb-6"></div>
                      <div className="h-8 w-24 bg-gray-200 rounded"></div>
                    </CardContent>
                  </Card>
                ))
              ) : playlists?.length === 0 ? (
                <div className="col-span-full text-center py-10">
                  <ListMusic className="h-12 w-12 mx-auto text-gray-400" />
                  <h3 className="mt-2 text-sm font-medium text-gray-900">No playlists</h3>
                  <p className="mt-1 text-sm text-gray-500">
                    Create your first playlist to organize your tracks.
                  </p>
                  <div className="mt-6">
                    <Button onClick={() => setIsPlaylistFormOpen(true)}>
                      <Plus className="mr-2 h-4 w-4" /> Create Playlist
                    </Button>
                  </div>
                </div>
              ) : (
                playlists?.map((playlist) => (
                  <Card key={playlist.id}>
                    <CardHeader>
                      <CardTitle>{playlist.name}</CardTitle>
                      <CardDescription>
                        {playlist.description || 'No description provided'}
                      </CardDescription>
                    </CardHeader>
                    <CardContent>
                      <Button variant="outline" className="mr-2"
                        onClick={() => toast({
                          title: "Coming Soon",
                          description: "Playlist playback functionality is coming soon.",
                        })}
                      >
                        <Play className="mr-2 h-4 w-4" /> Play
                      </Button>
                      <Button variant="outline"
                        onClick={() => toast({
                          title: "Coming Soon",
                          description: "Playlist editing functionality is coming soon.",
                        })}
                      >
                        <Edit className="mr-2 h-4 w-4" /> Edit
                      </Button>
                    </CardContent>
                  </Card>
                ))
              )}
            </div>
          </TabsContent>

          <TabsContent value="analytics">
            <Card>
              <CardHeader>
                <CardTitle>Track Analytics</CardTitle>
                <CardDescription>
                  Coming soon: Track play counts, popularity metrics, and listener feedback.
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="text-center py-8">
                  <p className="text-gray-500">Analytics features are under development.</p>
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>

        {/* Track Form Dialog */}
        <Dialog open={isTrackFormOpen} onOpenChange={setIsTrackFormOpen}>
          <DialogContent className="sm:max-w-lg max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>{selectedTrack ? 'Edit Track' : 'Add New Track'}</DialogTitle>
              <DialogDescription>
                {selectedTrack 
                  ? 'Update the track information in your music library.'
                  : 'Add a new track to your music library.'}
              </DialogDescription>
            </DialogHeader>

            {!selectedTrack && (
              <div className="mb-6 p-4 border rounded-md bg-gray-50">
                <h3 className="font-medium mb-2">Upload Media Files</h3>
                <form onSubmit={handleFileUpload} className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium mb-1">Audio File (Required)</label>
                    <input 
                      type="file" 
                      name="audio" 
                      accept="audio/*"
                      className="w-full border rounded-md p-2"
                      required
                    />
                    <p className="text-xs text-gray-500 mt-1">
                      File will be uploaded to Cloudflare R2 storage. Duration will be automatically extracted.
                    </p>
                  </div>

                  <div>
                    <label className="block text-sm font-medium mb-1">Cover Image (Optional)</label>
                    <input 
                      type="file" 
                      name="image" 
                      accept="image/*"
                      className="w-full border rounded-md p-2"
                    />
                    <p className="text-xs text-gray-500 mt-1">
                      Image will be uploaded to Cloudflare R2 storage.
                    </p>
                  </div>

                  <Button 
                    type="submit"
                    disabled={isUploading}
                    className="w-full"
                  >
                    {isUploading ? (
                      <>
                        <div className="animate-spin mr-2 h-4 w-4 border-b-2 rounded-full border-white"></div>
                        Uploading to R2 Storage...
                      </>
                    ) : (
                      "Upload Files"
                    )}
                  </Button>

                  {(uploadedFiles.audioUrl || uploadedFiles.coverArt) && (
                    <div className="p-3 bg-green-50 text-green-700 text-sm rounded border border-green-200">
                      <h4 className="font-semibold mb-2">Uploaded Files</h4>

                      {uploadedFiles.audioUrl && (
                        <div className="mb-2">
                          <div className="flex items-center">
                            <div className="h-3 w-3 bg-green-600 rounded-full mr-2"></div>
                            <p className="font-medium">Audio</p>
                          </div>
                          <p className="text-xs ml-5 mt-1 text-gray-600">{uploadedFiles.audioFileName}</p>
                          {uploadedFiles.audioDuration && (
                            <p className="text-xs ml-5 text-gray-600">Duration: {formatDuration(uploadedFiles.audioDuration)}</p>
                          )}
                        </div>
                      )}

                      {uploadedFiles.coverArt && (
                        <div>
                          <div className="flex items-center">
                            <div className="h-3 w-3 bg-green-600 rounded-full mr-2"></div>
                            <p className="font-medium">Cover Image</p>
                          </div>
                          <p className="text-xs ml-5 mt-1 text-gray-600">{uploadedFiles.imageFileName}</p>
                        </div>
                      )}
                    </div>
                  )}
                </form>
              </div>
            )}

            <Form {...trackForm}>
              <form onSubmit={trackForm.handleSubmit(onSubmitTrack)} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <FormField
                    control={trackForm.control}
                    name="title"
                    render={({ field }) => (
                      <FormItem className="col-span-2">
                        <FormLabel>Title *</FormLabel>
                        <FormControl>
                          <Input placeholder="Track title" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={trackForm.control}
                    name="artist"
                    render={({ field }) => (
                      <FormItem className="col-span-2">
                        <FormLabel>Artist *</FormLabel>
                        <FormControl>
                          <Input placeholder="Artist name" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={trackForm.control}
                    name="album"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Album</FormLabel>
                        <FormControl>
                          <Input placeholder="Album name (optional)" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={trackForm.control}
                    name="duration"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Duration (seconds) *</FormLabel>
                        <FormControl>
                          <Input 
                            type="number" 
                            min="1" 
                            placeholder={isUploading ? "Detecting duration..." : "Duration in seconds"} 
                            {...field} 
                            disabled={isUploading}
                            className={uploadedFiles.audioDuration ? "bg-gray-50" : ""}
                          />
                        </FormControl>
                        <FormDescription>
                          {uploadedFiles.audioDuration ? 
                            `Duration detected: ${formatDuration(uploadedFiles.audioDuration)}` : 
                            "Duration will be automatically detected on upload"
                          }
                        </FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={trackForm.control}
                    name="url"
                    render={({ field }) => (
                      <FormItem className="col-span-2">
                        <FormLabel>Audio URL *</FormLabel>
                        <div className="flex flex-col space-y-2">
                          <div className="flex items-center gap-2">
                            <FormControl className="flex-1">
                              <Input 
                                placeholder="https://example.com/audio.mp3" 
                                {...field} 
                                disabled={!!uploadedFiles.audioUrl}
                                className={uploadedFiles.audioUrl ? "bg-gray-50" : ""}
                              />
                            </FormControl>
                            {field.value && (
                              <AudioPreview 
                                url={field.value} 
                                size="sm"
                              />
                            )}
                          </div>
                          {!selectedTrack && !uploadedFiles.audioUrl && (
                            <div 
                              className="flex items-center space-x-2 rounded-md border p-2 bg-slate-50 cursor-pointer"
                              onDrop={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                if (e.dataTransfer.files && e.dataTransfer.files[0]) {
                                  const formData = new FormData();
                                  formData.append('audio', e.dataTransfer.files[0]);
                                  setIsUploading(true);
                                  uploadFilesMutation.mutate(formData);
                                }
                              }}
                              onDragOver={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                              }}
                              onDragEnter={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                e.currentTarget.classList.add('border-primary');
                              }}
                              onDragLeave={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                e.currentTarget.classList.remove('border-primary');
                              }}
                            >
                              <Upload className="h-4 w-4 text-gray-500" />
                              <div className="flex-1">
                                <label htmlFor="audio-upload" className="text-sm font-medium cursor-pointer text-blue-600 hover:text-blue-800">
                                  Upload Audio File
                                </label>
                                <input 
                                  id="audio-upload" 
                                  type="file" 
                                  name="audio" 
                                  accept="audio/*"
                                  className="hidden"
                                  onChange={(e) => {
                                    if (e.target.files && e.target.files[0]) {
                                      const formData = new FormData();
                                      formData.append('audio', e.target.files[0]);
                                      setIsUploading(true);
                                      uploadFilesMutation.mutate(formData);
                                    }
                                  }}
                                />
                                <p className="text-xs text-gray-500">or drag and drop</p>
                              </div>
                            </div>
                          )}
                        </div>
                        <FormDescription>
                          {!selectedTrack && !uploadedFiles.audioUrl 
                            ? "Upload an audio file or enter a URL directly" 
                            : "URL to the audio file"}
                        </FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={trackForm.control}
                    name="coverArt"
                    render={({ field }) => (
                      <FormItem className="col-span-2">
                        <FormLabel>Cover Art URL</FormLabel>
                        <div className="flex flex-col space-y-2">
                          <FormControl>
                            <Input 
                              placeholder="https://example.com/cover.jpg" 
                              {...field} 
                              disabled={!!uploadedFiles.coverArt}
                              className={uploadedFiles.coverArt ? "bg-gray-50" : ""}
                            />
                          </FormControl>
                          {!selectedTrack && !uploadedFiles.coverArt && (
                            <div 
                              className="flex items-center space-x-2 rounded-md border p-2 bg-slate-50 cursor-pointer"
                              onDrop={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                if (e.dataTransfer.files && e.dataTransfer.files[0]) {
                                  const formData = new FormData();
                                  formData.append('image', e.dataTransfer.files[0]);
                                  setIsUploading(true);
                                  uploadFilesMutation.mutate(formData);
                                }
                              }}
                              onDragOver={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                              }}
                              onDragEnter={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                e.currentTarget.classList.add('border-primary');
                              }}
                              onDragLeave={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                e.currentTarget.classList.remove('border-primary');
                              }}
                            >
                              <Upload className="h-4 w-4 text-gray-500" />
                              <div className="flex-1">
                                <label htmlFor="image-upload" className="text-sm font-medium cursor-pointer text-blue-600 hover:text-blue-800">
                                  Upload Cover Art
                                </label>
                                <input 
                                  id="image-upload" 
                                  type="file" 
                                  name="image" 
                                  accept="image/*"
                                  className="hidden"
                                  onChange={(e) => {
                                    if (e.target.files && e.target.files[0]) {
                                      const formData = new FormData();
                                      formData.append('image', e.target.files[0]);
                                      setIsUploading(true);
                                      uploadFilesMutation.mutate(formData);
                                    }
                                  }}
                                />
                                <p className="text-xs text-gray-500">or drag and drop</p>
                              </div>
                            </div>
                          )}
                        </div>
                        <FormDescription>URL to the cover art image (optional)</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={trackForm.control}
                    name="genre"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Genre</FormLabel>
                        <Select 
                          onValueChange={field.onChange} 
                          defaultValue={field.value}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Select genre" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="Electronic">Electronic</SelectItem>
                            <SelectItem value="Pop">Pop</SelectItem>
                            <SelectItem value="Rock">Rock</SelectItem>
                            <SelectItem value="Hip Hop">Hip Hop</SelectItem>
                            <SelectItem value="RnB">RnB</SelectItem>
                            <SelectItem value="Jazz">Jazz</SelectItem>
                            <SelectItem value="Classical">Classical</SelectItem>
                            <SelectItem value="World">World</SelectItem>
                            <SelectItem value="Lounge">Lounge</SelectItem>
                            <SelectItem value="Ambient">Ambient</SelectItem>
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={trackForm.control}
                    name="mood"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Mood</FormLabel>
                        <Select 
                          onValueChange={field.onChange} 
                          defaultValue={field.value}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Select mood" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="upbeat">Upbeat</SelectItem>
                            <SelectItem value="relaxed">Relaxed</SelectItem>
                            <SelectItem value="energetic">Energetic</SelectItem>
                            <SelectItem value="chill">Chill</SelectItem>
                            <SelectItem value="romantic">Romantic</SelectItem>
                            <SelectItem value="melancholic">Melancholic</SelectItem>
                            <SelectItem value="happy">Happy</SelectItem>
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={trackForm.control}
                    name="tempo"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Tempo (BPM)</FormLabel>
                        <FormControl>
                          <Input 
                            type="number" 
                            min="0" 
                            placeholder="Beats per minute" 
                            {...field} 
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={trackForm.control}
                    name="year"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Year</FormLabel>
                        <FormControl>
                          <Input 
                            type="number" 
                            min="1900" 
                            max={new Date().getFullYear()} 
                            placeholder="Release year" 
                            {...field} 
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <DialogFooter>
                  <Button 
                    type="button" 
                    variant="outline" 
                    onClick={() => setIsTrackFormOpen(false)}
                  >
                    Cancel
                  </Button>
                  <Button 
                    type="submit" 
                    disabled={
                      createTrackMutation.isPending || 
                      updateTrackMutation.isPending || 
                      (!selectedTrack && !trackForm.getValues().url)
                    }
                  >
                    {(createTrackMutation.isPending || updateTrackMutation.isPending) 
                      ? 'Saving...' 
                      : selectedTrack ? 'Update Track' : 'Add Track'
                    }
                  </Button>
                </DialogFooter>
              </form>
            </Form>
          </DialogContent>
        </Dialog>

        {/* Playlist Form Dialog */}
        <Dialog open={isPlaylistFormOpen} onOpenChange={setIsPlaylistFormOpen}>
          <DialogContent className="sm:max-w-md">
            <DialogHeader>
              <DialogTitle>Create New Playlist</DialogTitle>
              <DialogDescription>
                Create a new playlist to organize your tracks.
              </DialogDescription>
            </DialogHeader>

            <Form {...playlistForm}>
              <form onSubmit={playlistForm.handleSubmit(onSubmitPlaylist)} className="space-y-4">
                <FormField
                  control={playlistForm.control}
                  name="name"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Playlist Name *</FormLabel>
                      <FormControl>
                        <Input placeholder="My Awesome Playlist" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={playlistForm.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Description</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="A short description of this playlist" 
                          {...field} 
                        />
                      </FormControl>
                      <FormDescription>Optional description for your playlist</FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <DialogFooter>
                  <Button 
                    type="button" 
                    variant="outline" 
                    onClick={() => setIsPlaylistFormOpen(false)}
                  >
                    Cancel
                  </Button>
                  <Button 
                    type="submit" 
                    disabled={createPlaylistMutation.isPending}
                  >
                    {createPlaylistMutation.isPending ? 'Creating...' : 'Create Playlist'}
                  </Button>
                </DialogFooter>
              </form>
            </Form>
          </DialogContent>
        </Dialog>

        {/* Delete Confirmation Dialog */}
        <Dialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
          <DialogContent className="sm:max-w-md">
            <DialogHeader>
              <DialogTitle className="flex items-center">
                <AlertTriangle className="h-5 w-5 text-red-500 mr-2" />
                Confirm Deletion
              </DialogTitle>
              <DialogDescription>
                Are you sure you want to delete the track{" "}
                <span className="font-medium">{selectedTrack?.title}</span>? This action cannot be undone.
              </DialogDescription>
            </DialogHeader>

            <DialogFooter>
              <Button 
                type="button" 
                variant="outline" 
                onClick={() => setIsDeleteDialogOpen(false)}
              >
                Cancel
              </Button>
              <Button 
                variant="destructive" 
                onClick={() => selectedTrack && deleteTrackMutation.mutate(selectedTrack.id)}
                disabled={deleteTrackMutation.isPending}
              >
                {deleteTrackMutation.isPending ? 'Deleting...' : 'Delete Track'}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </AdminLayout>
  );
}

