import { useState, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useRoute } from "wouter";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Calendar } from "@/components/ui/calendar";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "@/hooks/use-toast";
import { 
  Calendar as CalendarIcon, 
  Upload, 
  FileText, 
  Mic, 
  Play, 
  PlusCircle, 
  Edit, 
  User, 
  Clock,
  Target,
  Headphones,
  Settings,
  BookOpen,
  MessageSquare,
  TrendingUp,
  Archive
} from "lucide-react";

interface PodcastFormat {
  id: number;
  name: string;
  category: string;
  description: string;
  colorCode?: string;
  moderatorId?: number;
  targetDuration: number;
  frequency: string; // daily, weekly, monthly
  timeSlot: string;
}

interface PodcastEpisode {
  id: number;
  formatId: number;
  title: string;
  description: string;
  scheduledDate: Date;
  status: 'planned' | 'recorded' | 'published';
  topics: string[];
  materials: string[];
  notes: string;
  duration?: number;
}

interface ContentMaterial {
  id: number;
  formatId: number;
  filename: string;
  type: 'text' | 'audio' | 'script';
  uploadDate: Date;
  processed: boolean;
}

export default function PodcastPlanner() {
  const [match, params] = useRoute("/admin/podcast-planner/:formatId");
  const formatId = params?.formatId ? parseInt(params.formatId) : null;

  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [selectedEpisode, setSelectedEpisode] = useState<PodcastEpisode | null>(null);
  const [isEpisodeDialogOpen, setIsEpisodeDialogOpen] = useState(false);
  const [newTopicText, setNewTopicText] = useState("");
  const [uploadingMaterial, setUploadingMaterial] = useState(false);

  const queryClient = useQueryClient();

  // Fetch format details
  const { data: format } = useQuery<PodcastFormat>({
    queryKey: ['/api/program-formats', formatId],
    enabled: !!formatId,
  });

  // Fetch moderator details
  const { data: moderator } = useQuery({
    queryKey: ['/api/moderators', format?.moderatorId],
    enabled: !!format?.moderatorId,
  });

  // Fetch episodes for this format
  const { data: episodes = [] } = useQuery<PodcastEpisode[]>({
    queryKey: ['/api/podcast-episodes', formatId],
    enabled: !!formatId,
  });

  // Fetch content materials
  const { data: materials = [] } = useQuery<ContentMaterial[]>({
    queryKey: ['/api/podcast-materials', formatId],
    enabled: !!formatId,
  });

  // Create/update episode
  const episodeMutation = useMutation({
    mutationFn: async (episodeData: Partial<PodcastEpisode>) => {
      const url = selectedEpisode 
        ? `/api/podcast-episodes/${selectedEpisode.id}` 
        : '/api/podcast-episodes';
      const method = selectedEpisode ? 'PUT' : 'POST';
      const response = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...episodeData, formatId }),
      });
      if (!response.ok) throw new Error('Failed to save episode');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/podcast-episodes', formatId] });
      setIsEpisodeDialogOpen(false);
      setSelectedEpisode(null);
      toast({
        title: "Success",
        description: "Episode saved successfully",
      });
    },
  });

  // Upload material
  const uploadMaterial = async (file: File) => {
    setUploadingMaterial(true);
    const formData = new FormData();
    formData.append('file', file);
    formData.append('formatId', formatId?.toString() || '');

    try {
      const response = await fetch('/api/podcast-materials', {
        method: 'POST',
        body: formData,
      });
      if (!response.ok) throw new Error('Upload failed');

      queryClient.invalidateQueries({ queryKey: ['/api/podcast-materials', formatId] });
      toast({
        title: "Upload Successful",
        description: `${file.name} has been uploaded and will be processed`,
      });
    } catch (error) {
      toast({
        title: "Upload Failed",
        description: "Please try again",
        variant: "destructive",
      });
    } finally {
      setUploadingMaterial(false);
    }
  };

  // Get episodes for selected date
  const getEpisodesForDate = (date: Date) => {
    return episodes.filter(episode => {
      const episodeDate = new Date(episode.scheduledDate);
      return episodeDate.toDateString() === date.toDateString();
    });
  };

  // Generate month view calendar
  const generateMonthCalendar = () => {
    const today = new Date();
    const currentMonth = today.getMonth();
    const currentYear = today.getFullYear();
    const daysInMonth = new Date(currentYear, currentMonth + 1, 0).getDate();
    const calendar = [];

    for (let day = 1; day <= daysInMonth; day++) {
      const date = new Date(currentYear, currentMonth, day);
      const dayEpisodes = getEpisodesForDate(date);
      calendar.push({
        date,
        episodes: dayEpisodes,
        hasContent: dayEpisodes.length > 0
      });
    }
    return calendar;
  };

  if (!formatId || !format) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-center">
          <Headphones className="h-12 w-12 mx-auto text-gray-400 mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No Format Selected</h3>
          <p className="text-gray-500">Please select a podcast format to manage</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-white border rounded-lg p-6">
        <div className="flex items-start justify-between">
          <div className="flex space-x-4">
            <div className={`w-16 h-16 rounded-lg ${format.colorCode ? `bg-${format.colorCode}-100` : 'bg-gray-100'} flex items-center justify-center`}>
              <Mic className={`h-8 w-8 ${format.colorCode ? `text-${format.colorCode}-600` : 'text-gray-600'}`} />
            </div>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">{format.name}</h1>
              <p className="text-gray-600 mt-1">{format.description}</p>
              <div className="flex items-center space-x-4 mt-2">
                <Badge variant="outline">{format.category}</Badge>
                <span className="text-sm text-gray-500">
                  <Clock className="h-4 w-4 inline mr-1" />
                  {format.targetDuration} min • {format.frequency}
                </span>
                <span className="text-sm text-gray-500">{format.timeSlot}</span>
              </div>
            </div>
          </div>

          {moderator && (
            <div className="text-right">
              <div className="flex items-center space-x-2 mb-2">
                <User className="h-4 w-4 text-gray-400" />
                <span className="font-medium">{moderator.name}</span>
              </div>
              <p className="text-sm text-gray-600">{moderator.style}</p>
            </div>
          )}
        </div>
      </div>

      <Tabs defaultValue="calendar" className="space-y-6">
        <TabsList className="grid w-full grid-cols-5">
          <TabsTrigger value="calendar">Calendar</TabsTrigger>
          <TabsTrigger value="content">Content Bank</TabsTrigger>
          <TabsTrigger value="topics">Topic Planning</TabsTrigger>
          <TabsTrigger value="analytics">Analytics</TabsTrigger>
          <TabsTrigger value="settings">Settings</TabsTrigger>
        </TabsList>

        {/* Calendar View */}
        <TabsContent value="calendar" className="space-y-6">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Monthly Calendar */}
            <div className="lg:col-span-2">
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center justify-between">
                    Monthly Schedule
                    <Button onClick={() => setIsEpisodeDialogOpen(true)}>
                      <PlusCircle className="h-4 w-4 mr-2" />
                      New Episode
                    </Button>
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-7 gap-2 mb-4">
                    {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                      <div key={day} className="p-2 text-center text-sm font-medium text-gray-500">
                        {day}
                      </div>
                    ))}
                  </div>
                  <div className="grid grid-cols-7 gap-2">
                    {generateMonthCalendar().map((day, index) => (
                      <div
                        key={index}
                        className={`p-2 h-20 border rounded cursor-pointer hover:bg-gray-50 ${
                          day.hasContent ? 'bg-blue-50 border-blue-200' : ''
                        } ${
                          day.date.toDateString() === selectedDate.toDateString() 
                            ? 'ring-2 ring-blue-500' : ''
                        }`}
                        onClick={() => setSelectedDate(day.date)}
                      >
                        <div className="text-sm font-medium">{day.date.getDate()}</div>
                        {day.episodes.map((episode, episodeIndex) => (
                          <div key={episodeIndex} className="text-xs mt-1 p-1 bg-blue-100 rounded truncate">
                            {episode.title}
                          </div>
                        ))}
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>
            </div>

            {/* Selected Day Details */}
            <div>
              <Card>
                <CardHeader>
                  <CardTitle className="text-lg">
                    {selectedDate.toLocaleDateString('en-US', { 
                      weekday: 'long', 
                      month: 'long', 
                      day: 'numeric' 
                    })}
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  {getEpisodesForDate(selectedDate).length > 0 ? (
                    <div className="space-y-3">
                      {getEpisodesForDate(selectedDate).map(episode => (
                        <div key={episode.id} className="p-3 border rounded-lg">
                          <div className="flex items-center justify-between mb-2">
                            <h4 className="font-medium">{episode.title}</h4>
                            <Badge 
                              variant={
                                episode.status === 'published' ? 'default' :
                                episode.status === 'recorded' ? 'secondary' : 'outline'
                              }
                            >
                              {episode.status}
                            </Badge>
                          </div>
                          <p className="text-sm text-gray-600 mb-2">{episode.description}</p>
                          {episode.topics.length > 0 && (
                            <div className="flex flex-wrap gap-1">
                              {episode.topics.slice(0, 3).map((topic, index) => (
                                <Badge key={index} variant="outline" className="text-xs">
                                  {topic}
                                </Badge>
                              ))}
                              {episode.topics.length > 3 && (
                                <Badge variant="outline" className="text-xs">
                                  +{episode.topics.length - 3} more
                                </Badge>
                              )}
                            </div>
                          )}
                          <Button 
                            size="sm" 
                            variant="ghost" 
                            className="mt-2"
                            onClick={() => {
                              setSelectedEpisode(episode);
                              setIsEpisodeDialogOpen(true);
                            }}
                          >
                            <Edit className="h-3 w-3 mr-1" />
                            Edit
                          </Button>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="text-center py-8">
                      <CalendarIcon className="h-12 w-12 mx-auto text-gray-400 mb-4" />
                      <p className="text-gray-500">No episodes scheduled</p>
                      <Button 
                        size="sm" 
                        className="mt-2"
                        onClick={() => setIsEpisodeDialogOpen(true)}
                      >
                        Schedule Episode
                      </Button>
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          </div>
        </TabsContent>

        {/* Content Bank */}
        <TabsContent value="content" className="space-y-6">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Upload Materials */}
            <Card>
              <CardHeader>
                <CardTitle>Upload Content Materials</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center">
                    <input
                      type="file"
                      multiple
                      accept=".txt,.md,.mp3,.wav,.m4a,.pdf"
                      className="hidden"
                      id="material-upload"
                      onChange={(e) => {
                        if (e.target.files) {
                          Array.from(e.target.files).forEach(uploadMaterial);
                        }
                      }}
                    />
                    <label htmlFor="material-upload" className="cursor-pointer">
                      <Upload className="h-12 w-12 mx-auto text-gray-400 mb-4" />
                      <h3 className="text-lg font-medium mb-2">Upload Materials</h3>
                      <p className="text-gray-500 mb-4">
                        Drop files here or click to upload
                      </p>
                      <p className="text-xs text-gray-400">
                        Supports: Text files, Audio files, Scripts, PDFs
                      </p>
                    </label>
                  </div>

                  <div className="grid grid-cols-3 gap-2 text-center">
                    <div className="p-3 bg-blue-50 rounded">
                      <FileText className="h-6 w-6 mx-auto text-blue-600 mb-1" />
                      <div className="text-xs text-blue-600">Text Scripts</div>
                    </div>
                    <div className="p-3 bg-green-50 rounded">
                      <Mic className="h-6 w-6 mx-auto text-green-600 mb-1" />
                      <div className="text-xs text-green-600">Audio Notes</div>
                    </div>
                    <div className="p-3 bg-purple-50 rounded">
                      <BookOpen className="h-6 w-6 mx-auto text-purple-600 mb-1" />
                      <div className="text-xs text-purple-600">Research Docs</div>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Materials Library */}
            <Card>
              <CardHeader>
                <CardTitle>Materials Library</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2 max-h-80 overflow-y-auto">
                  {materials.length > 0 ? (
                    materials.map(material => (
                      <div key={material.id} className="flex items-center space-x-3 p-2 border rounded">
                        <div className="flex-shrink-0">
                          {material.type === 'text' && <FileText className="h-4 w-4 text-blue-500" />}
                          {material.type === 'audio' && <Mic className="h-4 w-4 text-green-500" />}
                          {material.type === 'script' && <BookOpen className="h-4 w-4 text-purple-500" />}
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="text-sm font-medium truncate">{material.filename}</p>
                          <p className="text-xs text-gray-500">
                            {new Date(material.uploadDate).toLocaleDateString()}
                          </p>
                        </div>
                        <div className="flex-shrink-0">
                          <Badge variant={material.processed ? "default" : "secondary"}>
                            {material.processed ? "Ready" : "Processing"}
                          </Badge>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-8">
                      <Archive className="h-12 w-12 mx-auto text-gray-400 mb-4" />
                      <p className="text-gray-500">No materials uploaded yet</p>
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        {/* Topic Planning */}
        <TabsContent value="topics">
          <Card>
            <CardHeader>
              <CardTitle>Topic Variations & Planning</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {['Trending Topics', 'Evergreen Content', 'Seasonal Themes', 'Expert Interviews', 'Audience Q&A', 'Industry News'].map((category, index) => (
                  <Card key={index}>
                    <CardHeader className="pb-3">
                      <CardTitle className="text-lg flex items-center">
                        <TrendingUp className="h-4 w-4 mr-2" />
                        {category}
                      </CardTitle>
                    </CardHeader>
                    <CardContent>
                      <div className="space-y-2">
                        <Input 
                          placeholder="Add new topic..."
                          value={newTopicText}
                          onChange={(e) => setNewTopicText(e.target.value)}
                          onKeyPress={(e) => {
                            if (e.key === 'Enter' && newTopicText.trim()) {
                              // Add topic logic here
                              setNewTopicText("");
                            }
                          }}
                        />
                        <Button size="sm" className="w-full">
                          <PlusCircle className="h-3 w-3 mr-1" />
                          Add Topic
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* Analytics */}
        <TabsContent value="analytics">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <Card>
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">Total Episodes</p>
                    <p className="text-2xl font-bold">{episodes.length}</p>
                  </div>
                  <Headphones className="h-8 w-8 text-blue-500" />
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">Published</p>
                    <p className="text-2xl font-bold">
                      {episodes.filter(e => e.status === 'published').length}
                    </p>
                  </div>
                  <Play className="h-8 w-8 text-green-500" />
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">Materials</p>
                    <p className="text-2xl font-bold">{materials.length}</p>
                  </div>
                  <FileText className="h-8 w-8 text-purple-500" />
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">Avg Duration</p>
                    <p className="text-2xl font-bold">{format.targetDuration}m</p>
                  </div>
                  <Clock className="h-8 w-8 text-orange-500" />
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        {/* Settings */}
        <TabsContent value="settings">
          <Card>
            <CardHeader>
              <CardTitle>Format Settings</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <Label>Target Duration (minutes)</Label>
                    <Input value={format.targetDuration} type="number" />
                  </div>
                  <div>
                    <Label>Frequency</Label>
                    <Select value={format.frequency}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="daily">Daily</SelectItem>
                        <SelectItem value="weekly">Weekly</SelectItem>
                        <SelectItem value="monthly">Monthly</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <div>
                  <Label>Description</Label>
                  <Textarea value={format.description} rows={3} />
                </div>
                <Button>Save Settings</Button>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Episode Creation/Edit Dialog */}
      <Dialog open={isEpisodeDialogOpen} onOpenChange={setIsEpisodeDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>
              {selectedEpisode ? 'Edit Episode' : 'Create New Episode'}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label>Episode Title</Label>
              <Input 
                placeholder="Enter episode title..."
                defaultValue={selectedEpisode?.title}
              />
            </div>
            <div>
              <Label>Description</Label>
              <Textarea 
                placeholder="Describe what this episode will cover..."
                defaultValue={selectedEpisode?.description}
                rows={3}
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Scheduled Date</Label>
                <Input type="date" />
              </div>
              <div>
                <Label>Status</Label>
                <Select defaultValue={selectedEpisode?.status || 'planned'}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="planned">Planned</SelectItem>
                    <SelectItem value="recorded">Recorded</SelectItem>
                    <SelectItem value="published">Published</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div>
              <Label>Topics (comma separated)</Label>
              <Input 
                placeholder="topic1, topic2, topic3..."
                defaultValue={selectedEpisode?.topics.join(', ')}
              />
            </div>
            <div>
              <Label>Notes</Label>
              <Textarea 
                placeholder="Additional notes and talking points..."
                defaultValue={selectedEpisode?.notes}
                rows={4}
              />
            </div>
            <div className="flex justify-end space-x-2">
              <Button variant="outline" onClick={() => setIsEpisodeDialogOpen(false)}>
                Cancel
              </Button>
              <Button onClick={() => episodeMutation.mutate({})}>
                {selectedEpisode ? 'Update' : 'Create'} Episode
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

