import { useState, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Calendar } from "@/components/ui/calendar";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Plus, Edit, Calendar as CalendarIcon, Music, Mic, Clock, Target, Upload, FileText, Star, MapPin, Settings, MessageSquare, Sparkles, Trash2, Volume2 } from "lucide-react";
import { toast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";

interface ProgramBlock {
  id: number;
  dayOfWeek: number;
  startHour: number;
  endHour: number;
  title: string;
  blockType: 'music' | 'content' | 'mixed';
  formatId?: number;
  moderatorId?: number;
  description?: string;
  musicFilters: any;
  linkedEventId?: number;
  isActive: boolean;
}

interface Moderator {
  id: number;
  name: string;
  style: string;
  voiceType: string;
  isActive: boolean;
}

interface ProgramFormat {
  id: number;
  name: string;
  category: string;
  description?: string;
  colorCode?: string;
  duration?: number;
  isActive: boolean;
}

interface Event {
  id: number;
  title: string;
  eventDate: string;
  venue?: string;
  category?: string;
  isPromoted: boolean;
}

export default function ProgramScheduler() {
  const [selectedBlock, setSelectedBlock] = useState<ProgramBlock | null>(null);
  const [selectedEventText, setSelectedEventText] = useState("");
  const [dialoguePreview, setDialoguePreview] = useState("");
  const [isBlockFormOpen, setIsBlockFormOpen] = useState(false);
  const [editingBlock, setEditingBlock] = useState<ProgramBlock | null>(null);
  const [autoGeneratedContent, setAutoGeneratedContent] = useState<any[] | null>(null);
  const [selectedHour, setSelectedHour] = useState<{day: number, hour: number} | null>(null);
  const [minuteView, setMinuteView] = useState<any[] | null>(null);
  const [formatMaterials, setFormatMaterials] = useState<{[key: string]: any[]}>({});
  const [uploadingFormat, setUploadingFormat] = useState<string | null>(null);
  const [promotedEvent, setPromotedEvent] = useState<Event | null>(null);
  const [generatedQuestions, setGeneratedQuestions] = useState<any[]>([]);
  const [selectedQuestions, setSelectedQuestions] = useState<any[]>([]);
  const [editingTransition, setEditingTransition] = useState<{index: number, text: string} | null>(null);
  const [showPromotionDialog, setShowPromotionDialog] = useState(false);
  const [editableDialogues, setEditableDialogues] = useState<any[]>([]);
  const [editingDialogue, setEditingDialogue] = useState<{id: number, text: string} | null>(null);
  const [generatedSuggestions, setGeneratedSuggestions] = useState<any[]>([]);
  const [isGeneratingSuggestions, setIsGeneratingSuggestions] = useState(false);
  const [formatIdeas, setFormatIdeas] = useState<{[key: string]: any[]}>({});
  const [isGeneratingFormatIdeas, setIsGeneratingFormatIdeas] = useState(false);
  const queryClient = useQueryClient();

  const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const hours = Array.from({ length: 24 }, (_, i) => i);

  // Fetch data
  const { data: programBlocks, isLoading: blocksLoading } = useQuery<ProgramBlock[]>({
    queryKey: ['/api/program-blocks'],
  });

  const { data: moderators } = useQuery<Moderator[]>({
    queryKey: ['/api/moderators'],
  });

  const { data: formats } = useQuery<ProgramFormat[]>({
    queryKey: ['/api/program-formats'],
  });

  const { data: events } = useQuery<Event[]>({
    queryKey: ['/api/events'],
  });

  // Create/update program block
  const blockMutation = useMutation({
    mutationFn: async (blockData: Partial<ProgramBlock>) => {
      const url = editingBlock ? `/api/program-blocks/${editingBlock.id}` : '/api/program-blocks';
      const method = editingBlock ? 'PUT' : 'POST';
      const response = await fetch(url, {
        method,
