  const generateMinuteView = (day: number, hour: number) => {
    const hourBlock = programBlocks?.find(block => 
      block.dayOfWeek === day && 
      hour >= block.startHour && 
      hour < block.endHour
    );

    if (!hourBlock) {
      setMinuteView([]);
      return;
    }

    // Generate 60 minutes of content
    const minutes = [];
    for (let minute = 0; minute < 60; minute += 3) {
      const timeSlot = `${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}-${String(hour).padStart(2, '0')}:${String(minute + 3).padStart(2, '0')}`;

      if (minute % 15 === 0) {
        minutes.push({
          minute,
          duration: 3,
          type: 'moderation',
          contentType: minute === 0 ? 'Station ID' : minute === 30 ? 'Local Update' : 'Transition',
          timeSlot,
          title: minute === 0 ? 'Hourly Station ID' : minute === 30 ? 'Dubai Update' : 'Track Intro',
          dialogue: minute === 0 ? 
            `You're listening to Golden Pearl Radio, ${hour}:00 in beautiful Dubai!` :
            minute === 30 ? 
