            `That was a beautiful track, here's another one to keep the energy flowing.`,
          format: hourBlock.formatId,
          canEdit: true
        });
      } else {
        minutes.push({
          minute,
          duration: 3,
          type: 'music',
          timeSlot,
          title: `Track ${Math.floor(minute/3) + 1}`,
          artist: 'Auto-Selected',
