                  <div className="flex items-center space-x-2 mb-3">
                    <Sparkles className="h-5 w-5 text-purple-600" />
                    <h4 className="font-medium text-purple-800">KI-Vorschläge für weitere Dialoge</h4>
                    <Badge variant="outline" className="bg-white">
                      {generatedSuggestions.length} Vorschläge
                    </Badge>
                  </div>

                  <div className="space-y-3">
                    {generatedSuggestions.map((suggestion, index) => (
                      <div key={index} className="bg-white border rounded-lg p-4">
                        <div className="flex justify-between items-start">
                          <div className="flex-1">
                            <div className="flex items-center space-x-2 mb-2">
                              <Badge variant="secondary">{suggestion.type}</Badge>
                              <span className="font-medium text-sm">{suggestion.title}</span>
                              <Badge variant="outline" className="text-xs">
                                {suggestion.duration}
                              </Badge>
                            </div>
                            <p className="text-sm text-gray-700 mb-2">
                              {suggestion.text}
                            </p>
                            <div className="text-xs text-gray-500">
                              Moderator: {suggestion.moderator || 'Omar'}
                            </div>
                          </div>
                          <Button
                            size="sm"
                            onClick={() => addSuggestedDialogue(suggestion)}
                            className="ml-3"
                          >
                            <Plus className="h-3 w-3 mr-1" />
                            Hinzufügen
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>

                  <div className="mt-4 pt-3 border-t">
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => setGeneratedSuggestions([])}
                      className="text-gray-600"
                    >
                      Vorschläge ausblenden
                    </Button>
                  </div>
                </div>
              </div>
            )}

            {/* Preview Summary */}
            {editableDialogues.length > 0 && (
              <div className="bg-blue-50 p-4 rounded-lg border">
                <h4 className="font-medium mb-2">Dialog-Sequenz Zusammenfassung</h4>
                <div className="text-sm text-gray-600">
                  <p>• {editableDialogues.length} Dialog-Segmente</p>
                  <p>• Geschätzte Gesamtdauer: {editableDialogues.reduce((total, d) => 
                    total + parseInt(d.duration.replace(/\D/g, '') || '30'), 0
                  )} Sekunden</p>
                  <p>• Event: {promotedEvent?.title} am {promotedEvent && new Date(promotedEvent.eventDate).toLocaleDateString()}</p>
                </div>
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

// Form component for creating/editing program blocks
function ProgramBlockForm({ 
  block, 
  moderators, 
  formats, 
  onSubmit, 
  isLoading 
}: {
  block: ProgramBlock | null;
  moderators: Moderator[];
  formats: ProgramFormat[];
  onSubmit: (data: any) => void;
  isLoading: boolean;
}) {
  const [formData, setFormData] = useState({
    dayOfWeek: block?.dayOfWeek || 0,
    startHour: block?.startHour || 9,
    endHour: block?.endHour || 10,
    title: block?.title || '',
    blockType: block?.blockType || 'music',
    formatId: block?.formatId || '',
    moderatorId: block?.moderatorId || '',
    description: block?.description || '',
    musicFilters: block?.musicFilters || {}
  });

  const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
      ...formData,
      formatId: formData.formatId || null,
      moderatorId: formData.moderatorId || null,
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="grid grid-cols-2 gap-4">
        <div>
          <Label>Day</Label>
          <Select value={String(formData.dayOfWeek)} onValueChange={(value) => 
            setFormData(prev => ({ ...prev, dayOfWeek: parseInt(value) }))
          }>
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {days.map((day, index) => (
                <SelectItem key={index} value={String(index)}>{day}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        <div>
          <Label>Block Type</Label>
          <Select value={formData.blockType} onValueChange={(value) => 
            setFormData(prev => ({ ...prev, blockType: value as any }))
          }>
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="music">Music</SelectItem>
              <SelectItem value="content">Content</SelectItem>
              <SelectItem value="mixed">Mixed</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <Label>Start Hour</Label>
          <Input
            type="number"
            min="0"
            max="23"
            value={formData.startHour}
            onChange={(e) => setFormData(prev => ({ ...prev, startHour: parseInt(e.target.value) }))}
          />
        </div>

        <div>
          <Label>End Hour</Label>
          <Input
            type="number"
            min="0"
            max="23"
            value={formData.endHour}
            onChange={(e) => setFormData(prev => ({ ...prev, endHour: parseInt(e.target.value) }))}
          />
        </div>
      </div>

      <div>
        <Label>Title</Label>
        <Input
          value={formData.title}
          onChange={(e) => setFormData(prev => ({ ...prev, title: e.target.value }))}
          placeholder="e.g. Morning Energy Mix"
        />
      </div>

      <div>
        <Label>Description</Label>
        <Textarea
          value={formData.description}
          onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
          placeholder="Block description..."
        />
      </div>

      {formData.blockType === 'content' && (
        <>
          <div>
            <Label>Format</Label>
            <Select value={String(formData.formatId)} onValueChange={(value) => 
              setFormData(prev => ({ ...prev, formatId: value }))
            }>
              <SelectTrigger>
                <SelectValue placeholder="Select format" />
              </SelectTrigger>
              <SelectContent>
                {formats.map(format => (
                  <SelectItem key={format.id} value={String(format.id)}>
                    {format.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label>Moderator</Label>
            <Select value={String(formData.moderatorId)} onValueChange={(value) => 
              setFormData(prev => ({ ...prev, moderatorId: value }))
            }>
              <SelectTrigger>
                <SelectValue placeholder="Select moderator" />
              </SelectTrigger>
              <SelectContent>
                {moderators.map(moderator => (
                  <SelectItem key={moderator.id} value={String(moderator.id)}>
                    {moderator.name} ({moderator.style})
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </>
      )}

      <Button type="submit" disabled={isLoading} className="w-full">
        {isLoading ? 'Saving...' : (block ? 'Update Block' : 'Create Block')}
      </Button>
    </form>
  );
}

