  const [breakPoints, setBreakPoints] = useState<number[]>([]);

  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Schedule form
  const scheduleForm = useForm<z.infer<typeof scheduleFormSchema>>({
    resolver: zodResolver(scheduleFormSchema),
    defaultValues: {
      type: "track",
      itemId: 0,
      startTime: new Date(),
      isRecurring: false,
      recurrencePattern: "daily",
    },
  });

  // AI Playlist form
  const aiPlaylistForm = useForm<z.infer<typeof aiPlaylistFormSchema>>({
    resolver: zodResolver(aiPlaylistFormSchema),
    defaultValues: {
      targetMood: "",
      targetGenre: "",
      duration: 3600, // 1 hour in seconds
      messageCount: 3,
    },
  });

  // Format the selected date for API queries
  const formattedDate = format(date, 'yyyy-MM-dd');
  const startDate = new Date(formattedDate);
  const endDate = new Date(formattedDate);
  endDate.setDate(endDate.getDate() + 1);

  // Fetch schedule items for selected date
  const { data: scheduleItems, isLoading: isLoadingSchedule } = useQuery<ScheduleItem[]>({
    queryKey: ['/api/schedule', startDate.toISOString(), endDate.toISOString()],
    queryFn: async () => {
      const response = await fetch(`/api/schedule?startDate=${startDate.toISOString()}&endDate=${endDate.toISOString()}`);
      if (!response.ok) throw new Error('Failed to fetch schedule');
      return response.json();
    },
  });

  // Fetch tracks for selection
  const { data: tracks, isLoading: isLoadingTracks } = useQuery<Track[]>({
    queryKey: ['/api/tracks'],
  });

  // Fetch shows for selection
  const { data: shows, isLoading: isLoadingShows } = useQuery<Show[]>({
    queryKey: ['/api/shows'],
  });

  // Fetch moderator messages for selection
  const { data: messages, isLoading: isLoadingMessages } = useQuery<ModeratorMessage[]>({
    queryKey: ['/api/messages'],
  });

  // Create schedule item mutation
  const createScheduleItemMutation = useMutation({
    mutationFn: async (data: z.infer<typeof scheduleFormSchema>) => {
      // Format the data for API
      const formattedData = {
        type: data.type,
        itemId: data.itemId,
        startTime: data.startTime.toISOString(),
        endTime: data.endTime ? data.endTime.toISOString() : undefined,
        isRecurring: data.isRecurring,
        recurrencePattern: data.isRecurring ? data.recurrencePattern : undefined,
      };

      const response = await apiRequest('POST', '/api/schedule', formattedData);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ 
        queryKey: ['/api/schedule', startDate.toISOString(), endDate.toISOString()] 
      });
      setIsScheduleFormOpen(false);
      scheduleForm.reset();
      toast({
        title: "Schedule Item Created",
        description: "The item has been successfully scheduled.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to create schedule item: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Delete schedule item mutation
  const deleteScheduleItemMutation = useMutation({
    mutationFn: async (id: number) => {
      await apiRequest('DELETE', `/api/schedule/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ 
        queryKey: ['/api/schedule', startDate.toISOString(), endDate.toISOString()] 
      });
      setIsDeleteDialogOpen(false);
      setSelectedScheduleItem(null);
      toast({
        title: "Schedule Item Deleted",
        description: "The scheduled item has been successfully removed.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to delete schedule item: ${error}`,
        variant: "destructive",
      });
    },
  });

  // Watch for type changes in schedule form to reset itemId
  useEffect(() => {
    const subscription = scheduleForm.watch((value, { name }) => {
      if (name === 'type' && value.type !== scheduleForm.getValues('type')) {
        scheduleForm.setValue('itemId', 0);
      }
    });

    return () => subscription.unsubscribe();
  }, [scheduleForm]);

  // Handle schedule form submission
  const onSubmitScheduleItem = (data: z.infer<typeof scheduleFormSchema>) => {
    // Ensure end time is after start time
    if (data.endTime && data.endTime <= data.startTime) {
      toast({
        title: "Invalid time range",
        description: "End time must be after start time",
        variant: "destructive",
      });
      return;
    }

    createScheduleItemMutation.mutate(data);
  };

  // Handle AI Playlist generation
  const onGeneratePlaylist = (data: z.infer<typeof aiPlaylistFormSchema>) => {
    if (!tracks || tracks.length === 0) {
      toast({
        title: "Error",
        description: "No tracks available to generate playlist",
        variant: "destructive",
      });
      return;
    }

    // Generate playlist using AI engine
    const playlist = generateAIPlaylist(
      tracks,
      data.targetMood || null,
      data.targetGenre || null,
      data.duration
    );

    // Find optimal break points for moderator messages
    const optimalBreakPoints = findOptimalBreakPoints(playlist, data.messageCount);

    // Analyze the generated playlist
    const analysis = analyzePlaylist(playlist);

    setGeneratedPlaylist(playlist);
    setBreakPoints(optimalBreakPoints);
    setPlaylistAnalysis(analysis);

    toast({
      title: "Playlist Generated",
      description: `Generated a ${Math.round(analysis.duration / 60)} minute playlist with ${playlist.length} tracks`,
    });
  };

  // Handle scheduling of generated playlist
  const scheduleGeneratedPlaylist = () => {
    if (generatedPlaylist.length === 0) return;

    // Show success notification
    toast({
      title: "Playlist Scheduled",
      description: "The AI-generated playlist has been added to the schedule.",
    });

    // Close the AI playlist dialog
    setIsAIPlaylistFormOpen(false);
    setGeneratedPlaylist([]);
    setBreakPoints([]);
    setPlaylistAnalysis(null);
    aiPlaylistForm.reset();

    // In a production app, this would send the playlist and break points to the backend
    // for scheduling, but for this demo we'll just show a success message
  };

  // Get item details for schedule display
  const getItemDetails = (item: ScheduleItem) => {
    if (item.type === 'track') {
      const track = tracks?.find(t => t.id === item.itemId);
      return {
        title: track?.title || 'Unknown Track',
        subtitle: track?.artist || '',
        icon: <Music className="h-4 w-4" />,
      };
    } else if (item.type === 'show') {
      const show = shows?.find(s => s.id === item.itemId);
      return {
        title: show?.title || 'Unknown Show',
        subtitle: show?.hostName || '',
        icon: <Radio className="h-4 w-4" />,
      };
    } else if (item.type === 'message') {
      const message = messages?.find(m => m.id === item.itemId);
      return {
        title: `${message?.type || 'Unknown'} Message`,
        subtitle: message?.content.substring(0, 30) + (message?.content.length || 0 > 30 ? '...' : '') || '',
        icon: <MessageSquare className="h-4 w-4" />,
      };
    }

    return {
      title: 'Unknown Item',
      subtitle: '',
      icon: <AlertTriangle className="h-4 w-4" />,
    };
  };

  // Format time from Date object
  const formatTime = (date: Date) => {
    return format(date, 'h:mm a');
  };

  return (
    <AdminLayout>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 md:px-8">
        <h1 className="text-2xl font-semibold text-gray-900 mb-6">Content Scheduler</h1>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Calendar and Schedule Controls */}
          <Card className="lg:col-span-1">
            <CardHeader>
              <CardTitle>Select Date</CardTitle>
              <CardDescription>
                View and manage schedule for selected date
              </CardDescription>
            </CardHeader>
            <CardContent>
              <Calendar
                mode="single"
                selected={date}
                onSelect={(newDate) => newDate && setDate(newDate)}
                className="rounded-md border mb-6"
              />

              <div className="space-y-4">
                <Button 
                  className="w-full" 
                  onClick={() => {
                    scheduleForm.reset({
                      ...scheduleForm.getValues(),
                      startTime: new Date(date),
                      endTime: undefined,
                    });
                    setIsScheduleFormOpen(true);
                  }}
                >
                  <Plus className="mr-2 h-4 w-4" /> Add Schedule Item
                </Button>
                <Button 
                  variant="outline" 
                  className="w-full"
                  onClick={() => setIsAIPlaylistFormOpen(true)}
                >
                  <Radio className="mr-2 h-4 w-4" /> Generate AI Playlist
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Schedule Display */}
          <Card className="lg:col-span-2">
            <CardHeader>
              <CardTitle className="flex items-center">
                <CalendarDays className="mr-2 h-5 w-5" />
                Schedule for {format(date, 'MMMM d, yyyy')}
              </CardTitle>
              <CardDescription>
                {isLoadingSchedule 
                  ? 'Loading schedule...' 
                  : scheduleItems && scheduleItems.length > 0 
                    ? `${scheduleItems.length} items scheduled` 
                    : 'No items scheduled for this date'
                }
              </CardDescription>
            </CardHeader>
            <CardContent>
              {isLoadingSchedule ? (
                <div className="flex justify-center items-center h-64">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
                </div>
              ) : scheduleItems?.length === 0 ? (
                <div className="text-center py-10">
                  <CalendarDays className="h-12 w-12 mx-auto text-gray-400" />
                  <h3 className="mt-2 text-sm font-medium text-gray-900">No items scheduled</h3>
                  <p className="mt-1 text-sm text-gray-500">
                    Add content to the schedule for this date.
                  </p>
                  <div className="mt-6">
                    <Button
                      onClick={() => {
                        scheduleForm.reset({
                          ...scheduleForm.getValues(),
                          startTime: new Date(date),
                          endTime: undefined,
                        });
                        setIsScheduleFormOpen(true);
                      }}
                    >
                      <Plus className="mr-2 h-4 w-4" /> Add Schedule Item
                    </Button>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  {scheduleItems?.sort((a, b) => 
                    new Date(a.startTime).getTime() - new Date(b.startTime).getTime()
                  ).map((item) => {
                    const details = getItemDetails(item);
                    return (
                      <div 
                        key={item.id} 
                        className="flex items-start p-3 rounded-lg border hover:bg-gray-50"
                      >
                        <div className={`rounded-full p-2 mr-3 ${
                          item.type === 'track' ? 'bg-blue-100 text-blue-700' :
                          item.type === 'show' ? 'bg-purple-100 text-purple-700' :
                          'bg-green-100 text-green-700'
                        }`}>
                          {details.icon}
                        </div>
                        <div className="flex-1">
                          <div className="flex justify-between items-start">
                            <div>
                              <h4 className="font-medium text-gray-900">{details.title}</h4>
                              <p className="text-sm text-gray-500">{details.subtitle}</p>
                            </div>
                            <Button 
                              variant="ghost" 
                              size="icon" 
                              className="h-8 w-8 text-red-500 hover:text-red-700"
                              onClick={() => {
                                setSelectedScheduleItem(item);
                                setIsDeleteDialogOpen(true);
                              }}
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </div>
                          <div className="flex items-center mt-2 text-sm">
                            <Clock className="h-3 w-3 mr-1 text-gray-400" />
                            <span>
                              {formatTime(new Date(item.startTime))}
                              {item.endTime && (
                                <>
                                  <ArrowRight className="inline-block mx-1 h-3 w-3" />
                                  {formatTime(new Date(item.endTime))}
                                </>
                              )}
                            </span>
                            {item.isRecurring && (
                              <span className="ml-2 px-2 py-0.5 rounded-full text-xs font-medium bg-amber-100 text-amber-800">
                                Recurring: {item.recurrencePattern}
                              </span>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </CardContent>
          </Card>
        </div>

        {/* Schedule Form Dialog */}
        <Dialog open={isScheduleFormOpen} onOpenChange={setIsScheduleFormOpen}>
          <DialogContent className="sm:max-w-lg">
            <DialogHeader>
              <DialogTitle>Add Schedule Item</DialogTitle>
              <DialogDescription>
                Schedule content for playback on the radio.
              </DialogDescription>
            </DialogHeader>

            <Form {...scheduleForm}>
              <form onSubmit={scheduleForm.handleSubmit(onSubmitScheduleItem)} className="space-y-4">
                <FormField
                  control={scheduleForm.control}
                  name="type"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Item Type *</FormLabel>
                      <Select
                        onValueChange={field.onChange}
                        defaultValue={field.value}
                      >
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Select item type" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="track">Track</SelectItem>
                          <SelectItem value="show">Show</SelectItem>
                          <SelectItem value="message">Moderator Message</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={scheduleForm.control}
                  name="itemId"
                  render={({ field }) => {
                    const type = scheduleForm.getValues('type');
                    let options: { id: number; name: string; subtext?: string }[] = [];
                    let isLoading = false;

                    if (type === 'track') {
                      isLoading = isLoadingTracks;
                      options = tracks?.map(track => ({
                        id: track.id,
                        name: track.title,
                        subtext: track.artist
                      })) || [];
                    } else if (type === 'show') {
                      isLoading = isLoadingShows;
                      options = shows?.map(show => ({
                        id: show.id,
                        name: show.title,
                        subtext: show.hostName
                      })) || [];
                    } else if (type === 'message') {
                      isLoading = isLoadingMessages;
                      options = messages?.map(message => ({
                        id: message.id,
                        name: `${message.type} Message`,
                        subtext: message.content.substring(0, 30) + (message.content.length > 30 ? '...' : '')
                      })) || [];
                    }

                    return (
                      <FormItem>
                        <FormLabel>Select Item *</FormLabel>
                        <select
                          className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                          value={field.value}
                          onChange={(e) => field.onChange(parseInt(e.target.value))}
                          disabled={isLoading}
                        >
                          <option value="0" disabled>
                            {isLoading ? 'Loading options...' : `Select a ${type}`}
                          </option>
                          {options.map(option => (
                            <option key={option.id} value={option.id}>
                              {option.name} {option.subtext ? `— ${option.subtext}` : ''}
                            </option>
                          ))}
                        </select>
                        <FormMessage />
                      </FormItem>
                    );
                  }}
                />

                <div className="grid grid-cols-2 gap-4">
                  <FormField
                    control={scheduleForm.control}
                    name="startTime"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Start Time *</FormLabel>
                        <Popover>
                          <PopoverTrigger asChild>
                            <FormControl>
                              <Button
                                variant="outline"
                                className="w-full pl-3 text-left font-normal"
                              >
                                {field.value ? (
                                  format(field.value, "PPP p")
                                ) : (
                                  <span>Pick a date & time</span>
                                )}
                                <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                              </Button>
                            </FormControl>
                          </PopoverTrigger>
                          <PopoverContent className="w-auto p-0" align="start">
                            <Calendar
                              mode="single"
                              selected={field.value}
                              onSelect={(date) => {
                                if (date) {
                                  const newDate = new Date(field.value);
                                  newDate.setFullYear(date.getFullYear());
                                  newDate.setMonth(date.getMonth());
                                  newDate.setDate(date.getDate());
                                  field.onChange(newDate);
                                }
                              }}
                              initialFocus
                            />
                            <div className="p-3 border-t border-border">
                              <Input
                                type="time"
                                value={format(field.value, "HH:mm")}
                                onChange={(e) => {
                                  const [hours, minutes] = e.target.value.split(":");
                                  const newDate = new Date(field.value);
                                  newDate.setHours(parseInt(hours));
                                  newDate.setMinutes(parseInt(minutes));
                                  field.onChange(newDate);
                                }}
                              />
                            </div>
                          </PopoverContent>
                        </Popover>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={scheduleForm.control}
                    name="endTime"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>End Time</FormLabel>
                        <Popover>
                          <PopoverTrigger asChild>
                            <FormControl>
                              <Button
                                variant="outline"
                                className="w-full pl-3 text-left font-normal"
                              >
                                {field.value ? (
                                  format(field.value, "PPP p")
                                ) : (
                                  <span>Pick a date & time (optional)</span>
                                )}
                                <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                              </Button>
                            </FormControl>
                          </PopoverTrigger>
                          <PopoverContent className="w-auto p-0" align="start">
                            <Calendar
                              mode="single"
                              selected={field.value || undefined}
                              onSelect={(date) => {
                                if (date) {
                                  const startTime = scheduleForm.getValues('startTime');
                                  const newDate = new Date(field.value || startTime);
                                  newDate.setFullYear(date.getFullYear());
                                  newDate.setMonth(date.getMonth());
                                  newDate.setDate(date.getDate());
                                  field.onChange(newDate);
                                } else {
                                  field.onChange(undefined);
                                }
                              }}
                              initialFocus
                            />
                            {field.value && (
                              <div className="p-3 border-t border-border">
                                <Input
                                  type="time"
                                  value={format(field.value, "HH:mm")}
                                  onChange={(e) => {
                                    const [hours, minutes] = e.target.value.split(":");
                                    const newDate = new Date(field.value);
                                    newDate.setHours(parseInt(hours));
                                    newDate.setMinutes(parseInt(minutes));
                                    field.onChange(newDate);
                                  }}
                                />
                              </div>
                            )}
                          </PopoverContent>
                        </Popover>
                        <FormDescription>
                          Optional - defaults to track/show duration
                        </FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <FormField
                  control={scheduleForm.control}
                  name="isRecurring"
                  render={({ field }) => (
                    <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                      <div className="space-y-0.5">
                        <FormLabel className="text-base">Recurring Schedule</FormLabel>
                        <FormDescription>
                          Schedule this item to repeat on a defined pattern
                        </FormDescription>
                      </div>
                      <FormControl>
                        <Switch
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                {scheduleForm.watch('isRecurring') && (
                  <FormField
                    control={scheduleForm.control}
                    name="recurrencePattern"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Recurrence Pattern</FormLabel>
                        <Select
                          onValueChange={field.onChange}
                          defaultValue={field.value}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Select pattern" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="daily">Daily</SelectItem>
                            <SelectItem value="weekdays">Weekdays</SelectItem>
                            <SelectItem value="weekends">Weekends</SelectItem>
                            <SelectItem value="Monday">Every Monday</SelectItem>
                            <SelectItem value="Tuesday">Every Tuesday</SelectItem>
                            <SelectItem value="Wednesday">Every Wednesday</SelectItem>
                            <SelectItem value="Thursday">Every Thursday</SelectItem>
                            <SelectItem value="Friday">Every Friday</SelectItem>
                            <SelectItem value="Saturday">Every Saturday</SelectItem>
                            <SelectItem value="Sunday">Every Sunday</SelectItem>
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                )}

                <DialogFooter>
                  <Button 
                    type="button" 
                    variant="outline" 
                    onClick={() => setIsScheduleFormOpen(false)}
                  >
                    Cancel
                  </Button>
                  <Button 
                    type="submit" 
                    disabled={createScheduleItemMutation.isPending}
                  >
                    {createScheduleItemMutation.isPending ? 'Scheduling...' : 'Schedule Item'}
                  </Button>
                </DialogFooter>
              </form>
            </Form>
          </DialogContent>
        </Dialog>

        {/* AI Playlist Generator Dialog */}
        <Dialog 
          open={isAIPlaylistFormOpen} 
          onOpenChange={setIsAIPlaylistFormOpen}
        >
          <DialogContent className="sm:max-w-lg">
            <DialogHeader>
              <DialogTitle>AI Playlist Generator</DialogTitle>
              <DialogDescription>
                Generate an AI-curated playlist with optimal song transitions and message breaks.
              </DialogDescription>
            </DialogHeader>

            {generatedPlaylist.length > 0 ? (
              <div className="space-y-4">
                <div className="bg-gray-50 p-4 rounded-lg">
                  <h3 className="font-medium text-lg mb-2">Playlist Analysis</h3>
                  <div className="grid grid-cols-2 gap-x-4 gap-y-2 text-sm">
                    <div>
                      <span className="text-gray-500">Duration:</span> {Math.floor(playlistAnalysis.duration / 60)} minutes
                    </div>
                    <div>
                      <span className="text-gray-500">Tracks:</span> {generatedPlaylist.length}
                    </div>
                    <div>
                      <span className="text-gray-500">Mood:</span> {playlistAnalysis.dominantMood}
                    </div>
                    <div>
                      <span className="text-gray-500">Genre:</span> {playlistAnalysis.dominantGenre}
                    </div>
                    <div>
                      <span className="text-gray-500">Energy:</span> {playlistAnalysis.energyProfile}
                    </div>
                    <div>
                      <span className="text-gray-500">Tempo:</span> {playlistAnalysis.averageTempo} BPM
                    </div>
                  </div>
                </div>

                <div className="max-h-60 overflow-y-auto border rounded-lg">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50 sticky top-0">
                      <tr>
                        <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">#</th>
                        <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Title</th>
                        <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Artist</th>
                        <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Duration</th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {generatedPlaylist.map((track, index) => (
                        <tr key={track.id} className={breakPoints.includes(index) ? "bg-amber-50" : ""}>
                          <td className="px-3 py-2 whitespace-nowrap text-sm">
                            {index + 1}
                            {breakPoints.includes(index) && (
                              <span className="ml-1 inline-flex items-center px-1.5 py-0.5 rounded-full text-xs font-medium bg-amber-100 text-amber-800">
                                <MessageSquare className="h-3 w-3 mr-0.5" /> Msg
                              </span>
                            )}
                          </td>
                          <td className="px-3 py-2 whitespace-nowrap text-sm font-medium">{track.title}</td>
                          <td className="px-3 py-2 whitespace-nowrap text-sm">{track.artist}</td>
                          <td className="px-3 py-2 whitespace-nowrap text-sm">
                            {Math.floor(track.duration / 60)}:{(track.duration % 60).toString().padStart(2, '0')}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>

                <DialogFooter>
                  <Button 
                    type="button" 
                    variant="outline" 
                    onClick={() => {
                      setGeneratedPlaylist([]);
                      setBreakPoints([]);
                      setPlaylistAnalysis(null);
                    }}
                  >
                    Generate Another
                  </Button>
                  <Button 
                    type="button"
                    onClick={scheduleGeneratedPlaylist}
                  >
                    <Check className="mr-2 h-4 w-4" />
                    Schedule Playlist
                  </Button>
                </DialogFooter>
              </div>
            ) : (
              <Form {...aiPlaylistForm}>
                <form 
                  onSubmit={aiPlaylistForm.handleSubmit(onGeneratePlaylist)} 
                  className="space-y-4"
                >
                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={aiPlaylistForm.control}
                      name="targetMood"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Target Mood</FormLabel>
                          <Select
                            onValueChange={field.onChange}
                            defaultValue={field.value}
                          >
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue placeholder="Any mood" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              <SelectItem value="">Any mood</SelectItem>
                              <SelectItem value="upbeat">Upbeat</SelectItem>
                              <SelectItem value="relaxed">Relaxed</SelectItem>
                              <SelectItem value="energetic">Energetic</SelectItem>
                              <SelectItem value="chill">Chill</SelectItem>
                              <SelectItem value="romantic">Romantic</SelectItem>
                              <SelectItem value="melancholic">Melancholic</SelectItem>
                              <SelectItem value="happy">Happy</SelectItem>
                            </SelectContent>
                          </Select>
                          <FormDescription>
                            Optional - focus playlist on a specific mood
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={aiPlaylistForm.control}
                      name="targetGenre"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Target Genre</FormLabel>
                          <Select
                            onValueChange={field.onChange}
                            defaultValue={field.value}
                          >
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue placeholder="Any genre" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              <SelectItem value="">Any genre</SelectItem>
                              <SelectItem value="Electronic">Electronic</SelectItem>
                              <SelectItem value="Pop">Pop</SelectItem>
                              <SelectItem value="Rock">Rock</SelectItem>
                              <SelectItem value="Hip Hop">Hip Hop</SelectItem>
                              <SelectItem value="RnB">RnB</SelectItem>
                              <SelectItem value="Jazz">Jazz</SelectItem>
                              <SelectItem value="Classical">Classical</SelectItem>
                              <SelectItem value="World">World</SelectItem>
                              <SelectItem value="Lounge">Lounge</SelectItem>
                              <SelectItem value="Ambient">Ambient</SelectItem>
                            </SelectContent>
                          </Select>
                          <FormDescription>
                            Optional - focus playlist on a specific genre
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={aiPlaylistForm.control}
                      name="duration"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Duration (minutes)</FormLabel>
                          <FormControl>
                            <Input 
                              type="number" 
                              min="5" 
                              max="180" 
                              {...field}
                              onChange={(e) => {
                                // Convert minutes to seconds for internal use
                                const minutes = parseInt(e.target.value);
                                field.onChange(minutes * 60);
                              }}
                              value={Math.floor(field.value / 60)}
                            />
                          </FormControl>
                          <FormDescription>
                            Playlist duration in minutes (5-180)
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={aiPlaylistForm.control}
                      name="messageCount"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Message Breaks</FormLabel>
                          <FormControl>
                            <Input 
                              type="number" 
                              min="0" 
                              max="10" 
                              {...field} 
                            />
                          </FormControl>
                          <FormDescription>
                            Number of moderator message slots to include
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <DialogFooter>
                    <Button 
                      type="button" 
                      variant="outline" 
                      onClick={() => setIsAIPlaylistFormOpen(false)}
                    >
                      Cancel
                    </Button>
                    <Button type="submit">
                      Generate Playlist
                    </Button>
                  </DialogFooter>
                </form>
              </Form>
            )}
          </DialogContent>
        </Dialog>

        {/* Delete Confirmation Dialog */}
        <Dialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
          <DialogContent className="sm:max-w-md">
            <DialogHeader>
              <DialogTitle className="flex items-center">
                <AlertTriangle className="h-5 w-5 text-red-500 mr-2" />
                Confirm Deletion
              </DialogTitle>
              <DialogDescription>
                Are you sure you want to delete this scheduled item? This action cannot be undone.
              </DialogDescription>
            </DialogHeader>

            <DialogFooter>
              <Button 
                type="button" 
                variant="outline" 
                onClick={() => setIsDeleteDialogOpen(false)}
              >
                Cancel
              </Button>
              <Button 
                variant="destructive" 
                onClick={() => selectedScheduleItem && deleteScheduleItemMutation.mutate(selectedScheduleItem.id)}
                disabled={deleteScheduleItemMutation.isPending}
              >
                {deleteScheduleItemMutation.isPending ? 'Deleting...' : 'Delete Item'}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </AdminLayout>
  );
}

client/src/pages/admin/speakers.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { queryClient } from "@/lib/queryClient";
import { Mic, Upload, Play, Pause, Trash2, Settings, Volume2 } from "lucide-react";
import type { Speaker, InsertSpeaker } from "@shared/schema";

export default function SpeakersPage() {
  const { toast } = useToast();
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [name, setName] = useState("");
  const [code, setCode] = useState("");
  const [colorTag, setColorTag] = useState("#3B82F6");
  const [voiceType, setVoiceType] = useState("female");
  const [language, setLanguage] = useState("en");
  const [personality, setPersonality] = useState("");
  const [isUploading, setIsUploading] = useState(false);
  const [playingSampleId, setPlayingSampleId] = useState<number | null>(null);

  const voiceTypes = [
    { value: "female", label: "Female" },
    { value: "male", label: "Male" },
    { value: "neutral", label: "Neutral" }
  ];

  const languages = [
    { value: "en", label: "English" },
    { value: "ar", label: "Arabic" },
    { value: "fr", label: "French" },
    { value: "de", label: "German" },
    { value: "es", label: "Spanish" }
  ];

  const colorOptions = [
    "#3B82F6", "#EF4444", "#10B981", "#F59E0B", "#8B5CF6", 
    "#EC4899", "#06B6D4", "#84CC16", "#F97316", "#6366F1"
  ];

  // Fetch speakers
  const { data: speakers = [], isLoading } = useQuery({
    queryKey: ['/api/speakers']
  });

  // Create speaker
  const createSpeaker = useMutation({
    mutationFn: async (formData: FormData) => {
      setIsUploading(true);
      const response = await fetch('/api/speakers', {
        method: 'POST',
        body: formData
      });
      if (!response.ok) throw new Error('Failed to create speaker');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/speakers'] });
      toast({
        title: "Speaker Created",
        description: "Voice sample has been processed and synthetic voice is being generated"
      });
      resetForm();
    },
    onSettled: () => {
      setIsUploading(false);
    }
  });

  // Delete speaker
  const deleteSpeaker = useMutation({
    mutationFn: async (id: number) => {
      const response = await fetch(`/api/speakers/${id}`, {
        method: 'DELETE'
      });
      if (!response.ok) throw new Error('Failed to delete speaker');
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/speakers'] });
      toast({
        title: "Speaker Deleted",
        description: "Speaker and associated voice data have been removed"
      });
    }
  });

  // Generate TTS test
  const generateTtsTest = useMutation({
    mutationFn: async ({ speakerId, testText }: { speakerId: number, testText: string }) => {
      const response = await fetch(`/api/speakers/${speakerId}/test-tts`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: testText })
      });
      if (!response.ok) throw new Error('Failed to generate TTS test');
      return response.json();
    },
    onSuccess: (data, variables) => {
      if (data.audioUrl) {
        const audio = new Audio(data.audioUrl);
        audio.onended = () => setPlayingSampleId(null);
        audio.play();
        setPlayingSampleId(variables.speakerId);
      }
    }
  });

  const resetForm = () => {
    setUploadFile(null);
    setName("");
    setCode("");
    setColorTag("#3B82F6");
    setVoiceType("female");
    setLanguage("en");
    setPersonality("");
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!uploadFile || !name || !code) return;

    const formData = new FormData();
    formData.append('file', uploadFile);
    formData.append('name', name);
    formData.append('code', code.toUpperCase());
    formData.append('colorTag', colorTag);
    formData.append('voiceType', voiceType);
    formData.append('language', language);
    formData.append('personality', personality);

    createSpeaker.mutate(formData);
  };

  const handlePlaySample = (speaker: Speaker) => {
    if (playingSampleId === speaker.id) {
      setPlayingSampleId(null);
      return;
    }

    if (speaker.sampleAudioUrl) {
      const audio = new Audio(speaker.sampleAudioUrl);
      audio.onended = () => setPlayingSampleId(null);
      audio.play();
      setPlayingSampleId(speaker.id);
    }
  };

  const handleTtsTest = (speaker: Speaker) => {
    const testText = `Hello, this is ${speaker.name} speaking. This is a test of the synthetic voice generation system for Golden Pearl Radio Dubai.`;
    generateTtsTest.mutate({ speakerId: speaker.id, testText });
  };

  if (isLoading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Mic className="h-6 w-6 text-blue-600" />
        <h1 className="text-2xl font-bold">Speaker Management</h1>
        <Badge variant="outline" className="ml-auto">
          {speakers.filter((speaker: Speaker) => speaker.isActive).length} Active Voices
        </Badge>
      </div>

      {/* Create New Speaker */}
      <Card>
        <CardHeader>
          <CardTitle>Add New Speaker</CardTitle>
          <CardDescription>
            Upload voice samples to generate synthetic voices with unique codes and color tags
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <Label htmlFor="voice-upload">Voice Sample (WAV, MP3)</Label>
              <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-gray-300 border-dashed rounded-md">
                <div className="space-y-1 text-center">
                  <Upload className="mx-auto h-12 w-12 text-gray-400" />
                  <div className="flex text-sm text-gray-600">
                    <label htmlFor="voice-upload" className="relative cursor-pointer bg-white rounded-md font-medium text-blue-600 hover:text-blue-500">
                      <span>Upload voice sample</span>
                      <input
                        id="voice-upload"
                        type="file"
                        accept="audio/*"
                        className="sr-only"
                        onChange={(e) => setUploadFile(e.target.files?.[0] || null)}
                      />
                    </label>
                    <p className="pl-1">or drag and drop</p>
                  </div>
                  <p className="text-xs text-gray-500">WAV, MP3 up to 50MB</p>
                  {uploadFile && (
                    <p className="text-sm text-green-600 font-medium">{uploadFile.name}</p>
                  )}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <Label htmlFor="name">Speaker Name</Label>
                <Input
                  id="name"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="e.g., Sarah"
                  required
                />
              </div>

              <div>
                <Label htmlFor="code">Voice Code</Label>
                <Input
                  id="code"
                  value={code}
                  onChange={(e) => setCode(e.target.value.toUpperCase())}
                  placeholder="e.g., A, B, C"
                  maxLength={3}
                  required
                />
              </div>

              <div>
                <Label>Color Tag</Label>
                <div className="flex gap-2 mt-1">
                  {colorOptions.map(color => (
                    <button
                      key={color}
                      type="button"
                      className={`w-8 h-8 rounded-full border-2 ${colorTag === color ? 'border-gray-800' : 'border-gray-300'}`}
                      style={{ backgroundColor: color }}
                      onClick={() => setColorTag(color)}
                    />
                  ))}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <Label>Voice Type</Label>
                <Select value={voiceType} onValueChange={setVoiceType}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {voiceTypes.map(type => (
                      <SelectItem key={type.value} value={type.value}>
                        {type.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label>Language</Label>
                <Select value={language} onValueChange={setLanguage}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {languages.map(lang => (
                      <SelectItem key={lang.value} value={lang.value}>
                        {lang.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div>
              <Label htmlFor="personality">Personality Description</Label>
              <Textarea
                id="personality"
                value={personality}
                onChange={(e) => setPersonality(e.target.value)}
                placeholder="e.g., Warm and professional, great for morning shows..."
                rows={3}
              />
            </div>

            <Button 
              type="submit" 
              className="w-full bg-blue-600 hover:bg-blue-700"
              disabled={isUploading || !uploadFile || !name || !code}
            >
              {isUploading ? "Processing..." : "Create Speaker"}
            </Button>
          </form>
        </CardContent>
      </Card>

      {/* Speaker Library */}
      <div className="grid gap-4">
        {speakers.map((speaker: Speaker) => (
          <Card key={speaker.id}>
            <CardContent className="p-4">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-2">
                    <div 
                      className="w-4 h-4 rounded-full border"
                      style={{ backgroundColor: speaker.colorTag }}
                    />
                    <h3 className="font-semibold">{speaker.name}</h3>
                    <Badge variant="outline" className="font-mono">
                      {speaker.code}
                    </Badge>
                    <Badge variant="secondary">
                      {voiceTypes.find(v => v.value === speaker.voiceType)?.label}
                    </Badge>
                    <Badge variant="outline">
                      {languages.find(l => l.value === speaker.language)?.label}
                    </Badge>
                    {!speaker.isActive && (
                      <Badge variant="destructive">Inactive</Badge>
                    )}
                  </div>

                  {speaker.personality && (
                    <p className="text-sm text-muted-foreground mb-3">{speaker.personality}</p>
                  )}

                  <div className="flex items-center gap-2">
                    {speaker.sampleAudioUrl && (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handlePlaySample(speaker)}
                        disabled={playingSampleId === speaker.id}
                      >
                        {playingSampleId === speaker.id ? (
                          <>
                            <Pause className="w-3 h-3 mr-1" />
                            Playing
                          </>
                        ) : (
                          <>
                            <Play className="w-3 h-3 mr-1" />
                            Sample
                          </>
                        )}
                      </Button>
                    )}

                    {speaker.ttsVoiceId && (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleTtsTest(speaker)}
                        disabled={generateTtsTest.isPending && playingSampleId === speaker.id}
                        className="text-purple-600 border-purple-600 hover:bg-purple-50"
                      >
                        <Volume2 className="w-3 h-3 mr-1" />
                        Test TTS
                      </Button>
                    )}

                    {!speaker.ttsVoiceId && (
                      <Badge variant="outline" className="text-yellow-600">
                        Processing...
                      </Badge>
                    )}
                  </div>
                </div>

                <Button
                  size="sm"
                  variant="ghost"
                  onClick={() => deleteSpeaker.mutate(speaker.id)}
                  disabled={deleteSpeaker.isPending}
                  className="text-red-600 hover:bg-red-50"
                >
                  <Trash2 className="w-4 h-4" />
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {speakers.length === 0 && (
        <Card>
          <CardContent className="p-12 text-center">
            <Mic className="w-12 h-12 text-gray-400 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900 mb-2">No Speakers</h3>
            <p className="text-gray-500">Upload your first voice sample to create a speaker.</p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

client/src/pages/admin/weekly-albums.tsx.content:
import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { Plus, Edit, Calendar, ShoppingCart, Music, Upload } from "lucide-react";
import type { WeeklyAlbum, InsertWeeklyAlbum } from "@shared/schema";

export default function WeeklyAlbumsManager() {
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingAlbum, setEditingAlbum] = useState<WeeklyAlbum | null>(null);
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [formData, setFormData] = useState<Partial<InsertWeeklyAlbum>>({
    title: '',
    description: '',
    coverArt: '',
    releaseWeek: '',
    price: '',
    purchaseUrl: '',
    storyText: '',
    isActive: true
  });

  const { data: albums, isLoading } = useQuery<WeeklyAlbum[]>({
    queryKey: ['/api/weekly-albums']
  });

  const { data: currentAlbum } = useQuery<WeeklyAlbum>({
    queryKey: ['/api/weekly-albums/current']
  });

  const createMutation = useMutation({
    mutationFn: (data: InsertWeeklyAlbum) => apiRequest(`/api/weekly-albums`, {
      method: 'POST',
      body: JSON.stringify(data),
    }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/weekly-albums'] });
      queryClient.invalidateQueries({ queryKey: ['/api/weekly-albums/current'] });
      toast({ title: "Weekly album created successfully" });
      setIsDialogOpen(false);
      resetForm();
    },
    onError: () => {
      toast({ title: "Error creating weekly album", variant: "destructive" });
    }
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: number; data: Partial<InsertWeeklyAlbum> }) => 
      apiRequest(`/api/weekly-albums/${id}`, {
        method: 'PUT',
        body: JSON.stringify(data),
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/weekly-albums'] });
      queryClient.invalidateQueries({ queryKey: ['/api/weekly-albums/current'] });
      toast({ title: "Weekly album updated successfully" });
      setIsDialogOpen(false);
      resetForm();
    },
    onError: () => {
      toast({ title: "Error updating weekly album", variant: "destructive" });
    }
  });

  const resetForm = () => {
    setFormData({
      title: '',
      description: '',
      coverArt: '',
      releaseWeek: '',
      price: '',
      purchaseUrl: '',
      storyText: '',
      isActive: true
    });
    setEditingAlbum(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.title || !formData.description || !formData.releaseWeek) {
      toast({ title: "Please fill in all required fields", variant: "destructive" });
      return;
    }

    if (editingAlbum) {
      updateMutation.mutate({ id: editingAlbum.id, data: formData as InsertWeeklyAlbum });
    } else {
      createMutation.mutate(formData as InsertWeeklyAlbum);
    }
  };

  const handleEdit = (album: WeeklyAlbum) => {
    setEditingAlbum(album);
    setFormData({
      title: album.title,
      description: album.description,
      coverArt: album.coverArt || '',
      releaseWeek: album.releaseWeek,
      price: album.price || '',
      purchaseUrl: album.purchaseUrl || '',
      storyText: album.storyText || '',
      isActive: album.isActive
    });
    setIsDialogOpen(true);
  };

  const getCurrentWeek = () => {
    const now = new Date();
    const start = new Date(now.getFullYear(), 0, 1);
    const days = Math.floor((now.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    const weekNum = Math.ceil((days + start.getDay() + 1) / 7);
    return `${now.getFullYear()}-W${weekNum.toString().padStart(2, '0')}`;
  };

  if (isLoading) {
    return (
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold">CD of the Week</h1>
            <p className="text-gray-600">Manage weekly album promotions</p>
          </div>
        </div>
        <div className="grid gap-4">
          {Array(3).fill(0).map((_, i) => (
            <Card key={i}>
              <CardContent className="p-6">
                <div className="h-4 bg-gray-200 animate-pulse mb-2"></div>
                <div className="h-4 bg-gray-200 animate-pulse w-3/4"></div>
              </CardContent>
            </Card>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">CD of the Week</h1>
          <p className="text-gray-600">Manage weekly album promotions and purchase links</p>
        </div>
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogTrigger asChild>
            <Button onClick={() => { resetForm(); setFormData(prev => ({ ...prev, releaseWeek: getCurrentWeek() })); }}>
              <Plus className="h-4 w-4 mr-2" />
              Add Weekly Album
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>
                {editingAlbum ? 'Edit Weekly Album' : 'Add New Weekly Album'}
              </DialogTitle>
            </DialogHeader>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="title">Album Title *</Label>
                  <Input
                    id="title"
                    value={formData.title}
                    onChange={(e) => setFormData(prev => ({ ...prev, title: e.target.value }))}
                    placeholder="Enter album title"
                    required
                  />
                </div>
                <div>
                  <Label htmlFor="releaseWeek">Release Week *</Label>
                  <Input
                    id="releaseWeek"
                    value={formData.releaseWeek}
                    onChange={(e) => setFormData(prev => ({ ...prev, releaseWeek: e.target.value }))}
                    placeholder="2025-W25"
                    required
                  />
                </div>
              </div>

              <div>
                <Label htmlFor="description">Description *</Label>
                <Textarea
                  id="description"
                  value={formData.description}
                  onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                  placeholder="Brief description of the album"
                  rows={3}
                  required
                />
              </div>

              <div>
                <Label htmlFor="coverArt">Album Cover URL</Label>
                <Input
                  id="coverArt"
                  value={formData.coverArt}
                  onChange={(e) => setFormData(prev => ({ ...prev, coverArt: e.target.value }))}
                  placeholder="https://example.com/cover.jpg or @assets/filename.jpg"
                />
                <p className="text-sm text-gray-500 mt-1">
                  Use @assets/filename.jpg for uploaded assets or full URL for external images
                </p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="price">Price</Label>
                  <Input
                    id="price"
                    value={formData.price}
                    onChange={(e) => setFormData(prev => ({ ...prev, price: e.target.value }))}
                    placeholder="AED 39.99 Digital / AED 69.99 Vinyl"
                  />
                </div>
                <div>
                  <Label htmlFor="purchaseUrl">Purchase URL</Label>
                  <Input
                    id="purchaseUrl"
                    value={formData.purchaseUrl}
                    onChange={(e) => setFormData(prev => ({ ...prev, purchaseUrl: e.target.value }))}
                    placeholder="https://music.apple.com/album/..."
                  />
                </div>
              </div>

              <div>
                <Label htmlFor="storyText">Story/Background</Label>
                <Textarea
                  id="storyText"
                  value={formData.storyText}
                  onChange={(e) => setFormData(prev => ({ ...prev, storyText: e.target.value }))}
                  placeholder="Detailed backstory for the homepage feature"
                  rows={4}
                />
              </div>

              <div className="flex items-center space-x-2">
                <Switch
                  id="isActive"
                  checked={formData.isActive}
                  onCheckedChange={(checked) => setFormData(prev => ({ ...prev, isActive: checked }))}
                />
                <Label htmlFor="isActive">Active (Show on homepage)</Label>
              </div>

              <div className="flex justify-end space-x-2 pt-4">
                <Button type="button" variant="outline" onClick={() => setIsDialogOpen(false)}>
                  Cancel
                </Button>
                <Button type="submit" disabled={createMutation.isPending || updateMutation.isPending}>
                  {createMutation.isPending || updateMutation.isPending ? 'Saving...' : 
                   editingAlbum ? 'Update Album' : 'Create Album'}
                </Button>
              </div>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      {/* Current Active Album */}
      {currentAlbum && (
        <Card className="border-radio-gold">
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-2">
                <Music className="h-5 w-5 text-radio-gold" />
                Current CD of the Week
              </CardTitle>
              <Badge className="bg-radio-gold text-radio-dark">LIVE</Badge>
            </div>
          </CardHeader>
          <CardContent>
            <div className="flex gap-4">
              {currentAlbum.coverArt && (
                <div className="w-24 h-24 rounded-lg overflow-hidden flex-shrink-0">
                  <img
                    src={currentAlbum.coverArt.startsWith('@assets/') 
                      ? currentAlbum.coverArt.replace('@assets/', '/attached_assets/')
                      : currentAlbum.coverArt}
                    alt={currentAlbum.title}
                    className="w-full h-full object-cover"
                  />
                </div>
              )}
              <div className="flex-1">
                <h3 className="font-semibold text-lg">{currentAlbum.title}</h3>
                <p className="text-gray-600 mb-2">{currentAlbum.description}</p>
                <div className="flex items-center gap-4 text-sm text-gray-500">
                  <span className="flex items-center gap-1">
                    <Calendar className="h-4 w-4" />
                    Week {currentAlbum.releaseWeek.split('-')[1]}
                  </span>
                  {currentAlbum.price && (
                    <span className="flex items-center gap-1">
                      <ShoppingCart className="h-4 w-4" />
                      {currentAlbum.price}
                    </span>
                  )}
                </div>
              </div>
              <Button onClick={() => handleEdit(currentAlbum)} variant="outline" size="sm">
                <Edit className="h-4 w-4 mr-1" />
                Edit
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* All Albums List */}
      <div className="grid gap-4">
        {albums?.map((album) => (
          <Card key={album.id} className={album.id === currentAlbum?.id ? 'opacity-50' : ''}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                  {album.coverArt && (
                    <div className="w-16 h-16 rounded overflow-hidden flex-shrink-0">
                      <img
                        src={album.coverArt.startsWith('@assets/') 
                          ? album.coverArt.replace('@assets/', '/attached_assets/')
                          : album.coverArt}
                        alt={album.title}
                        className="w-full h-full object-cover"
                      />
                    </div>
                  )}
                  <div>
                    <h3 className="font-semibold">{album.title}</h3>
                    <p className="text-gray-600 text-sm">{album.description}</p>
                    <div className="flex items-center gap-2 mt-1">
                      <Badge variant="outline" size="sm">
                        Week {album.releaseWeek.split('-')[1]}
                      </Badge>
                      {!album.isActive && (
                        <Badge variant="secondary" size="sm">Inactive</Badge>
                      )}
                      {album.purchaseUrl && (
                        <Badge variant="outline" size="sm" className="text-green-600">
                          <ShoppingCart className="h-3 w-3 mr-1" />
                          Purchasable
                        </Badge>
                      )}
                    </div>
                  </div>
                </div>
                <Button onClick={() => handleEdit(album)} variant="outline" size="sm">
                  <Edit className="h-4 w-4 mr-1" />
                  Edit
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {(!albums || albums.length === 0) && (
        <Card>
          <CardContent className="p-8 text-center">
            <Music className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <h3 className="font-semibold text-lg mb-2">No weekly albums yet</h3>
            <p className="text-gray-600 mb-4">Start promoting albums by creating your first CD of the Week</p>
            <Button onClick={() => { resetForm(); setFormData(prev => ({ ...prev, releaseWeek: getCurrentWeek() })); setIsDialogOpen(true); }}>
              <Plus className="h-4 w-4 mr-2" />
              Create First Album
            </Button>
          </CardContent>
        </Card>
      )}
    </div>
  );
}
